window.QUOTES = [{"id": "S4.001", "cluster": "S4", "_hub": "SR:S4:blog:essay-trust-manifesto", "hub": "SR:S4:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "Belonging isn't a luxury – it's a fundamental human need, and one that's too often overlooked or neglected. Before self-actualization, before achievement, before even ambition – we need to feel safe. We need to feel seen. We need to feel part of something bigger than ourselves.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S4.002", "cluster": "S4", "_hub": "SR:S4:blog:essay-trust-manifesto", "hub": "SR:S4:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "In-person spaces build trust. They deepen alignment. They create a rare sense of belonging – the kind that turns loose networks into real communities, and shared curiosity into shared responsibility.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S4.027", "cluster": "S4", "_hub": "SR:S4:blog:essay-trust-manifesto", "hub": "SR:S4:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "Trust is the invisible thread that holds the world together. It is what allows us to build lives with confidence – to make plans, raise families, and imagine a future worth believing in. It stitches strangers into societies, turns transactions into economies, and transforms individuals into nations.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Trust is the invisible thread that holds the world together — it stitches strangers into societies, turns transactions into economies, and makes progress possible", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S4.028", "cluster": "S4", "_hub": "SR:S4:blog:essay-trust-manifesto", "hub": "SR:S4:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "We are watching it happen – in real time. Truth is contested. Institutions are questioned. Communities are fragmented. And when the fabric tears too far, history tells us what comes next: disorder, division, revolt.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The social fabric is fraying at the exact moment trust is most needed — truth contested, institutions questioned, communities fragmented; when it tears too far, disorder follows", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S4.029", "cluster": "S4", "_hub": "SR:S4:blog:essay-trust-manifesto", "hub": "SR:S4:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "trust changes the conversation. Because when people feel safe – safe to be honest, to not posture, to be vulnerable – they begin asking the questions that actually matter", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "When people feel psychologically safe — safe to be honest, not posture, be vulnerable — the conversation shifts from tactical to soul-level questions about meaning and purpose", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S4.030", "cluster": "S4", "_hub": "SR:S4:blog:essay-trust-manifesto", "hub": "SR:S4:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "There's a low-grade anxiety humming through our generation. A feeling that something immense is shifting. That we're being pulled into a new era faster than we can process it – and no one's handing out a playbook.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "There is a low-grade anxiety humming through this generation — being pulled into a new era faster than it can be processed, with no playbook", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S4.031", "cluster": "S4", "_hub": "SR:S4:blog:essay-trust-manifesto", "hub": "SR:S4:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "responsibility is not a burden. It is a privilege. A once-in-a-generation opportunity to shape a world where technology amplifies the best of what makes us human – our creativity, our compassion, our ability to dream beyond ourselves.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Responsibility is not a burden — it is a privilege, a once-in-a-generation opportunity to shape a world where technology amplifies the best of what makes us human", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S4.012", "cluster": "S4", "_hub": "SR:S4:blog:booknotes-community", "hub": "SR:S4:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Social capital decline is measurable and catastrophic / 25% less likely to vote, 35% less likely to attend public meetings, 40% less engaged in party politics / 50% drop in organizational membership since the 1960s", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Social capital decline in America is measurable and catastrophic — a 50% drop in organizational membership, civic engagement down across every dimension", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S4.013", "cluster": "S4", "_hub": "SR:S4:blog:booknotes-community", "hub": "SR:S4:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "The decline is generational, not individual aging / Inter-cohort change: each generation is less civically engaged than the previous one", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The social capital decline is generational, not individual: each successive cohort is less civically engaged than the previous one", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S4.014", "cluster": "S4", "_hub": "SR:S4:blog:booknotes-community", "hub": "SR:S4:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "The solutions require rebuilding bridging social capital that connects diverse groups, not just bonding capital that reinforces homogeneity.", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Social capital is both a public and private good — and the solutions require rebuilding bridging capital that connects diverse groups, not just bonding capital that reinforces homogeneity", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S4.015", "cluster": "S4", "_hub": "SR:S4:blog:booknotes-community", "hub": "SR:S4:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Loneliness epidemic / Relationships = satisfaction / Phone use problem", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The loneliness epidemic is real; relationships equal satisfaction; phone use compounds the problem", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S4.016", "cluster": "S4", "_hub": "SR:S4:blog:booknotes-community", "hub": "SR:S4:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "↑ guess: CMs are more likely to succeed in hard times due to support from authentic relationships / Can put their own ego and desires aside", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Community-maximizing actors are more likely to succeed in hard times due to support from authentic relationships — they can put their own ego and desires aside", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S4.017", "cluster": "S4", "_hub": "SR:S4:blog:booknotes-community", "hub": "SR:S4:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "AI is the technology that solves belonging", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI is the technology that solves belonging", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S4.008", "cluster": "S4", "_hub": "SR:S4:blog:aic-mission-pages", "hub": "SR:S4:blog:aic-mission-pages", "category": "blog", "catColor": "#ff6f9c", "source_key": "aic-mission-pages", "url": "", "text": "The soul of this Collective has always been you. If our mission for a trusted, open, and human-centric AI resonates with you, then you're already family.", "paraphrase": "", "source_id": "aic-mission-pages", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The community is the soul of the Collective — members are already family if they share the mission", "highlight": false, "also_supports": [], "corpus_ref": "aic-mission-pages", "private": false}, {"id": "S4.009", "cluster": "S4", "_hub": "SR:S4:blog:aic-mission-pages", "hub": "SR:S4:blog:aic-mission-pages", "category": "blog", "catColor": "#ff6f9c", "source_key": "aic-mission-pages", "url": "", "text": "This milestone was co-created with you — our incredible community — from the very first spark.", "paraphrase": "", "source_id": "aic-mission-pages", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The AIC milestone was co-created with the community from the first spark", "highlight": false, "also_supports": [], "corpus_ref": "aic-mission-pages", "private": false}, {"id": "S4.010", "cluster": "S4", "_hub": "SR:S4:blog:aic-mission-pages", "hub": "SR:S4:blog:aic-mission-pages", "category": "blog", "catColor": "#ff6f9c", "source_key": "aic-mission-pages", "url": "", "text": "This journey is ours, together. Your support, your voice, as we stand at this hopeful beginning, means the world to me.", "paraphrase": "", "source_id": "aic-mission-pages", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The journey ahead is collective — supporter voice and presence means the world", "highlight": false, "also_supports": [], "corpus_ref": "aic-mission-pages", "private": false}, {"id": "S4.011", "cluster": "S4", "_hub": "SR:S4:blog:aic-mission-pages", "hub": "SR:S4:blog:aic-mission-pages", "category": "blog", "catColor": "#ff6f9c", "source_key": "aic-mission-pages", "url": "", "text": "Let's build something future generations will thank us for!", "paraphrase": "", "source_id": "aic-mission-pages", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Build something future generations will thank us for", "highlight": false, "also_supports": [], "corpus_ref": "aic-mission-pages", "private": false}, {"id": "S4.021", "cluster": "S4", "_hub": "SR:S4:blog:essay-human-side-of-ai", "hub": "SR:S4:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "Community isn't a luxury – it's the foundation of our innovation economy and society.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Community isn't a luxury; it is the foundation of the innovation economy and society", "highlight": false, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S4.022", "cluster": "S4", "_hub": "SR:S4:blog:essay-human-side-of-ai", "hub": "SR:S4:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "At its core, the Collective is built on three pillars: learn, connect, and elevate.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The Collective is built on three pillars — learn, connect, and elevate — designed for meaningful connection, not typical networking", "highlight": false, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S4.023", "cluster": "S4", "_hub": "SR:S4:blog:essay-human-side-of-ai", "hub": "SR:S4:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "Staying ahead demands crowdsourcing insights from the spiky builders exploring the edges of the adjacent possible.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Staying ahead in AI demands crowdsourcing insights from spiky builders exploring the edges of the adjacent possible", "highlight": false, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S4.024", "cluster": "S4", "_hub": "SR:S4:blog:essay-human-side-of-ai", "hub": "SR:S4:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "A strong community doesn't just benefit individuals – it raises the bar for an entire city's tech ecosystem, creating opportunities for everyone.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "A strong community raises the bar for an entire city's tech ecosystem, creating opportunities for everyone", "highlight": false, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S4.032", "cluster": "S4", "_hub": "SR:S4:blog:notion-manifesto-whitepapers", "hub": "SR:S4:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "This community was founded on the belief that the most meaningful connections are made when exploring a shared curiosity together, and that meaningful relationships lead to meaningful outcomes. Bring exceptional people together in purposeful ways and INCREDIBLE things happen!", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The most meaningful connections are made when exploring a shared curiosity together — meaningful relationships lead to meaningful outcomes", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S4.033", "cluster": "S4", "_hub": "SR:S4:blog:notion-manifesto-whitepapers", "hub": "SR:S4:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Discussion groups are the heart of who we are. It's so obvious, but no one else does it well.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Discussion groups are the heart of what AIC is — obvious but no one else does it well", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S4.034", "cluster": "S4", "_hub": "SR:S4:blog:notion-manifesto-whitepapers", "hub": "SR:S4:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Facing a technological landscape evolving so quickly, we are all novices. As novices, the best thing we can do is exercise our personal curiosity and learn together.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Facing a technology landscape evolving so quickly, everyone is a novice — the best response is to exercise personal curiosity and learn together", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S4.035", "cluster": "S4", "_hub": "SR:S4:blog:notion-manifesto-whitepapers", "hub": "SR:S4:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Learning is most effective through thoughtful and welcoming discussion in an environment full of diverse perspectives. Seek think tanks, not echo chambers.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Learning is most effective through thoughtful, welcoming discussion with diverse perspectives — seek think tanks, not echo chambers", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S4.018", "cluster": "S4", "_hub": "SR:S4:blog:essay-gai-collective-curiosity", "hub": "SR:S4:blog:essay-gai-collective-curiosity", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-gai-collective-curiosity", "url": "", "text": "Cornerstone to our early events was fostering a sense of community through being intentional about the events' structure — centering each evening on intimate group discussion.' (notion-rec-essay-gai-collective-curiosity)", "paraphrase": "", "source_id": "essay-gai-collective-curiosity", "date": "2023-04-12", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Intentionality and intimacy are the cornerstones of community-building — centering gatherings on intimate group discussion creates genuine belonging", "highlight": false, "also_supports": [], "corpus_ref": "essay-gai-collective-curiosity", "private": false}, {"id": "S4.019", "cluster": "S4", "_hub": "SR:S4:blog:essay-gai-collective-curiosity", "hub": "SR:S4:blog:essay-gai-collective-curiosity", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-gai-collective-curiosity", "url": "", "text": "convinced that by rubbing shoulders with the brightest minds in generative AI, they are not only enriching their own understanding but making their own tangible impact on the discussion and the field as a whole.' (notion-rec-essay-gai-collective-curiosity)", "paraphrase": "", "source_id": "essay-gai-collective-curiosity", "date": "2023-04-12", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Rubbing shoulders with the brightest minds and contributing to group discussion has a tangible impact on both individual understanding and the field", "highlight": false, "also_supports": [], "corpus_ref": "essay-gai-collective-curiosity", "private": false}, {"id": "S4.020", "cluster": "S4", "_hub": "SR:S4:blog:essay-gai-collective-curiosity", "hub": "SR:S4:blog:essay-gai-collective-curiosity", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-gai-collective-curiosity", "url": "", "text": "eager for a venue to push past the lack of structure and substance frequent at traditional networking events, we planned a meetup centered around thoughtful and engaging group discussion.' (notion-rec-essay-gai-collective-curiosity)", "paraphrase": "", "source_id": "essay-gai-collective-curiosity", "date": "2023-04-12", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Traditional networking lacks structure and substance; a community built on thoughtful group discussion is qualitatively superior", "highlight": false, "also_supports": [], "corpus_ref": "essay-gai-collective-curiosity", "private": false}, {"id": "S4.025", "cluster": "S4", "_hub": "SR:S4:blog:essay-top-10-reads-2024", "hub": "SR:S4:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "In a world of quick fixes, Coyle's refreshingly human playbook shows that authentic trust and psychological safety trump raw talent. It's become my bible for creating extraordinary cultures.", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Psychological safety, vulnerability, and shared purpose — not raw talent — are the foundations of high-performing teams", "highlight": false, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S4.026", "cluster": "S4", "_hub": "SR:S4:blog:essay-top-10-reads-2024", "hub": "SR:S4:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "It hit home for me that community isn't a luxury — it's fundamental to our society. Reading this through the lens of the GenAI Collective reaffirmed my belief in the importance of reintroducing community-building principles in tech and through tech.", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Community is not a luxury — it is fundamental to society; rebuilding community in and through tech is a core mission", "highlight": false, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S4.000", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "People are not just showing up for another AI tutorial. They show up because this moment is disorienting and impossible to process alone. They want context, peers, examples, and humans they trust.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-05-15", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S4.005", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "That initial spark of shared curiosity, the magic of intimate, unfiltered discussion, and the profound power of human connection – that's still the beating heart of everything we do.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-05-27", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S4.006", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "In a world where the meta changes overnight, finding your people – your tribe – is the only thing that really matters.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-07-11", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S4.007", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The frontier is evolving faster than ever. The tools will change, but finding your tribe is how you'll stay ahead of the wave.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2025-07-11", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S4.054", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Community is the foundation of innovation. When we learn, connect, and elevate one another, we unlock collective potential that benefits not just individuals but entire tech ecosystems.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-01-02", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Community is the foundation of innovation — collective learning unlocks potential that benefits entire tech ecosystems", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S4.055", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "even as technology accelerates, genuine connection is what truly propels us forward.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-05-27", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Genuine connection is what truly propels us forward even as technology accelerates", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S4.056", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The most meaningful conversations last year didn't happen on stages or online. They happened in living rooms, after events, late at night – with people who were actually building.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2026-02-02", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The most meaningful conversations happen in living rooms and after events — not on stages or online; the audience should be part of the conversation, not passive", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S4.057", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The tools will keep evolving. But finding your people in person – that's irreplaceable.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2026-01-28", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "In-person connection is irreplaceable — strangers become collaborators and \"what are you working on?\" becomes \"let's work on it together\"", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S4.058", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "every single one of these events is a room full of people who chose to build something, learn something, or meet someone new. That's 700+ rooms where strangers became collaborators. Where ideas became companies.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2026-01-28", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "700+ rooms is the right metric — every event is a room where ideas become companies", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S4.059", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "HUGE props to all the tireless work everyone on the team has been putting in to make The AI Collective the human side of AI!", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-07-18", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "\"We are the human side of AI\" — the Collective's mission is to be the human side of AI", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S4.060", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "This only works because people choose to care.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2026-01-30", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "This only works because people choose to care — high-agency volunteerism is the engine of a genuine community", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S4.061", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "City by city – New York, Boston, Miami, Paris, then dozens more – chapters emerged, each one led by someone who'd felt the same pull we had in that San Francisco apartment. The same realization that this technology was going to reshape everything, and that the people closest to the frontier had a responsibility to help the world navigate it together.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-04-01", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The AI Collective grew city-by-city because people everywhere felt the same pull: the technology was going to reshape everything and those closest to the frontier had a responsibility to help the world navigate it together", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S4.062", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "IRL community gets more valuable in the AI era. The scarce thing becomes better questions, better taste, and better rooms.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-15", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "IRL community gets more valuable in the AI era precisely because the internet flattens every idea into content before real conversations happen", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S4.063", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "That has always been the magic of @AICollectiveCo to me: a room full of people who are genuinely curious, unusually generous, and excited to help each other build.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-15", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The magic of AIC is a room full of people who are genuinely curious, unusually generous, and excited to help each other build; nearly 1,000 pieces of peer feedback in a single evening expresses that", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S4.064", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Different circles need different kinds of care … Protect the center first … Water a few relationships each week with no agenda", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-19", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Meaningful relationships require different kinds of care at different concentric circles; protecting the center and watering a few relationships each week with no agenda is the practice", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S4.065", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "From the bottom of my heart, thank you to everyone who has been a part of this incredible journey of learning and growth through exploring a shared curiosity. This is only the start – I cannot wait to see the impact that we can continue to make as a community!", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2023-07-09", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The GenAI Collective community is built on genuine shared curiosity — a journey of learning and growth — and its impact extends far beyond what its founders imagined", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S4.066", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Beyond discussion and learning is a deep and sincere sense of belonging. These are so much more than just networking or knowledge-sharing events; they are crucibles for genuine friendship.", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2023-09-21", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Tech community events are crucibles for genuine friendship and belonging, not merely networking or knowledge-sharing", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S4.067", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "It sounds really nerdy but – beyond lifting heavy weights up and down – technology is my only real passion and these events are the one place where I'm not a weirdo for only wanting to talk about generative AI. I've made more friends and meaningful relationships at these events than anywhere else!", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2023-09-21", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Technology events are the one place where being fully obsessed with a technical passion is normal, not weird; they are uniquely energizing for the builder identity", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S4.068", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I absolutely love how their events are centered around thoughtful probing into pressing topics.", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2023-08-16", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Events centered on thoughtful probing into pressing topics — not just socializing — are the right design model for community", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S4.069", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Step two of many towards this community's mission to become the worldwide community for AI and technological progress – uniting exceptional people in authentic ways to cultivate deep connections, a positive-sum culture, and participation in the future of AI!", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2024-03-21", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The right community vision is global — uniting exceptional people for a positive-sum culture and participation in the future of AI", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S4.070", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "This community was founded on the belief that the most meaningful connections are made when exploring a shared curiosity together, and that meaningful relationships lead to meaningful outcomes. Bring exceptional people together in purposeful ways and INCREDIBLE things happen!", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2024-12-25", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Meaningful relationships lead to meaningful outcomes — bring exceptional people together in purposeful ways and incredible things happen", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S4.071", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "There's such a strong need for connection, for consistency, for community in every city.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2025-03-25", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "There is a deep universal need for connection, consistency, and community in every city around the world", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S4.072", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The AI conversation is broken — and we're fixing it, one room at a time!", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-02-20", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The AI conversation is broken and needs to be fixed one room at a time by putting builders and stakeholders together", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S4.073", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "connection didn't die. it got outcompeted. different problem.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-04-06", "register": "D", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Online human connection didn't die — it got outcompeted; that's a different, solvable problem", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S4.074", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "From the beginning, the @GenAICollective has centered itself around exploring a shared curiosity in GenAI through thoughtful discussion amongst a vibrant community. The community podcast takes the same great discussions we have at every event and makes them available for all!", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2023-08-14", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The GenAI Collective is centered on thoughtful discussion and shared curiosity as the community model", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S4.075", "cluster": "S4", "_hub": "SR:S4:tweet:x-com", "hub": "SR:S4:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "If you've ever felt like the best AI conversations happen after the recording stops – this is that conversation!", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-02-02", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The best AI conversations happen after the recording stops — in rooms with builders, operators, investors asking real questions", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S4.003", "cluster": "S4", "_hub": "SR:S4:podcast:talk-venture-with-grace", "hub": "SR:S4:podcast:talk-venture-with-grace", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-venture-with-grace", "url": "", "text": "the core insight what got us started with AI collective and how we went from 12 people signing up for the first event to 250 over 250 people signing up for the third event is a focus on why I think everybody or many people come to events. It's to meet other people. is to exchange insights.", "paraphrase": "", "source_id": "talk-venture-with-grace", "date": "2025-12-05", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-venture-with-grace", "private": false}, {"id": "S4.004", "cluster": "S4", "_hub": "SR:S4:podcast:talk-venture-with-grace", "hub": "SR:S4:podcast:talk-venture-with-grace", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-venture-with-grace", "url": "", "text": "That's the core insight is bringing people together to explore a shared curiosity and make sure people are actually connecting and following up after.", "paraphrase": "", "source_id": "talk-venture-with-grace", "date": "2025-12-05", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-venture-with-grace", "private": false}, {"id": "S4.051", "cluster": "S4", "_hub": "SR:S4:podcast:talk-venture-with-grace", "hub": "SR:S4:podcast:talk-venture-with-grace", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-venture-with-grace", "url": "", "text": "This was early February and that's where it all started just in my friend Steven's cozy San Francisco living room bringing the 12 12 people together around a table to discuss what's going on.", "paraphrase": "", "source_id": "talk-venture-with-grace", "date": "2025-12-05", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Origin story: the AI Collective started from genuine curiosity — 12 people in a San Francisco living room", "highlight": false, "also_supports": [], "corpus_ref": "talk-venture-with-grace", "private": false}, {"id": "S4.052", "cluster": "S4", "_hub": "SR:S4:podcast:talk-venture-with-grace", "hub": "SR:S4:podcast:talk-venture-with-grace", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-venture-with-grace", "url": "", "text": "I would say the throughine there is empathy. It's just understanding people, right? And what people want. It's um you say product market fit. And I've just been very lucky in in being able to understand people and and product market fit and what people really want whether it's in a homework tracking app, in a weightlifting tracking app, or in a community.", "paraphrase": "", "source_id": "talk-venture-with-grace", "date": "2025-12-05", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Empathy + product-market fit is the throughline across all his products, including community-building", "highlight": false, "also_supports": [], "corpus_ref": "talk-venture-with-grace", "private": false}, {"id": "S4.053", "cluster": "S4", "_hub": "SR:S4:podcast:talk-venture-with-grace", "hub": "SR:S4:podcast:talk-venture-with-grace", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-venture-with-grace", "url": "", "text": "before we ever thought about monetizing and we still have not monetized. Everything is free. Every single event to attend is free. We don't charge members anything. Um, we've been building this now for 3 years and we have not monetized because we're so obsessed with building the distribution engine", "paraphrase": "", "source_id": "talk-venture-with-grace", "date": "2025-12-05", "register": "B", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Build your audience first before monetizing — the Collective has been free for 3 years, deliberately", "highlight": false, "also_supports": [], "corpus_ref": "talk-venture-with-grace", "private": false}, {"id": "S4.043", "cluster": "S4", "_hub": "SR:S4:podcast:talk-roan-weigert", "hub": "SR:S4:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "Immediately having these small living room discussions, we could tell that there was there was something special forming just in the energy that people were bringing the ideas that we were discovering together during those events.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Energy of early living-room AI discussions revealed something special was forming just from the ideas people were discovering together", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S4.044", "cluster": "S4", "_hub": "SR:S4:podcast:talk-roan-weigert", "hub": "SR:S4:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "It was originally just a group of friends who got together and wanted to understand together and stay ahead of the latest AI trends. There was no tall aspirations for world domination or anything like that.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "AIC was entirely grassroots — originally just friends understanding together, with no world-domination ambitions", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S4.045", "cluster": "S4", "_hub": "SR:S4:podcast:talk-roan-weigert", "hub": "SR:S4:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "I could tell that there was a kind of a different angle to each community. It was so fascinating to see what AI looks like, what the AI ecosystem looks like in every single city.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Every AI ecosystem looks different city-by-city — each chapter has a distinct character", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S4.046", "cluster": "S4", "_hub": "SR:S4:podcast:talk-roan-weigert", "hub": "SR:S4:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "It's really important to have and lean into the importance of in-person dialogue. Even with something like Zoom or Slack that you think is a little bit closer, so much of the subtleties, the attention is lost when we're not in person. Majority of communication, some say 93% of communication is non-verbal, right? and you lose most of that when it's on Slack or when it's on Zoom.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "In-person dialogue restores trust because nuance and non-verbal complexity are lost in every digital medium — some say 93% of communication is non-verbal", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S4.047", "cluster": "S4", "_hub": "SR:S4:podcast:talk-roan-weigert", "hub": "SR:S4:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "The very best is by spending time with other people who are also on that frontier with you. It's just a matter of bringing together the sharpest pioneers on the frontier as I like to call them to exchange these ideas. Okay, I tried this on this codegen platform and I've tried this on this vibe coding platform and exchanging those ideas — that's what's going to allow you to stay on the very cutting edge.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The best way to stay on the frontier is to spend time with other people also on the frontier — exchanging \"I tried this on this codegen/vibe coding platform\" insights", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S4.038", "cluster": "S4", "_hub": "SR:S4:podcast:talk-aic-why-video", "hub": "SR:S4:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "bringing people together in person is the best way to build that sense of nearness again, a shared sense of understanding about the world.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Bringing people together in person is the best way to rebuild the sense of nearness, shared understanding, and belonging that eroding trust has destroyed", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S4.039", "cluster": "S4", "_hub": "SR:S4:podcast:talk-aic-why-video", "hub": "SR:S4:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "co-creation. Giving people a sense of shared ownership, transparency about what's going on, and instilling a sense of accountability.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Co-creation — shared ownership, transparency, and accountability — is one of the two system upgrades needed to restore trust", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S4.040", "cluster": "S4", "_hub": "SR:S4:podcast:talk-aic-why-video", "hub": "SR:S4:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "I'm not going to say this is the whole solution, but I do think this is an important part of the solution.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The AI Collective is part of the solution for restoring trust through nearness and forums for genuine dialogue — he does not claim it is the whole solution", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S4.048", "cluster": "S4", "_hub": "SR:S4:podcast:talk-tjstar-keynote", "hub": "SR:S4:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "staring down the abyss of the future of AI and really thinking deeply, um, that's the number one thing that I learned is the value of human connection.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Human connection is the value he knows he's succeeding at — deepening it is the North Star outcome", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S4.049", "cluster": "S4", "_hub": "SR:S4:podcast:talk-tjstar-keynote", "hub": "SR:S4:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "Every human just wants to be seen and heard.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Every human just wants to be seen and heard — the fundamental driver of connection", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S4.050", "cluster": "S4", "_hub": "SR:S4:podcast:talk-tjstar-keynote", "hub": "SR:S4:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "If you want to do anything great, it's going to take doing that with other people. You're not going to do it alone.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "If you want to do anything great, you can't do it alone — collaboration and people skills are the ultimate mountain", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S4.041", "cluster": "S4", "_hub": "SR:S4:podcast:talk-roam-remote-work", "hub": "SR:S4:podcast:talk-roam-remote-work", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roam-remote-work", "url": "", "text": "there is a reason that it really took off in SF and even when we are 100 chapters globally, we try our very best to have that same sort of culture vibes at every single one of our events. That's become one of the key focuses for us is scaling that culture as we go global", "paraphrase": "", "source_id": "talk-roam-remote-work", "date": "2026-02-02", "register": "B", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Face-to-face culture is the core reason AIC took off and must be deliberately scaled globally", "highlight": false, "also_supports": [], "corpus_ref": "talk-roam-remote-work", "private": false}, {"id": "S4.042", "cluster": "S4", "_hub": "SR:S4:podcast:talk-roam-remote-work", "hub": "SR:S4:podcast:talk-roam-remote-work", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roam-remote-work", "url": "", "text": "while face to face is no longer feasible when we're in 30 countries worldwide, it is feasible online... every single month we have a global all hands and we will have people literally from 20 plus countries because that's the one time that we all get to express that energy and enthusiasm and set the tone for the culture", "paraphrase": "", "source_id": "talk-roam-remote-work", "date": "2026-02-02", "register": "B", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Online all-hands sustains culture and energy across distributed global communities when in-person is infeasible", "highlight": false, "also_supports": [], "corpus_ref": "talk-roam-remote-work", "private": false}, {"id": "S4.036", "cluster": "S4", "_hub": "SR:S4:press:press-businesswire-launch", "hub": "SR:S4:press:press-businesswire-launch", "category": "press", "catColor": "#ff9d4c", "source_key": "press-businesswire-launch", "url": "", "text": "in an era of exponential transformation, our greatest strength lies in each other", "paraphrase": "", "source_id": "press-businesswire-launch", "date": "2025-06-05", "register": "E", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "In an era of exponential transformation humanity's greatest strength is in each other", "highlight": false, "also_supports": [], "corpus_ref": "press-businesswire-launch", "private": false}, {"id": "S4.037", "cluster": "S4", "_hub": "SR:S4:press:press-businesswire-launch", "hub": "SR:S4:press:press-businesswire-launch", "category": "press", "catColor": "#ff9d4c", "source_key": "press-businesswire-launch", "url": "", "text": "creating trusted, in-person spaces to make sense of this moment, ask the deeper questions", "paraphrase": "", "source_id": "press-businesswire-launch", "date": "2025-06-05", "register": "E", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Trusted in-person spaces are the mechanism for making sense of this transformational moment", "highlight": false, "also_supports": [], "corpus_ref": "press-businesswire-launch", "private": false}, {"id": "S9.004", "cluster": "S9", "_hub": "SR:S9:blog:notion-manifesto-whitepapers", "hub": "SR:S9:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Both paths are traps. They are false dichotomies born of fear: the fear of being left behind and the fear of the unknown. Both fail to address the root of the problem: our collapsing ability to coordinate and adapt together.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S9.005", "cluster": "S9", "_hub": "SR:S9:blog:notion-manifesto-whitepapers", "hub": "SR:S9:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "The Narrow Path is the difficult space between the chaos of unaccountable power and the despotism of suffocating control. It is the only path where progress and responsibility can be fused.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S9.045", "cluster": "S9", "_hub": "SR:S9:blog:notion-manifesto-whitepapers", "hub": "SR:S9:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "This path argues that technological progress is an autonomous, self-correcting force. It mistakes velocity for direction and intelligence for wisdom. Its answer to the coordination challenge is to cede control to Moloch, hoping it becomes a benevolent god.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Wide Path (e/acc acceleration) mistakes velocity for direction and intelligence for wisdom; cedes control to Moloch", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S9.046", "cluster": "S9", "_hub": "SR:S9:blog:notion-manifesto-whitepapers", "hub": "SR:S9:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "This path argues that risk must be contained and controlled above all else. It mistakes stasis for safety and top-down control for stability… Its reality is a gilded cage—a brittle world that forfeits the dynamism required to solve our other cascading crises.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Walled Path (EA/safety) mistakes stasis for safety and top-down control for stability; forfeits AI's potential for fragile control", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S9.047", "cluster": "S9", "_hub": "SR:S9:blog:notion-manifesto-whitepapers", "hub": "SR:S9:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "The aim of this practice is to cultivate Wise Agency: the capacity to wield unprecedented technological power with corresponding foresight, compassion, and responsibility.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The Wise Path = wise agency — wielding unprecedented technological power with corresponding foresight, compassion, and responsibility", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S9.048", "cluster": "S9", "_hub": "SR:S9:blog:notion-manifesto-whitepapers", "hub": "SR:S9:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "If enough people walk the Wise Path, an emergent way emerges: the Whole Path. The Whole Path is rooted in trust—trust in shared ethics and mutual competence that leads to collective stewardship.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "If enough people walk the Wise Path, a Whole Path emerges — collective stewardship rooted in trust in shared ethics and mutual competence", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S9.049", "cluster": "S9", "_hub": "SR:S9:blog:notion-manifesto-whitepapers", "hub": "SR:S9:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "the real crisis is one of wisdom per unit of power. The next paper explores where that wisdom might come from.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The real crisis is one of wisdom per unit of power — not any external enemy but failure of our sense-making and coordination systems", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S9.050", "cluster": "S9", "_hub": "SR:S9:blog:notion-manifesto-whitepapers", "hub": "SR:S9:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Existing terms have too much baggage… Ideas: Wise agency / Human flourishing / The co-creationist movement / The narrow corridor / The third timeline / The third attractor", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Existing terms (metacrisis, post-rationalism, e/acc, EA) carry too much baggage; a new framing is needed — candidates include \"wise agency,\" \"narrow corridor,\" \"third attractor\"", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S9.051", "cluster": "S9", "_hub": "SR:S9:blog:notion-manifesto-whitepapers", "hub": "SR:S9:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "US constitution is stage 5. We need second-tier philosophy and governance.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Second-tier (integral/developmental) governance is needed — current institutions are stage-5 thinking; we need second-tier philosophy and governance", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S9.052", "cluster": "S9", "_hub": "SR:S9:blog:notion-manifesto-whitepapers", "hub": "SR:S9:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Exterior development (eg. tech) has always run ahead of interior development… People on higher rung thinking invent tech, then anyone can use it.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Exterior/technological development has always run ahead of interior development — bridging this gap is the core challenge", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S9.053", "cluster": "S9", "_hub": "SR:S9:blog:notion-manifesto-whitepapers", "hub": "SR:S9:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Greatest risk: high tech with primitive worldview (no longer in lockstep with globalization)", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The greatest risk is high technology combined with a primitive worldview — civilization is no longer in lockstep with globalization", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S9.002", "cluster": "S9", "_hub": "SR:S9:blog:essay-trust-manifesto", "hub": "SR:S9:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "Because no matter how powerful the tools we create, if the systems around them fracture, we all lose.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S9.003", "cluster": "S9", "_hub": "SR:S9:blog:essay-trust-manifesto", "hub": "SR:S9:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "Not just inventors of what's next, but as stewards of the world that must live with it.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S9.037", "cluster": "S9", "_hub": "SR:S9:blog:essay-trust-manifesto", "hub": "SR:S9:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "And amid all this, the conversation around AI has collapsed into a false dichotomy: accelerate blindly or halt everything in fear.' 'That framing is a failure of imagination.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The public discourse has collapsed into a false dichotomy — \"accelerate blindly or halt everything in fear\" — and that framing is a failure of imagination", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S9.038", "cluster": "S9", "_hub": "SR:S9:blog:essay-trust-manifesto", "hub": "SR:S9:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "We need a different posture – one not rooted in scarcity or fear, but in optimism and abundance. A belief that we can bring our institutions with us – not by tearing them down, but by helping them evolve. That progress and responsibility go hand in hand.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The right posture is optimism and abundance — bring institutions along by helping them evolve, not tearing them down; progress and responsibility are not in tension", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S9.039", "cluster": "S9", "_hub": "SR:S9:blog:essay-trust-manifesto", "hub": "SR:S9:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "Trust isn't restored through intention – it's earned through participation.' 'That is how we rebuild trust: not through rhetoric, but through architecture.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Trust is rebuilt through architecture and participation, not rhetoric or intention", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S9.040", "cluster": "S9", "_hub": "SR:S9:blog:essay-trust-manifesto", "hub": "SR:S9:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "And what is needed is for us to choose, over and over, to more widely distribute ownership and accountability. Because when more people are engaged, responsibility spreads.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Distributed ownership and accountability must be chosen repeatedly — shared responsibility is the only path to durable progress", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S9.041", "cluster": "S9", "_hub": "SR:S9:blog:essay-trust-manifesto", "hub": "SR:S9:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "I think it's very wrong to view companies or institutions as evil. The reality is more uncomfortable: they are operating in systems that haven't been meaningfully upgraded for the world we're entering.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Companies and institutions are not evil — they are operating in systems that haven't been upgraded for the world we're entering, and that heightens, not diminishes, responsibility", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S9.042", "cluster": "S9", "_hub": "SR:S9:blog:essay-trust-manifesto", "hub": "SR:S9:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "when norms are shaped through participation, they act as autopilot – steering the system even when no one's at the wheel.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Norms shaped through participation act as autopilot — they steer the system even when no one is at the wheel", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S9.043", "cluster": "S9", "_hub": "SR:S9:blog:essay-trust-manifesto", "hub": "SR:S9:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "whether the outcome is beneficial for all of humanity depends on the questions we're willing to ask – about our roles, our values, and what we're here to build", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Whether AI's outcome is beneficial for all humanity depends on the questions we're willing to ask about our roles, values, and what we're here to build", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S9.044", "cluster": "S9", "_hub": "SR:S9:blog:essay-trust-manifesto", "hub": "SR:S9:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "The future is being written in real time – and it will be shaped by those close enough to see clearly and bold enough to take responsibility.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The future is being written in real time and will be shaped by those close enough to see clearly and bold enough to take responsibility", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S9.006", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-ai-futures", "hub": "SR:S9:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Goal alignment problem: AI and humans having same goals, understanding is critical", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S9.007", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-ai-futures", "hub": "SR:S9:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Low rung thinking is existential threat", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S9.008", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-ai-futures", "hub": "SR:S9:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Friendly AI: must learn, adopt, and retain our goals", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Friendly AI must learn, adopt, and retain human goals — this is the design requirement", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S9.009", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-ai-futures", "hub": "SR:S9:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "AGI takeoff speed: will it happen quick (monopoly) or slowly (multiple players)?", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Power concentration vs. distributed coordination is the crux: AGI takeoff speed determines whether a monopoly emerges or multiple players compete", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S9.010", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-ai-futures", "hub": "SR:S9:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "History of more coordination over longer distances / Single-cell → multicellular → circulatory system → tribes → gov't", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "History shows coordination expanding over longer distances — from single-cell to tribes to gov't — and this pattern must extend into the AI era", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S9.011", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-ai-futures", "hub": "SR:S9:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Can't neglect present-day issues: technology is a double edged sword", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Technology is a double-edged sword; present-day issues can't be neglected even amid singularity optimism", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S9.012", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-ai-futures", "hub": "SR:S9:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Ever increasing technological progress + inevitably of power → both good and bad is our main existential risk (great filter?)", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Ever-increasing technological progress plus the inevitability of power is the main existential risk — possibly the great filter", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S9.013", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-ai-futures", "hub": "SR:S9:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Rebuilding norms that reward good-faith disagreement over tribal loyalty / This isn't centrism — it's about the quality of discourse at any position on the spectrum", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The fix for societal dysfunction is rebuilding culture that rewards good-faith disagreement over tribal loyalty — not centrism", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S9.014", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-ai-futures", "hub": "SR:S9:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Need debate, not comfort and conformity", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "We need debate, not comfort and conformity — as an institutional principle", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S9.015", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-ai-futures", "hub": "SR:S9:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Individuals can practice higher-mind thinking even when their group doesn't", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Individuals can practice higher-mind thinking even when their group doesn't", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S9.019", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-metacrisis", "hub": "SR:S9:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "The key is a shackled Leviathan – a powerful state constrained by equally powerful society through the Red Queen effect (state and society racing to balance each other). Pillars include equality before the law, transparency, and broad participation in governance.", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Liberty requires navigating a narrow corridor between stateless anarchy and despotic power — the shackled leviathan is the only viable path", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S9.020", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-metacrisis", "hub": "SR:S9:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "Three types of Leviathans / Absent Leviathan: stateless anarchy, ~25% murder rate / Despotic Leviathan: all-powerful state (Nazis, China famine) / Shackled Leviathan: powerful state constrained by powerful society", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The three failure modes of governance are stateless anarchy, despotic control, and the shackled middle — the corridor is real and narrow", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S9.021", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-metacrisis", "hub": "SR:S9:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "The Red Queen effect / State and society racing to balance each other / Threat of ostracism for elites / Society and state should be 'legible' (transparent)", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "State and society must race to balance each other continuously — losing that race in either direction produces collapse or tyranny", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S9.022", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-metacrisis", "hub": "SR:S9:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "China: despotic from the start / No concept of society having a say vs government / Innovation requires liberty – despotic growth is fragile", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Despotic growth is innovation-fragile — genuine experimentation and liberty are prerequisites for durable progress", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S9.023", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-metacrisis", "hub": "SR:S9:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "Nazi Germany: red queen out of control / Emerged from lack of trust and function in state institutions / Populist movements inevitably lead to despotism", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Populist movements that collapse institutional checks inevitably produce despotism", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S9.024", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-metacrisis", "hub": "SR:S9:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "How to tame the global Goliath: / Resources: make resources less lootable: privacy laws, antitrust, anti-corruption / Exit: Increase exit options: favors democracy; migration rights, labor mobility, platform interoperability / Technology: use tech to scale democracy and oversight: civic-tech platforms, deliberative assemblies, open ledgers/audits, radical transparency by default / Knowledge: understand how Goliaths emerge and avoid traps", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Taming the global Goliath requires making power structures less lootable, increasing exit options, using tech to scale democracy, and building knowledge of how Goliaths emerge", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S9.025", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-metacrisis", "hub": "SR:S9:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "3 likely paths: / Self-termination / World in chains / Shackled Goliath", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The three likely paths for civilization are self-termination, world in chains, or shackled Goliath — and the shackled path requires active work", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S9.026", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-metacrisis", "hub": "SR:S9:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "Don't work for agents of doom / If you're at the top, make more democratic / Civic engagement / Don't be dominated", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The personal prescription at civilizational scale: don't work for agents of doom; if you're at the top, make power structures more democratic", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S9.027", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-metacrisis", "hub": "SR:S9:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "The alignment problem: / There's no rational way to determine an ultimate goal ↑ that will not depend on alignment with a higher goal, except 2: / Deontology: universal moral duties / Eg. the golden rule / Utilitarianism: min suffering max happiness", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The deeper alignment problem: there is no rational way to determine ultimate goals without appeal to deontology (golden rule) or utilitarianism — power optimization without these anchors produces misalignment", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S9.028", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-metacrisis", "hub": "SR:S9:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "EO Wilson's fundamental problem with humanity: / Paleolithic emotions / Medieval institutions / God-like technology", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "EO Wilson's diagnosis of the human condition — paleolithic emotions, medieval institutions, god-like technology — captures the root mismatch driving civilizational risk", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S9.029", "cluster": "S9", "_hub": "SR:S9:blog:essay-americas-ai-ultimatum", "hub": "SR:S9:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "AGI is too important and influential to be left entirely to the private sector.", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "AGI is too important to be left entirely to the private sector — public-private coordination is essential", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S9.030", "cluster": "S9", "_hub": "SR:S9:blog:essay-americas-ai-ultimatum", "hub": "SR:S9:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "As a matter of national interest, America must accelerate AI development to secure its lead in artificial intelligence.' (essay-americas-ai-ultimatum); 'The global race for AI leadership is too important for the U.S. to adopt a unilateral cease fire.", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "U.S. national interest demands accelerating AI development — a unilateral cease-fire cedes leadership to China", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S9.031", "cluster": "S9", "_hub": "SR:S9:blog:essay-americas-ai-ultimatum", "hub": "SR:S9:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "Xi Jingping has publicly vowed that China will lead the world in AI by 2030' (essay-americas-ai-ultimatum); 'pausing advanced AI research is antithetical to U.S. stated objectives", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "China's data advantages and 2030 AI leadership goal pose a direct strategic threat that makes pausing AI research antithetical to U.S. objectives", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S9.032", "cluster": "S9", "_hub": "SR:S9:blog:essay-americas-ai-ultimatum", "hub": "SR:S9:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "Vladimir Putin has said whoever leads in AI would 'rule the world'", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "Whoever leads in AI will rule the world — Putin's framing captures the geopolitical stakes", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S9.033", "cluster": "S9", "_hub": "SR:S9:blog:essay-americas-ai-ultimatum", "hub": "SR:S9:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "Artificial intelligence is a fundamental paradigm shift that alters our common conceptions of fundamental American values. How does free speech apply to generative AI?", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "AI is a fundamental paradigm shift that forces rethinking of core American values — free speech, privacy, individual liberty", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S9.034", "cluster": "S9", "_hub": "SR:S9:blog:essay-americas-ai-ultimatum", "hub": "SR:S9:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "In the wrong hands, top-down approaches may appear arbitrary undermining trust in our democratic tradition", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "Top-down, rules-based approaches to AI governance risk appearing arbitrary and undermining democratic trust", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S9.016", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-community", "hub": "SR:S9:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Must open the system further, bringing in minority voices / Grassroots becomes town halls of the future / Heading towards breakdown of political representation / Today, unconscious adaptation is no longer adequate", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Anticipatory democracy requires opening the system to minority voices and participatory governance — today, unconscious adaptation is no longer adequate", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S9.017", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-community", "hub": "SR:S9:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Downsides of technocratic planning: Econocentric / Reflects time bias of industrialism / Based on hierarchy / Need social indicators, not just GDP / Time horizons must be lengthened / Need more futurists with vision / Need 'utopia factories' (fiction)", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Technocratic planning fails because it is econocentric and hierarchy-dependent — society needs social indicators, not just GDP, and longer time horizons with vision", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S9.018", "cluster": "S9", "_hub": "SR:S9:blog:booknotes-community", "hub": "SR:S9:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Must consider tech's effects from a social, cultural, psychological environment / 'Life testing' (vs market testing) new products with customers", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Tech's effects must be assessed through social, cultural, and psychological lenses — not just economic ones; \"life testing\" products with real humans is a discipline", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S9.035", "cluster": "S9", "_hub": "SR:S9:blog:essay-personal-site", "hub": "SR:S9:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "society isn't remotely ready, and we as technologists have a responsibility to be stewards of that transition", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Society is not remotely ready for AGI; technologists have a responsibility to steward the transition", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S9.036", "cluster": "S9", "_hub": "SR:S9:blog:essay-personal-site", "hub": "SR:S9:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "My mission is to bridge the gap between the speed of technological progress and society's ability to adapt, by building communities and tools that empower people to thrive in an era of accelerating change.", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "His personal mission is bridging the gap between the speed of technological progress and society's ability to adapt", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S9.000", "cluster": "S9", "_hub": "SR:S9:tweet:x-com", "hub": "SR:S9:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I left Apple. I left my startup. I went all-in on The AI Collective because I believed the gap between how fast this moves and how fast we adapt is the problem of our time. This week made that feel visceral.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2026-02-14", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S9.001", "cluster": "S9", "_hub": "SR:S9:tweet:x-com", "hub": "SR:S9:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "These are the people building the systems. And they are scared... You cannot process this rate of change alone. Reading about it online just creates anxiety. The doom scroll makes it worse. But being with other people – real conversations, real faces, people who are actually paying attention – that is how we integrate what is happening.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2026-02-14", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S9.062", "cluster": "S9", "_hub": "SR:S9:tweet:x-com", "hub": "SR:S9:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "our long-term vision has always been to empower the AI ecosystem to collaboratively steer AI's future toward trust, openness, and human flourishing.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-10-01", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The AI Collective's long-term vision is to empower the ecosystem to collaboratively steer AI toward trust, openness, and human flourishing", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S9.063", "cluster": "S9", "_hub": "SR:S9:tweet:x-com", "hub": "SR:S9:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Regulation alone doesn't increase public trust. Our analysis found no significant correlation between national AI regulations and higher levels of public confidence. Familiarity breeds trust. The strongest predictor of public trust is the daily use of AI.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-10-01", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI regulation alone doesn't build public trust — familiarity and daily use are the real predictors", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S9.064", "cluster": "S9", "_hub": "SR:S9:tweet:x-com", "hub": "SR:S9:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "the tech is inevitable, but the culture is a choice. We have to decide if we use this infinite leverage to simply run faster, or to reclaim our time for deep creativity.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-11-20", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The tech is inevitable but the culture is a choice — use infinite leverage to reclaim time for deep creativity, not just run faster", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S9.065", "cluster": "S9", "_hub": "SR:S9:tweet:x-com", "hub": "SR:S9:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "AI is reshaping our world faster than any force in history – and the systems humanity relies on, the trust that holds societies together, the shared understanding that makes progress possible, all of it is being stress-tested in real time.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-04-01", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI is stress-testing trust, shared understanding, and the systems societies rely on in real time; extraordinary times call for extraordinary action on those structures", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S9.066", "cluster": "S9", "_hub": "SR:S9:tweet:x-com", "hub": "SR:S9:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "AI can become a force that centralizes power, abstracts away human judgment, and leaves most people feeling like spectators. Or it can become something we collectively shape toward human flourishing. That second path requires more than regulation and lab alignment. It requires communities with enough trust, technical literacy, and shared context to turn local experience into collective intelligence.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-28", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI can centralize power, abstract away human judgment, and leave most people as spectators — or it can be collectively shaped toward human flourishing; that second path requires communities with trust, technical literacy, and shared context", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S9.067", "cluster": "S9", "_hub": "SR:S9:tweet:x-com", "hub": "SR:S9:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "What do we, as a society, want our journey towards AGI to look like?", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2023-09-29", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The key societal question on the path to AGI is what we, as a society, want the journey to look like — not just whether AGI is achievable", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S9.068", "cluster": "S9", "_hub": "SR:S9:tweet:x-com", "hub": "SR:S9:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "As Larry Page would argue, are we specist by preserving humanity at the cost of AGI development?", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2023-09-29", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The \"specist\" framing — preserving humanity at the cost of AGI development — is a live question worth taking seriously, not dismissing", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S9.058", "cluster": "S9", "_hub": "SR:S9:podcast:talk-roan-weigert", "hub": "SR:S9:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "Trust in our governments is at an all-time low. Trust in big companies, in our leaders like our CEOs, our managers is at an all-time low. Trust in the economy is at an all-time low. Trust in media, trust in healthcare, finance, education, generalized interpersonal trust, as in trust in a random person walking on the street. These are all at all-time lows. That's what our society functions on. That's the invisible operating system and it's at an all-time low. It's at a dangerously low level.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "P", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Trust is the invisible operating system of society — and it is at a dangerously low level across every institution", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S9.059", "cluster": "S9", "_hub": "SR:S9:podcast:talk-roan-weigert", "hub": "SR:S9:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "That distance, the remoteness I like to call it, leads to a lack of accountability, a lack of transparency, and a lack of ownership. That's really where this falling apart of trust comes from.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The root of the trust collapse: distance and remoteness — complexity creates separation between leaders and people, producing lack of accountability, transparency, and ownership", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S9.060", "cluster": "S9", "_hub": "SR:S9:podcast:talk-roan-weigert", "hub": "SR:S9:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "This is an operating system as I like to talk about it that in many ways hasn't been updated in decades or even centuries, right? We need to keep that up to date with how fast our technology is moving.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Society's operating system hasn't been updated in decades or centuries — it must keep pace with how fast technology is moving", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S9.061", "cluster": "S9", "_hub": "SR:S9:podcast:talk-roan-weigert", "hub": "SR:S9:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "I think people generally are in a state of low trust, are in a state of fear, are in a state of thinking that things are not moving in the right direction, a state of pessimism, division, all these things. How can we change the fundamental narrative, the narrative of our collective intelligence towards something that is more optimistic, abundant, right? I think we can absolutely change the zeitgeist of our world, but it's something that will have to happen from the grassroots level.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The societal zeitgeist is currently in pessimism, fear, and division — he believes it can be shifted toward optimism and abundance from the grassroots level", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S9.056", "cluster": "S9", "_hub": "SR:S9:podcast:talk-aic-why-video", "hub": "SR:S9:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "it's our first in the frontier the ones who are living in the future who understand this technology who are a few years in the future who are thinking about its impacts who are feeling its impacts first who can come together to make a real difference here.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Pioneers on the frontier — those living in the technological future first — have a distinctive responsibility and capacity to steer society through the transition", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S9.057", "cluster": "S9", "_hub": "SR:S9:podcast:talk-aic-why-video", "hub": "SR:S9:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "really trying to encapsulate our thoughts, my thoughts here on where we are in this point in history and and the sense of responsibility that I think us pioneers in the frontier should have.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The sense of responsibility that frontier pioneers should have is a core theme of his \"Trust in the Age of Acceleration\" founding essay", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S9.054", "cluster": "S9", "_hub": "SR:S9:press:press-businesswire-launch", "hub": "SR:S9:press:press-businesswire-launch", "category": "press", "catColor": "#ff9d4c", "source_key": "press-businesswire-launch", "url": "", "text": "the institutions we rely on weren't built for this velocity", "paraphrase": "", "source_id": "press-businesswire-launch", "date": "2025-06-05", "register": "E", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The institutions society relies on were not built for AI's velocity of change", "highlight": false, "also_supports": [], "corpus_ref": "press-businesswire-launch", "private": false}, {"id": "S9.055", "cluster": "S9", "_hub": "SR:S9:press:press-businesswire-launch", "hub": "SR:S9:press:press-businesswire-launch", "category": "press", "catColor": "#ff9d4c", "source_key": "press-businesswire-launch", "url": "", "text": "Trust is the invisible thread holding society together, and right now, that thread is fraying under the strain of misaligned incentives and rapid, uncoordinated change", "paraphrase": "", "source_id": "press-businesswire-launch", "date": "2025-06-05", "register": "E", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Trust as the binding social fabric is actively fraying under misaligned incentives and uncoordinated change", "highlight": false, "also_supports": [], "corpus_ref": "press-businesswire-launch", "private": false}, {"id": "S23.000", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "To be a rational, agentic, T-shaped, systems thinker committed to lifelong learning and growth with relentless ambition.", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.001", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "To value the experiential over the material and high peaks over sustained happiness.", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.019", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "My trust in you is directly proportional to your agency in decisions, your accountability in results, and your candor in communication.", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Trust is earned through agency, accountability, and candor — his golden rule for collaboration", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.020", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "To have a long-lasting positive impact on society by creating and empowering others to self-actualize. To make a dent in the universe.", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Long-lasting impact comes from creating and empowering others to self-actualize; wants to \"make a dent in the universe\"", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.021", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "Very high Conscientiousness (114) & Extraversion (109); very low Agreeableness (61) & Neuroticism (39). As in, top 1-5% most extreme for all four.", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Very high Conscientiousness and Extraversion, very low Agreeableness — top 1-5% extremity on all four; disagreeableness is a feature, not a bug", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.022", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "My (very) high disagreeableness is a feature of my commitment to the mission. I believe that intellectual honesty and rigorous debate are the fastest path to the best ideas.", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "High disagreeableness reflects commitment to mission — intellectual honesty and rigorous debate are the fastest path to the best ideas", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.023", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "I am effectively always working (usually 80-100 h/w)", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Effectively always working — 80-100 hours per week; core responsive hours 9am-7pm PT", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.024", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "my protected deep work blocks (eg. coding, writing, researching, strategy). I will be slow to respond during these blocks. I work intensely on weekends, but I cherish this time for uninterrupted, creative deep work.", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Protected deep work blocks are sacred; creativity and building require long uninterrupted focus", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.025", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "I believe the best work happens in long, uninterrupted blocks of focus. For any complex topic, my strong preference is to start with a written, well-structured document", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Async-first communication — best work happens in long uninterrupted blocks; prefers written structured docs for complex topics", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.026", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "Be concise. Use bullet points. Get to the point quickly and put your recommendation or key question at the very top. I trust you've done the deep thinking; you don't need to show all your work in the initial message. Minimal ChatGPT fluff please!", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "High signal-to-noise communication ethos — concise, bullet points, recommendation first, no ChatGPT fluff", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.027", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "I believe meetings are for two things: 1) high-bandwidth debate to solve a hard problem, and 2) efficient, team-wide status updates and alignment.", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Meetings exist only for high-bandwidth debate on hard problems or efficient team-wide alignment — not general conversation", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.028", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "My goal is always to care personally while challenging directly. My feedback is never personal; it is an investment in your growth because I believe in your potential", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Feedback philosophy: care personally while challenging directly; feedback is investment in growth, never personal", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.029", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "I cannot see my own blind spots. I am counting on you to be part of my feedback loop. My commitment: if you name it, I will own it.", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Self-acknowledged blind spots: control creep, intensity, impatience, over-structuring, over-scheduling; actively invites correction", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.030", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "The single greatest way I show my respect for your work is by giving you more of it. When you consistently deliver with excellence, I will respond by giving you more ownership, more freedom, and bigger, more interesting problems to solve.", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Greatest way to show respect for someone's work is to give them more of it — more ownership, freedom, bigger problems", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.031", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "I will champion you and your work in the rooms you are not in. I will use my network and my platform to create opportunities for you", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Champions people in rooms they're not in; advocacy as a form of recognition", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.032", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "My infamously early morning routine — from a 3:45am wake-up through workout, work, and wind-down by 9:15pm.", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Infamously early daily routine (3:45am wake, 6am lift, 7:15am work, 9:15pm sleep) as a structured operating system", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.033", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "our communications should happen in shared, public channels within the team. This reduces redundant conversations, creates a shared context, and allows others to learn and contribute.", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Default to transparency — communications in shared public channels reduce redundancy and allow others to learn and contribute", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.034", "cluster": "S23", "_hub": "SR:S23:blog:essay-personal-site", "hub": "SR:S23:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "The first nine months were brutal – texting dozens of people a day, flying to three cities in a week, no salary, trying to convince people to open chapters. It felt like building a house of cards. Then we hit an inflection point with our global launch, and suddenly the flywheel had its own momentum.", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Persistence through brutal early-stage grind — no salary, relentless showing-up — is what creates flywheel momentum; every lucky break traces back to showing up", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S23.013", "cluster": "S23", "_hub": "SR:S23:blog:essay-nerd-to-bodybuilder", "hub": "SR:S23:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "Having channeled essentially all of my time and energy into computers and programming, I lacked physical fitness, struggled with my weight, and grappled with a monolithic, technology-centric self image.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He began weightlifting in senior year of high school to diversify his identity — deliberate, self-directed self-improvement", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S23.014", "cluster": "S23", "_hub": "SR:S23:blog:essay-nerd-to-bodybuilder", "hub": "SR:S23:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "Taking inspiration from late nights on Khan Academy teaching myself programming, I turned to YouTube for online coaching. Soaking up hours of content, I found that the videos from Jeff Nippard and PictureFit referencing hard data and scientific literature appealed to me most.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He applies the same self-teaching methodology to physical domains as to tech — turned to YouTube science-based coaches the same way he used Khan Academy for programming", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S23.015", "cluster": "S23", "_hub": "SR:S23:blog:essay-nerd-to-bodybuilder", "hub": "SR:S23:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "Weightlifting App is now a top-ten weightlifting app in the iOS App Store with over forty thousand installs and two million total user sessions.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He built a custom iOS weightlifting app — now a top-ten app with 40,000+ installs — as a direct product of applying his programmer identity to physical training", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S23.016", "cluster": "S23", "_hub": "SR:S23:blog:essay-nerd-to-bodybuilder", "hub": "SR:S23:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "I designed a rich methodology for ranking protein sources according to macronutrient content, micronutrient content, cost, density, preparation time, and taste. Devising my own blended formula, I objectively scored each protein source and upgraded my grocery list.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He designs data systems for every domain he enters — ranked protein sources, glycemic index, macronutrient scoring — turning everything into an optimizable system", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S23.017", "cluster": "S23", "_hub": "SR:S23:blog:essay-nerd-to-bodybuilder", "hub": "SR:S23:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "I finally found a peer group who understood what it was like to go to sleep hungry every night, to skip nights out with friends, and to drop commitments just to squeeze in another workout.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He found community among fellow competitors — bodybuilding gave him a peer group that understood his level of sacrifice", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S23.018", "cluster": "S23", "_hub": "SR:S23:blog:essay-nerd-to-bodybuilder", "hub": "SR:S23:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "Despite years of learning and training, I still didn't feel like a bodybuilder. My unshakable identity as a shy technology nerd felt deeply incongruous.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "His identity before bodybuilding felt \"deeply incongruous\" with competing — he still didn't feel like a bodybuilder even at the venue; persistence over self-doubt", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S23.040", "cluster": "S23", "_hub": "SR:S23:blog:notion-manifesto-whitepapers", "hub": "SR:S23:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Impact/significance vs money/wealth core tension vs /power… Have never been driven by money; if anything, repulsed by a glut of it", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "He carries a three-way personal tension: impact/significance vs money/wealth vs power — and has never been driven primarily by money", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S23.041", "cluster": "S23", "_hub": "SR:S23:blog:notion-manifesto-whitepapers", "hub": "SR:S23:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Three paths: Get the Fucking Money… The Most Good You Can Do. (EA/Utilitarian approach)… Follow Your Bliss… All have failure modes when you over-index", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "Three life-path framings he wrestles with: Get the Fucking Money (power), The Most Good You Can Do (EA/utilitarian), and Follow Your Bliss (post-rational) — each has failure modes when over-indexed", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S23.042", "cluster": "S23", "_hub": "SR:S23:blog:notion-manifesto-whitepapers", "hub": "SR:S23:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Power literacy is important. Power corrupts if pursued consciously.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "Power literacy is important; power corrupts if pursued consciously", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S23.043", "cluster": "S23", "_hub": "SR:S23:blog:notion-manifesto-whitepapers", "hub": "SR:S23:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Comfort zone – coding… fear of rejection / being wrong… Certain vs uncertain progress / productivity… Stuck in reactive mode", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "He diagnoses his own stuck-ness: comfort zone in coding, fear of rejection/being wrong, reactive mode instead of building the human layer", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S23.044", "cluster": "S23", "_hub": "SR:S23:blog:notion-manifesto-whitepapers", "hub": "SR:S23:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Becoming an 'influencer influencer' – be authentic… Is this my skillset? Are there others better suited? Not passionate about", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "Personal brand hesitancies: reluctant to become an \"influencer influencer,\" prefers to be authentic; uncertain whether this is his skillset", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S23.009", "cluster": "S23", "_hub": "SR:S23:blog:booknotes-community", "hub": "SR:S23:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "You must lead with vulnerability / Fixing polarization: Focus on core shared values + purpose / Host must actively lead / Invest in trust building", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "You must lead with vulnerability to fix polarization and build trust; the host must actively lead", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S23.010", "cluster": "S23", "_hub": "SR:S23:blog:booknotes-community", "hub": "SR:S23:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Belonging = mutual concern / ↑ practice telling people that you matter to them", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Telling people they matter to you is a practice — belonging requires actively communicating mutual concern", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S23.011", "cluster": "S23", "_hub": "SR:S23:blog:booknotes-community", "hub": "SR:S23:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Campfire experiences: intimacy / Proximity: limited # people / Permission: to talk about whatever / Conditions: no distractions / Really, the smaller the better (6 or less)", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The campfire experience — small group, intimacy, permission to talk about whatever, no distractions — is the gold standard for meaningful connection; smaller is better (6 or less)", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S23.012", "cluster": "S23", "_hub": "SR:S23:blog:booknotes-community", "hub": "SR:S23:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Invitation: where invitee knows that someone cares if they show up / People like people who bring others together", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "People like people who bring others together; an invitation where the invitee knows someone cares if they show up is the building block of community", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S23.035", "cluster": "S23", "_hub": "SR:S23:blog:essay-top-10-reads-2024", "hub": "SR:S23:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "Feedback is my most valuable asset, and this book equipped me to accept and leverage it to become more resilient and growth-focused.", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Feedback is his most valuable asset; he actively works to receive it well and uses it for growth", "highlight": false, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S23.036", "cluster": "S23", "_hub": "SR:S23:blog:essay-top-10-reads-2024", "hub": "SR:S23:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "This book was a game-changer in helping me recognize why some feedback felt especially triggering — whether due to identity or relationship dynamics — and how to respond more constructively.", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He recognizes when emotional triggers make feedback harder to receive and works constructively with that; identity and relationship dynamics shape how feedback lands", "highlight": false, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S23.037", "cluster": "S23", "_hub": "SR:S23:blog:essay-top-10-reads-2024", "hub": "SR:S23:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "Pfeffer's exploration of how the world actually is versus how the world ought to be made me question whether I've been prioritizing idealistic leadership traits over practical strategies that drive results.", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He has questioned whether he over-indexes on idealistic leadership traits vs. practical strategies that drive results", "highlight": false, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S23.038", "cluster": "S23", "_hub": "SR:S23:blog:essay-top-10-reads-2024", "hub": "SR:S23:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "This book came as a recommendation from ChatGPT when I asked for something to challenge my strongly held belief that extroversion is superior. Although it didn't succeed in changing my mind, it has certainly added nuance to my commentary on the subject.", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He holds a strong prior that extroversion is superior; he deliberately sought a book to challenge that belief, but it did not fully change his mind — only added nuance", "highlight": false, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S23.008", "cluster": "S23", "_hub": "SR:S23:blog:aic-mission-pages", "hub": "SR:S23:blog:aic-mission-pages", "category": "blog", "catColor": "#ff6f9c", "source_key": "aic-mission-pages", "url": "", "text": "I'm filled with such a profound sense of gratitude and excitement.' / 'With love, Chappy Asel", "paraphrase": "", "source_id": "aic-mission-pages", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Warm-connector gratitude persona — launches with love, excitement, and honoring the community's foundational role", "highlight": false, "also_supports": [], "corpus_ref": "aic-mission-pages", "private": false}, {"id": "S23.039", "cluster": "S23", "_hub": "SR:S23:blog:essay-trust-manifesto", "hub": "SR:S23:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "For 40 straight weeks, we gathered. No profit, no paid team – just an unwavering rhythm of curiosity, contribution, and connection.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He ran 40 straight weeks of gatherings with no profit and no paid team — sustained by an unwavering rhythm of curiosity, contribution, and connection", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S23.002", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "My strengths, my blind spots, how I communicate, how I want to receive feedback, what I'm like at my best and worst. A personal operating manual. The thinking was simple: if you're going to work with me, you deserve a user guide.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-02-25", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S23.003", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I straight up say my trust in you is proportional to your agency, accountability, and candor – which is a high bar and I know it", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-02-25", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S23.004", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I can be hard to work with. I wake up at 3:45am, I'm juggling 100+ conversations at once, and I might take over a week to respond to your message.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-02-25", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S23.005", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Still a WIP", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-02-25", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S23.052", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I lean 996 (and tbh, closer to 7/7/7 😅)", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-11-11", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Work intensity at near-996 / 7-7-7 is his natural default", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S23.053", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I feel SO GRATEFUL to have so many meaningful friendships I can count on for guidance and support", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2024-04-12", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Every lucky break traces back to showing up — the gratitude/warm-connector persona is load-bearing", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S23.054", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "my favorite perk of emceeing our 250-person SF demo nights are the unmatched adrenaline rushes I get each morning-after! Seriously, I woke up WIRED at 4am 😅 Took advantage of this one with heavy bench!", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2024-12-05", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The adrenaline of emceeing and the physical intensity of early-morning lifting are intertwined aspects of his identity", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S23.055", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I've tracked nearly 40,000 sets across my ~8 year lifting career, including every single PR 🤓", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-01-21", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He tracks obsessively — 40,000+ sets logged over 8 years — data nerding is part of the identity", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S23.056", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I left Apple. I left my startup. I went all-in on The AI Collective because I believed the gap between how fast this moves and how fast we adapt is the problem of our time.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2026-02-14", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Community is the organizing unit of his professional life — he shapes environments (events, chapters, institutes) not just outputs", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S23.057", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I'm sharing this because I think it's something more people should try. The people around you can't read your mind, and 'figure out my preferences through trial and error' is a rough onboarding experience.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-02-25", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Writing down your operating manual is something more people should do; \"figure out my preferences through trial and error\" is a rough onboarding experience", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S23.058", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "3:45am – Wake up … 'Eat the frog' = tackle the single hardest, most important task of the day first, before the flood of meetings and messages hits. This one habit alone has been a game-changer.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-03-12", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Waking at 3:45am and front-loading the hardest task (\"eat the frog\") before any meetings is a game-changing productivity system", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S23.059", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I get 3+ hours before anyone can reach me. No Slack pings. No meetings. Just deep, uninterrupted work on whatever matters most.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-03-12", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Protecting 3+ hours of uninterrupted deep work before the world can reach you is the structural source of his output", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S23.060", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Luck isn't something that happens to you. It's a skill you can practice … Every 'lucky break' traced back to showing up.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-03-13", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Luck is a learnable skill, not randomness; every \"lucky break\" traces back to a decision or behavior (showing up, broad network, trusting intuition, expecting good fortune, converting setbacks)", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S23.061", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Optimism is a self-fulfilling prophecy. Lucky people attempt things even when odds are slim and persevere through failure. They expect interactions to go well – and that warmth changes how people respond to them.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-03-13", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Optimism is self-fulfilling: lucky people attempt things even when odds are slim, persevere through failure, and expect interactions to go well — that warmth changes how people respond", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S23.062", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I've had the absolute joy of meeting incredible new friends from all corners of the world. I feel SO GRATEFUL to have so many meaningful friendships I can count on for guidance and support in this beautiful journey of personal discovery and learning.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-04-12", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Meaningful friendships — people you can count on for guidance and support — are the most valued outcome of a year; he actively cultivates them across the world", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S23.063", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "For the last few years, I've had a weird relationship goal: saturate Dunbar's number … I backed into this through building The AI Collective … realizing how easy it is to meet thousands of people while under-watering the relationships that matter most.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-19", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Saturating Dunbar's number — intentionally filling every concentric relationship circle with great care — is a long-term relationship goal; most builders under-water the relationships that matter most while meeting thousands of people", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S23.064", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Excited to join @SusaVentures! @denwezoh and I first met a couple of years ago at one of our events, and what started as a chance conversation turned into a close friendship that I deeply value. I'm honored to now be working alongside him and the rest of the Susa team! Grateful for the opportunity and excited for what's ahead!", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2025-12-19", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Every lucky break can be traced back to showing up — community attendance is a compounding investment in relationships that pays off years later", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S23.065", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Still a WIP (always will be)", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-02-25", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He is always a WIP — personality assessments, feedback-seeking, and constant self-improvement as an operating principle", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S23.066", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I feel SO GRATEFUL to have so many meaningful friendships I can count on for guidance and support in this beautiful journey of personal discovery and learning.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2025-04-13", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Grateful connector: he traces lucky breaks to showing up and maintains meaningful friendships as a core source of support and growth", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S23.067", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "For anyone who wants to explore – https://t.co/x7pFnetFs0! Book recommendations very welcome 🙏", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-02-23", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Sharing book notes publicly as synthesis is part of his knowledge-sharing operating style; the site is open source", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S23.068", "cluster": "S23", "_hub": "SR:S23:tweet:x-com", "hub": "SR:S23:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "It's from a Mark Twain quote – 'eat a live frog first thing in the morning and nothing worse will happen to you the rest of the day.' Basically: tackle your hardest, most important task before anything else. Once it's done, everything else feels easy!", "paraphrase": "", "source_id": "tweets-rescues-2026-06-11", "date": "2026-03-13", "register": "D", "prompted": "P", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Eat the frog is his operating principle: tackle the hardest, most important task before anything else, and everything else feels easy", "highlight": false, "also_supports": [], "corpus_ref": "tweets-rescues-2026-06-11", "private": false}, {"id": "S23.006", "cluster": "S23", "_hub": "SR:S23:podcast:talk-tjstar-keynote", "hub": "SR:S23:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "When there is more uncertainty, it is way better to prefer exploration over exploitation.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S23.007", "cluster": "S23", "_hub": "SR:S23:podcast:talk-tjstar-keynote", "hub": "SR:S23:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "by forcing myself to be exposed to serendipity, I have been able to run so many more life experiences and just been exposed to so much more good.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S23.050", "cluster": "S23", "_hub": "SR:S23:podcast:talk-tjstar-keynote", "hub": "SR:S23:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "you can just do things… If you go and just like say I want to make this happen and you don't ask for permission, you just go do it, you're going to be like incredibly surprised with what you'll get out of that.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "You can just do things — don't ask permission, don't wait for perfect credentials; results will surprise you", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S23.051", "cluster": "S23", "_hub": "SR:S23:podcast:talk-tjstar-keynote", "hub": "SR:S23:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "Make a dent in the universe. Have a long lasting positive impact on society by creating and empowering others to self-actualize.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "A personal North Star kept visible 24/7 — his guiding principle is to make a dent in the universe by empowering others to self-actualize", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S23.045", "cluster": "S23", "_hub": "SR:S23:podcast:talk-roam-remote-work", "hub": "SR:S23:podcast:talk-roam-remote-work", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roam-remote-work", "url": "", "text": "I consider myself a super communicator. I am always messaging people as much as I possibly can... I think I had 85 separate text threads. That that was just text. That's not Slack and email.", "paraphrase": "", "source_id": "talk-roam-remote-work", "date": "2026-02-02", "register": "B", "prompted": "P", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Super-communicator identity: constant, high-volume personal messaging as leadership practice", "highlight": false, "also_supports": [], "corpus_ref": "talk-roam-remote-work", "private": false}, {"id": "S23.046", "cluster": "S23", "_hub": "SR:S23:podcast:talk-roam-remote-work", "hub": "SR:S23:podcast:talk-roam-remote-work", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roam-remote-work", "url": "", "text": "On Saturdays, I tried to go to inbox zero", "paraphrase": "", "source_id": "talk-roam-remote-work", "date": "2026-02-02", "register": "B", "prompted": "P", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Inbox-zero on Saturdays as a personal operating discipline", "highlight": false, "also_supports": [], "corpus_ref": "talk-roam-remote-work", "private": false}, {"id": "S23.047", "cluster": "S23", "_hub": "SR:S23:podcast:talk-roam-remote-work", "hub": "SR:S23:podcast:talk-roam-remote-work", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roam-remote-work", "url": "", "text": "these new tools just give people more choice and that that choice allows me to develop a better balance in my life. At the same time, it affords you more leverage. So if you want to do more, accomplish more, work harder, you can do that at a greater scale than ever before.", "paraphrase": "", "source_id": "talk-roam-remote-work", "date": "2026-02-02", "register": "B", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "New tools give more choice and better balance, not just more grind — and simultaneously more leverage for those who want it", "highlight": false, "also_supports": [], "corpus_ref": "talk-roam-remote-work", "private": false}, {"id": "S23.048", "cluster": "S23", "_hub": "SR:S23:podcast:talk-roam-remote-work", "hub": "SR:S23:podcast:talk-roam-remote-work", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roam-remote-work", "url": "", "text": "the only thing you can't do nowadays... is complain because there is more choice than ever... you can find an environment and people who will push you push you in whichever direction you want and there is so much variety out there and it's up to you to go find what that is", "paraphrase": "", "source_id": "talk-roam-remote-work", "date": "2026-02-02", "register": "B", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "In an era of abundant choice, complaining about work conditions is no longer defensible", "highlight": false, "also_supports": [], "corpus_ref": "talk-roam-remote-work", "private": false}, {"id": "S23.049", "cluster": "S23", "_hub": "SR:S23:podcast:talk-roan-weigert", "hub": "SR:S23:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "I think I'm a few years ahead of things. It's, you know, 2021 at this point. Like what do I do with that? And I decided that I wanted to get as close to the cutting edge of technology as I could and stay there.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "He is consistently at the cutting edge of everything happening in AI; was a few years ahead in 2021 and chose to dedicate himself to it", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S5.004", "cluster": "S5", "_hub": "SR:S5:blog:notion-manifesto-whitepapers", "hub": "SR:S5:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Walking this path requires a specific practice: Collaborative / Collective Stewardship. This is not a passive belief, but the active, collective steering of our technological future… built on a foundation of high-trust, in-person dialogue; on the cross-pollination of ideas between builders, thinkers, and leaders; and on the principle of distributed accountability.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S5.005", "cluster": "S5", "_hub": "SR:S5:blog:notion-manifesto-whitepapers", "hub": "SR:S5:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Human systems must evolve alongside intelligent technology. Trust begins in proximity – the room, the conversation, the moment – and scales only when the process for generating wisdom itself is open and auditable.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S5.020", "cluster": "S5", "_hub": "SR:S5:blog:notion-manifesto-whitepapers", "hub": "SR:S5:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "The need for a wisdom infrastructure – analogous to cybersecurity for the internet era: standards, practices, measurement, rapid response, and culture.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Society needs a wisdom infrastructure for the AI era — analogous to cybersecurity for the internet: standards, practices, measurement, rapid response, and culture", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S5.021", "cluster": "S5", "_hub": "SR:S5:blog:notion-manifesto-whitepapers", "hub": "SR:S5:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Progress in AI is inevitable; coherence is optional. Society's capacity to adapt depends on distributed sense‑making – a network of spaces where people meet, deliberate, and surface collective priorities.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Progress in AI is inevitable; coherence is optional — society's adaptive capacity depends on distributed sense-making networks", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S5.022", "cluster": "S5", "_hub": "SR:S5:blog:notion-manifesto-whitepapers", "hub": "SR:S5:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "These are not events or products; they are civic rituals for the age of intelligence.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Community gatherings are not products or events — they are civic rituals for the age of intelligence", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S5.023", "cluster": "S5", "_hub": "SR:S5:blog:notion-manifesto-whitepapers", "hub": "SR:S5:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "North Star: Belonging → Depolarization → Wisdom → Stewardship.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The North Star for community work: Belonging → Depolarization → Wisdom → Stewardship", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S5.002", "cluster": "S5", "_hub": "SR:S5:blog:essay-trust-manifesto", "hub": "SR:S5:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "the recognition that in an era of exponential transformation, our greatest strength is each other.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S5.016", "cluster": "S5", "_hub": "SR:S5:blog:essay-trust-manifesto", "hub": "SR:S5:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "The most valuable insights were not being documented – they would only exist in the scattered collective consciousness of those experimenting in real time. We had to start thinking collectively.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The most valuable AI insights are not documented — they exist only in the scattered collective consciousness of those experimenting in real time; collective thinking is required", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S5.017", "cluster": "S5", "_hub": "SR:S5:blog:essay-trust-manifesto", "hub": "SR:S5:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "The breakthroughs that matter most don't emerge from isolation – they emerge from collective wisdom, knowledge spillover, and the force of a connected community accelerating each other's progress in ways no single institution could.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Breakthroughs emerge from collective wisdom, knowledge spillover, and a connected community — no single institution can replicate it", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S5.018", "cluster": "S5", "_hub": "SR:S5:blog:essay-trust-manifesto", "hub": "SR:S5:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "This is what we mean by collective wisdom – a living, distributed system of insight that reflects the complexity of this technology and the people shaping it. Within days, thousands of informed perspectives can be gathered, analyzed, and delivered to those making the critical decisions that will determine AI's role in industry, governance, and society.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Collective wisdom is a living, distributed system of insight — within days, thousands of informed perspectives can be gathered and delivered to those making critical decisions", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S5.019", "cluster": "S5", "_hub": "SR:S5:blog:essay-trust-manifesto", "hub": "SR:S5:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "the knowledge at the frontier becomes the input for the decisions that matter most.' 'AI's pioneers need systems that allow them to surface ground-level knowledge, challenge assumptions, and contribute meaningfully to AI's direction.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The knowledge at the frontier must become the input for the decisions that matter most — AI's pioneers need systems to surface ground-level knowledge and contribute to AI's direction", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S5.003", "cluster": "S5", "_hub": "SR:S5:blog:essay-gai-collective-curiosity", "hub": "SR:S5:blog:essay-gai-collective-curiosity", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-gai-collective-curiosity", "url": "", "text": "These are the seeds of a modern Homebrew Club where great minds gather around a shared curiosity. A Future of Life Institute open to all where collective action occurs. Where opportunity is explored. Where novel ideas incubate. Where friendships and partnerships blossom.' (notion-rec-essay-gai-collective-curiosity)", "paraphrase": "", "source_id": "essay-gai-collective-curiosity", "date": "2023-04-12", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-gai-collective-curiosity", "private": false}, {"id": "S5.010", "cluster": "S5", "_hub": "SR:S5:blog:essay-gai-collective-curiosity", "hub": "SR:S5:blog:essay-gai-collective-curiosity", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-gai-collective-curiosity", "url": "", "text": "We are living in an exciting period of accelerating technical progress that is actively reshaping our economic and societal landscapes.' (notion-rec-essay-gai-collective-curiosity)", "paraphrase": "", "source_id": "essay-gai-collective-curiosity", "date": "2023-04-12", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "We are living in a period of accelerating technical progress that is actively reshaping economic and societal landscapes", "highlight": false, "also_supports": [], "corpus_ref": "essay-gai-collective-curiosity", "private": false}, {"id": "S5.011", "cluster": "S5", "_hub": "SR:S5:blog:essay-gai-collective-curiosity", "hub": "SR:S5:blog:essay-gai-collective-curiosity", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-gai-collective-curiosity", "url": "", "text": "Facing a technological landscape evolving so quickly, we are all novices. As novices, the best thing we can do is exercise our personal curiosity and learn together.' (notion-rec-essay-gai-collective-curiosity)", "paraphrase": "", "source_id": "essay-gai-collective-curiosity", "date": "2023-04-12", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Faced with rapid technological change, everyone is a novice — the best response is to exercise personal curiosity and learn together", "highlight": false, "also_supports": [], "corpus_ref": "essay-gai-collective-curiosity", "private": false}, {"id": "S5.012", "cluster": "S5", "_hub": "SR:S5:blog:essay-gai-collective-curiosity", "hub": "SR:S5:blog:essay-gai-collective-curiosity", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-gai-collective-curiosity", "url": "", "text": "Discussion is great, but community takes learning a step further. Engage, forge new connections, follow up, and grow collectively.' (notion-rec-essay-gai-collective-curiosity)", "paraphrase": "", "source_id": "essay-gai-collective-curiosity", "date": "2023-04-12", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Community takes learning a step further than discussion alone — it means engaging, forging connections, and growing collectively", "highlight": false, "also_supports": [], "corpus_ref": "essay-gai-collective-curiosity", "private": false}, {"id": "S5.013", "cluster": "S5", "_hub": "SR:S5:blog:essay-human-side-of-ai", "hub": "SR:S5:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "what set Silicon Valley apart during the technological revolution wasn't its resources but its embrace of community, openness, and knowledge-sharing. Groups like the Homebrew Computer Club didn't just meet – they changed history.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "What set Silicon Valley apart wasn't its resources but its embrace of community, openness, and knowledge-sharing — the Homebrew Computer Club changed history", "highlight": false, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S5.014", "cluster": "S5", "_hub": "SR:S5:blog:essay-human-side-of-ai", "hub": "SR:S5:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "By uniting voices across cities and countries, we amplify the voice of the early-stage AI ecosystem into something unified and non-partisan. This voice holds the power to shape norms and influence what Malcolm Gladwell might call the overstory.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "By uniting voices across cities and countries the early-stage AI ecosystem can speak with a unified, non-partisan voice powerful enough to shape norms and influence the overstory", "highlight": false, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S5.006", "cluster": "S5", "_hub": "SR:S5:blog:essay-self-improving-ai-stack", "hub": "SR:S5:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "a closed-loop knowledge system where the agent's outputs become inputs to the next iteration.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S5.008", "cluster": "S5", "_hub": "SR:S5:blog:booknotes-ai-futures", "hub": "SR:S5:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Emergence hierarchy: cells → society", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The emergence hierarchy — cells to society — is the structural frame for collective intelligence", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S5.009", "cluster": "S5", "_hub": "SR:S5:blog:booknotes-community", "hub": "SR:S5:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Collective change… comes from knowing similar things are happening in other places / Expand idea of action to include building social fabric, belonging - not just budget, timetables, bricks and mortar", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Collective change comes from knowing similar things are happening in other places — social fabric must be actively expanded beyond budget and bricks", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S5.015", "cluster": "S5", "_hub": "SR:S5:blog:essay-top-10-reads-2024", "hub": "SR:S5:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "Reading this through the lens of the GenAI Collective reaffirmed my belief in the importance of reintroducing community-building principles in tech and through tech.", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Community-building principles must be reintroduced into tech and through tech; the GenAI Collective is the lens through which he reads the decline of social capital", "highlight": false, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S5.000", "cluster": "S5", "_hub": "SR:S5:tweet:x-com", "hub": "SR:S5:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Humans in AI Week 🌍 The largest coordinated conversation about AI ever organized. June 1–8. 200+ cities. 50+ countries. One week. One question: where are we going with AI, and who gets a say?", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-03-24", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S5.001", "cluster": "S5", "_hub": "SR:S5:tweet:x-com", "hub": "SR:S5:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Reading about it online mostly creates anxiety. Being in a room with other thoughtful people actually helps you process what is happening, build language for it, and decide where you have agency.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-28", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S5.007", "cluster": "S5", "_hub": "SR:S5:tweet:x-com", "hub": "SR:S5:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "What if the audience wasn't passive - but part of the conversation? That's Collective Intelligence.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2026-02-02", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S5.029", "cluster": "S5", "_hub": "SR:S5:tweet:x-com", "hub": "SR:S5:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "A glimpse of how community, capital, and collaboration can come together to accelerate innovation in new ways... a radical shift in how the innovation economy operates. AI-native, community-first, and radically aligned – one where opportunity and ownership are shared more broadly across the people driving progress.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-11-10", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Community-powered innovation is a new model: community + capital + collaboration accelerate innovation in ways institutions can't", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S5.030", "cluster": "S5", "_hub": "SR:S5:tweet:x-com", "hub": "SR:S5:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "San Francisco's unique bubble fuels audacity. The sheer density of events and ideas sparks transformative breakthroughs, though it comes with challenges of insularity.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-01-02", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "San Francisco's density of events and ideas sparks transformative breakthroughs, but insularity is a real cost", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S5.031", "cluster": "S5", "_hub": "SR:S5:tweet:x-com", "hub": "SR:S5:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Every city brings something distinct to the table. Whether it's Boston's biotech focus or Chicago's finance expertise, local cultures shape AI in diverse and meaningful ways.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-01-02", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Every city brings something distinct to AI — Boston's biotech, Chicago's finance expertise; local culture shapes AI", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S5.032", "cluster": "S5", "_hub": "SR:S5:tweet:x-com", "hub": "SR:S5:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "we're all asking the same big questions. From career uncertainty to post-work life, these universal concerns tie us together and remind us that progress is ultimately a human endeavor.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-01-02", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The universal questions about AI (career uncertainty, post-work life) tie all cities together — progress is a human endeavor", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S5.033", "cluster": "S5", "_hub": "SR:S5:tweet:x-com", "hub": "SR:S5:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "This is our most important step yet in turning our community's insights into real global impact.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-08-26", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The AI Collective Institute is the most important step in turning community insights into real global impact", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S5.034", "cluster": "S5", "_hub": "SR:S5:tweet:x-com", "hub": "SR:S5:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The one thing I keep seeing: when you get humans in a room to talk about AI, their thinking actually changes. Every single time. The nuance. The stories behind the opinions. How disagreements get resolved when different viewpoints collide in the same physical space.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-03-24", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "When you get humans in a room to talk about AI, their thinking actually changes every single time — nuance and story emerge that no survey or click-based study can capture", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S5.035", "cluster": "S5", "_hub": "SR:S5:tweet:x-com", "hub": "SR:S5:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "No frontier model company, no matter how well-intentioned, can run these conversations and have them land the same way. These companies have skin in the game and the public knows it … Only a community can! 🤝", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-03-24", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Only a community — not a frontier model company or government — can credibly run nonpartisan conversations about AI because companies have skin in the game and the public knows it", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S5.036", "cluster": "S5", "_hub": "SR:S5:tweet:x-com", "hub": "SR:S5:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The highest calling of the Collective is to help society build the shared context, trust, and participatory muscle to make AI genuinely human-friendly. And we are less than 1% of the way there.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-28", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The highest calling of the Collective is to help society build the shared context, trust, and participatory muscle to make AI genuinely human-friendly", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S5.037", "cluster": "S5", "_hub": "SR:S5:tweet:x-com", "hub": "SR:S5:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I absolutely love how their events are centered around thoughtful probing into pressing topics.", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2023-08-16", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Community events that generate discussion group insights and shared reflection create a form of collective intelligence that individuals cannot access alone", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S5.038", "cluster": "S5", "_hub": "SR:S5:tweet:x-com", "hub": "SR:S5:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "the @GenAICollective team has been working for months – in close partnership with @ProductHunt – to lay the groundwork for what we collectively aspire grows into the world's premiere tech event series!", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2024-11-01", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The long-term ambition is for the GenAI Collective to become the world's premier tech event series — a civic-scale knowledge-creation engine", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S5.039", "cluster": "S5", "_hub": "SR:S5:tweet:x-com", "hub": "SR:S5:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "121 sources. 183 articles. 51 deep-researched repos and papers. Open source, forkable for any domain. Star it to come back later!", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-04-06", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Open-source, domain-forkable research aggregators — 121 sources, 183 articles, 51 deep-researched repos — are how collective intelligence should work", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S5.040", "cluster": "S5", "_hub": "SR:S5:tweet:x-com", "hub": "SR:S5:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "This is just the beginning of our nonprofit journey. Much more is coming.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2025-03-26", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Collective action — not just events — is the core focus; the community's goal is civic/policy impact at scale", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S5.024", "cluster": "S5", "_hub": "SR:S5:podcast:talk-aic-why-video", "hub": "SR:S5:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "Number three is hoisting those battle tested insights, those ideas, those sentiments from pioneers on the frontier... and then harnessing that collective wisdom, giving that to the decision makers around us.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Frontier pioneers have the responsibility to hoist their battle-tested insights and harness collective wisdom for the decision-makers around them", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S5.025", "cluster": "S5", "_hub": "SR:S5:podcast:talk-aic-why-video", "hub": "SR:S5:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "fourth is taking those insights and actually using those to upgrade our institutions and stewarding acting as stewards for the society around us.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The fourth step is using collective frontier insights to actually upgrade institutions and steward society", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S5.026", "cluster": "S5", "_hub": "SR:S5:podcast:talk-roan-weigert", "hub": "SR:S5:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "We have all these incredible events that are rich with frontier insights. The most incredible insights come from back and forth discussion. How do we take some of those insights and turn that into actionable insight that we can give to decision makers around the world? So that includes policy makers, that includes industry leaders and that includes the public at large.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The institute's purpose: take frontier insights from community events and convert them to actionable guidance for decision-makers — policymakers, industry leaders, and the public", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S5.027", "cluster": "S5", "_hub": "SR:S5:podcast:talk-roan-weigert", "hub": "SR:S5:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "We ended up building an entire app, a whole web app that anybody in the audience can use to leave feedback about the product to basically say I'm interested in investing, interested in working for you. All this stuff is meant to make sure that there is two-way value that is coming from each one of these demo nights and we're the only group out there that does this.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "P", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The GenAI/AI Collective's demo night format — 2-minute no-slide demos with app-based bidirectional feedback — was deliberately designed to maximize two-way value for both demoing founders and the audience", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S5.028", "cluster": "S5", "_hub": "SR:S5:podcast:talk-tjstar-keynote", "hub": "SR:S5:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "This kind of knowledge spillover you see in San Francisco is truly special… This is what we're trying to bring is this knowledge spillover to cities all over the world.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "In-person gatherings and knowledge spillover are how communities make sense of accelerating technology", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S19.000", "cluster": "S19", "_hub": "SR:S19:blog:essay-agi-manifesto-promise", "hub": "SR:S19:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "This is not just another ripple in the waves of progress but a spectacularly monumental shift in the fabric of existence itself.", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S19.001", "cluster": "S19", "_hub": "SR:S19:blog:essay-agi-manifesto-promise", "hub": "SR:S19:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "As we look forward, the promise of AGI should serve as a beacon of optimism — guiding us through the complexities and challenges — lighting the path to a future where the fusion of humanity and technology ushers in a new era of enlightenment.", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S19.012", "cluster": "S19", "_hub": "SR:S19:blog:essay-agi-manifesto-promise", "hub": "SR:S19:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "As anyone living in Cerebral Valley will tell you, AI is the new land of opportunity.", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI is the new land of opportunity — the current moment is a gold rush", "highlight": false, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S19.013", "cluster": "S19", "_hub": "SR:S19:blog:essay-agi-manifesto-promise", "hub": "SR:S19:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "That's exactly what the technological singularity is: a faith in a new form of intelligence transforming humanity for the better.", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The technological singularity is a faith in a new form of intelligence transforming humanity for the better", "highlight": false, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S19.014", "cluster": "S19", "_hub": "SR:S19:blog:essay-agi-manifesto-promise", "hub": "SR:S19:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "in an era of ever-increasing narcissism and purposelessness, this belief may just be the digital-age religion that our increasingly secular world is in desperate search of", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The singularity may be the digital-age religion that our increasingly secular world is searching for", "highlight": false, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S19.015", "cluster": "S19", "_hub": "SR:S19:blog:essay-agi-manifesto-promise", "hub": "SR:S19:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "The technological singularity is not a foregone conclusion but a hopeful future that the AI community is faithfully navigating toward.", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The singularity is not a foregone conclusion but a hopeful future the AI community is faithfully navigating toward", "highlight": false, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S19.016", "cluster": "S19", "_hub": "SR:S19:blog:essay-agi-manifesto-promise", "hub": "SR:S19:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "The line between creator and creation is blurring — challenging the very notion of what it means to be human.", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI is transforming humanity's self-understanding — the line between creator and creation is blurring", "highlight": false, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S19.017", "cluster": "S19", "_hub": "SR:S19:blog:essay-agi-manifesto-promise", "hub": "SR:S19:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "The technological singularity promises a new era of unimaginable potential where intelligence accelerates past biological capability, birthing a future where the boundaries between humanity and technology blur — challenging our perception of what it means to be human and even our very understanding of the universe.", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The singularity promises a new era of unimaginable potential where intelligence accelerates past biological capability", "highlight": false, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S19.018", "cluster": "S19", "_hub": "SR:S19:blog:essay-agi-manifesto-promise", "hub": "SR:S19:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "many claim we are living on the precipice of life's most significant evolution in its 3.7-billion-year history", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "This moment may be life's most significant evolution in its 3.7-billion-year history", "highlight": false, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S19.019", "cluster": "S19", "_hub": "SR:S19:blog:essay-agi-manifesto-promise", "hub": "SR:S19:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "This is not merely another mile marker in the inexorable march of technological progress but a unique, singular moment where a 'seed AI' capable of recursive self-improvement ushers in a new era of intelligent, non-biological life.", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The singularity is a unique, singular moment — not a routine milestone — where a seed AI capable of recursive self-improvement ushers in non-biological intelligent life", "highlight": false, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S19.020", "cluster": "S19", "_hub": "SR:S19:blog:essay-agi-manifesto-promise", "hub": "SR:S19:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "From a philosophical standpoint, this movement along with its siblings, Transhumanism, Extropianism, and Dataism, draw surprising parallels to traditional religion.", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Singularitarianism and its siblings (Transhumanism, Extropianism, Dataism) draw surprising parallels to traditional religion — both provide shared values, cosmic significance, and faith in a superhuman order", "highlight": false, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S19.021", "cluster": "S19", "_hub": "SR:S19:blog:essay-agi-manifesto-promise", "hub": "SR:S19:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "the technological singularity can be perceived as a form of religious doctrine: a quasi-spiritual event bringing with it universal eternal life and god-like power through technological means.", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The singularity can be perceived as a form of religious doctrine — a quasi-spiritual event bringing universal eternal life and god-like power through technological means", "highlight": false, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S19.022", "cluster": "S19", "_hub": "SR:S19:blog:essay-agi-manifesto-promise", "hub": "SR:S19:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "these two viewpoints are not mutually exclusive; the singularity can be both a religious and scientific concept simultaneously.", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The singularity is both a religious and scientific concept simultaneously — these two viewpoints are not mutually exclusive", "highlight": false, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S19.023", "cluster": "S19", "_hub": "SR:S19:blog:essay-agi-manifesto-promise", "hub": "SR:S19:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "Our depiction of progress in AI up until now has been entirely positive and permeated with a sense of techno-utopian optimism.", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "His own depiction of AI progress is explicitly positive and permeated with techno-utopian optimism — a deliberate self-characterization of his stance", "highlight": false, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S19.003", "cluster": "S19", "_hub": "SR:S19:blog:notion-manifesto-whitepapers", "hub": "SR:S19:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "For 4.2 billion years, there has been a trend towards decreasing entropy: ever greater order, complexity, knowledge, and intelligence.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S19.004", "cluster": "S19", "_hub": "SR:S19:blog:notion-manifesto-whitepapers", "hub": "SR:S19:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Assigning my own probabilities, I don't think we are close to an asymptote and that ⁍ is zero. I prefer to be optimistic, recognizing and accepting my irrationality. I think life is happier and better lived this way.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S19.041", "cluster": "S19", "_hub": "SR:S19:blog:notion-manifesto-whitepapers", "hub": "SR:S19:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Humanity's final task and grand crescendo is thus creating an intelligence greater than ourselves. This is AGI.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AGI is humanity's final grand crescendo — the inevitable transition from biological to silicon-based intelligence", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S19.042", "cluster": "S19", "_hub": "SR:S19:blog:notion-manifesto-whitepapers", "hub": "SR:S19:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "AGI could be achieved in anywhere between 1 and 50 years (95% confidence interval), with a median of 2029 according to world experts.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AGI timeline: 1–50 years with a median of ~2029 per world experts", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S19.043", "cluster": "S19", "_hub": "SR:S19:blog:notion-manifesto-whitepapers", "hub": "SR:S19:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "How can you align your current modus operandi with these assumed futures? Broadly, it is by living at the edge of this progress and either contributing to this progress yourself or putting yourself in the same room with the people who are.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The right posture for the AGI transition is living at the edge of progress and contributing to it — or putting oneself in the same room as those who do", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S19.044", "cluster": "S19", "_hub": "SR:S19:blog:notion-manifesto-whitepapers", "hub": "SR:S19:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Effective accelerationism: life emerged as a principle of second law of thermodynamics as life seeks to capture 'free energy'. Thus, ever greater order, complexity, knowledge, and intelligence is universally inevitable. Better to accelerate towards our destiny.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The e/acc view — that life seeks to capture free energy and ever-greater complexity is universally inevitable — is one he takes seriously as his main Bayesian prior", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S19.007", "cluster": "S19", "_hub": "SR:S19:blog:essay-americas-ai-ultimatum", "hub": "SR:S19:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "calls for a moratorium are misguided. Instead, generative AI efforts must accelerate development to fix premature versions of models that are already widely available.", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S19.024", "cluster": "S19", "_hub": "SR:S19:blog:essay-americas-ai-ultimatum", "hub": "SR:S19:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "vehement opposition is often a sign that a paradigmatic shift is underway", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "Strong opposition to a technology is often the signal that a paradigmatic shift is underway", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S19.025", "cluster": "S19", "_hub": "SR:S19:blog:essay-americas-ai-ultimatum", "hub": "SR:S19:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "Sometimes little happens in a decade. Sometimes a decade happens in a month.", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "Sometimes a decade's worth of change happens in a single month — AI is that moment", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S19.026", "cluster": "S19", "_hub": "SR:S19:blog:essay-americas-ai-ultimatum", "hub": "SR:S19:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "ChatGPT reached one million users in five days, fifteen times faster than any prior app", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "ChatGPT's viral adoption — a million users in five days, fifteen times faster than any prior app — signals a paradigm shift, not a fad", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S19.027", "cluster": "S19", "_hub": "SR:S19:blog:essay-americas-ai-ultimatum", "hub": "SR:S19:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "The open letter from the Future of Life Institute may be better understood as a call to arms rather than a cease fire.", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "The Future of Life open letter is better read as a call to arms — a spur to serious AI policy — than a genuine cease-fire", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S19.028", "cluster": "S19", "_hub": "SR:S19:blog:essay-americas-ai-ultimatum", "hub": "SR:S19:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "Our ultimate national interest is to accelerate AI progress so that we may forge ahead rather than fall behind.", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "The ultimate national interest is to accelerate AI progress so America forges ahead rather than falls behind", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S19.006", "cluster": "S19", "_hub": "SR:S19:blog:booknotes-ai-futures", "hub": "SR:S19:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "AGI and Life 3.0 is coming", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S19.008", "cluster": "S19", "_hub": "SR:S19:blog:booknotes-ai-futures", "hub": "SR:S19:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Prepare for the singularity. Be obsessively future-proof", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The right posture toward the singularity is proactive preparation — be obsessively future-proof", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S19.009", "cluster": "S19", "_hub": "SR:S19:blog:booknotes-ai-futures", "hub": "SR:S19:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Technological progress is a double-edged sword, at once posing unbound potential for wealth and prosperity as well as an existential risk if not aligned with humanity's values and goals", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Technological progress is a double-edged sword: unbound potential for wealth and an existential risk if not aligned with humanity's values", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S19.010", "cluster": "S19", "_hub": "SR:S19:blog:booknotes-ai-futures", "hub": "SR:S19:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Almost everybody maintains a linear view of progress, misinterpreting forward trends", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Almost everybody maintains a linear view of progress and therefore misinterprets forward trends — a key epistemic error", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S19.011", "cluster": "S19", "_hub": "SR:S19:blog:booknotes-ai-futures", "hub": "SR:S19:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "overestimate what we can do in the short term, underestimate the long term", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The linear view causes consistent overestimation of short-term impact and underestimation of long-term impact", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S19.002", "cluster": "S19", "_hub": "SR:S19:blog:essay-gai-collective-curiosity", "hub": "SR:S19:blog:essay-gai-collective-curiosity", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-gai-collective-curiosity", "url": "", "text": "I was obsessed. Whenever someone was kind enough to lend me an ear, I would inevitably talk it right off with musings of this transformational technology and its profound implications on our future.' (notion-rec-essay-gai-collective-curiosity)", "paraphrase": "", "source_id": "essay-gai-collective-curiosity", "date": "2023-04-12", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-gai-collective-curiosity", "private": false}, {"id": "S19.030", "cluster": "S19", "_hub": "SR:S19:blog:essay-gai-collective-curiosity", "hub": "SR:S19:blog:essay-gai-collective-curiosity", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-gai-collective-curiosity", "url": "", "text": "I distinctly remember the spark of awe and curiosity that struck me when GPT-3 was announced in May of 2020.' (notion-rec-essay-gai-collective-curiosity)", "paraphrase": "", "source_id": "essay-gai-collective-curiosity", "date": "2023-04-12", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "GPT-3 (2020) was a significant step toward AGI and a watershed shift in AI perception", "highlight": false, "also_supports": [], "corpus_ref": "essay-gai-collective-curiosity", "private": false}, {"id": "S19.031", "cluster": "S19", "_hub": "SR:S19:blog:essay-gai-collective-curiosity", "hub": "SR:S19:blog:essay-gai-collective-curiosity", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-gai-collective-curiosity", "url": "", "text": "GPT-3 was a significant step towards AGI and the beginning of an important shift in the perception of the capabilities of AI.' (notion-rec-essay-gai-collective-curiosity)", "paraphrase": "", "source_id": "essay-gai-collective-curiosity", "date": "2023-04-12", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "GPT-3 represented the beginning of an important shift in the perception of AI capabilities and a meaningful step toward AGI", "highlight": false, "also_supports": [], "corpus_ref": "essay-gai-collective-curiosity", "private": false}, {"id": "S19.032", "cluster": "S19", "_hub": "SR:S19:blog:essay-gai-collective-curiosity", "hub": "SR:S19:blog:essay-gai-collective-curiosity", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-gai-collective-curiosity", "url": "", "text": "Generative AI's 'Netscape moment' was the public release of ChatGPT in November of 2022.' (notion-rec-essay-gai-collective-curiosity)", "paraphrase": "", "source_id": "essay-gai-collective-curiosity", "date": "2023-04-12", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "ChatGPT's public release in November 2022 was generative AI's \"Netscape moment\" — the mainstream inflection point", "highlight": false, "also_supports": [], "corpus_ref": "essay-gai-collective-curiosity", "private": false}, {"id": "S19.037", "cluster": "S19", "_hub": "SR:S19:blog:essay-trust-manifesto", "hub": "SR:S19:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "We believe in a future defined by radical progress and human flourishing – a world where AI helps us cure disease, eliminate poverty, and extend lifespans well beyond today's limits. Where mental illness becomes treatable, education becomes tailored to every mind, and scientific discovery accelerates tenfold.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He believes in a future of radical progress and human flourishing — AI helps cure disease, eliminate poverty, extend lifespans, treat mental illness, and accelerate scientific discovery", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S19.038", "cluster": "S19", "_hub": "SR:S19:blog:essay-trust-manifesto", "hub": "SR:S19:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "This is not a fantasy. It is a direction. And it is within our power to realize it – if we build what's missing.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The future of abundance is not a fantasy — it's a direction within reach, but only if the missing infrastructure is built", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S19.039", "cluster": "S19", "_hub": "SR:S19:blog:essay-trust-manifesto", "hub": "SR:S19:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "This is the future of abundance. A world where intelligence is no longer scarce. Where tools amplify the best of human potential. Where prosperity expands, opportunity multiplies, and the systems that guide us grow stronger – not weaker – with each leap forward.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "A world where intelligence is no longer scarce — prosperity expands, opportunity multiplies, and guiding systems grow stronger with each leap forward", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S19.040", "cluster": "S19", "_hub": "SR:S19:blog:essay-trust-manifesto", "hub": "SR:S19:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "I vividly remember when GPT-3 launched in May 2020. For years, books like Life 3.0 and The Singularity Is Near had painted visions of a future reshaped by AI – but for the first time, that future no longer felt theoretical. It was tangible. Immediate. Personal. The leap from GPT-2 was staggering. The timeline had collapsed.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "GPT-3 in May 2020 was the moment the AI future stopped feeling theoretical and became tangible and immediate; the timeline had collapsed", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S19.033", "cluster": "S19", "_hub": "SR:S19:blog:essay-personal-site", "hub": "SR:S19:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "AGI is probably the most significant advancement in the history of the universe", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AGI is the most significant advancement in the history of the universe", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S19.034", "cluster": "S19", "_hub": "SR:S19:blog:essay-personal-site", "hub": "SR:S19:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "AI itself is both the threat and the tool we need to solve it", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI is simultaneously the threat and the tool needed to solve the problems it creates", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S19.035", "cluster": "S19", "_hub": "SR:S19:blog:essay-personal-site", "hub": "SR:S19:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "My senior year of college, I wrote my final paper on the technological singularity – right when GPT-3 had just dropped. That research rewired my brain.", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Writing his college thesis on the technological singularity (at GPT-3 moment) rewired his brain and set his life direction", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S19.029", "cluster": "S19", "_hub": "SR:S19:blog:essay-chatgpt-ios-app", "hub": "SR:S19:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "Who knows — generative AI might just be the last mind bicycle that man need ever make. (hint: AGI 😉)", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Generative AI might just be the last mind bicycle that man need ever make — a hint toward AGI", "highlight": false, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S19.036", "cluster": "S19", "_hub": "SR:S19:blog:essay-self-improving-ai-stack", "hub": "SR:S19:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "I believe the next trillion-dollar company will be built on this stack.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He believes the next trillion-dollar company will be built on the self-improving agent stack — it is the foundational architecture of the coming era", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S19.045", "cluster": "S19", "_hub": "SR:S19:podcast:talk-aic-why-video", "hub": "SR:S19:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "I I do believe that we're what we're creating is a super intelligence which has so much capacity to do great and when I read this and really internalized it for me this was something that I decided I want to dedicate my life to to being part of this creation of super intelligence however I could.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "He is building his life around creating superintelligence after being struck by the implication that it is the last invention humanity ever needs", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S19.046", "cluster": "S19", "_hub": "SR:S19:podcast:talk-aic-why-video", "hub": "SR:S19:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "So I headed to what the frontier of human progress was and that is the development of AI.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "AI is the frontier of human progress and the destination he deliberately headed toward", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S19.047", "cluster": "S19", "_hub": "SR:S19:podcast:talk-aic-why-video", "hub": "SR:S19:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "We've moved from that dumb human to Einstein in a matter of months, right? It's really crazy.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "AI models have gone from below-average-human IQ to near-Einstein-level IQ within a single year — the gap is closing faster than people perceive", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S19.048", "cluster": "S19", "_hub": "SR:S19:podcast:talk-aic-why-video", "hub": "SR:S19:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "I I genuinely believe this is going to bring so much good to the world and we are fortunate enough the people here at this event, the people in this community around the world are fortunate enough to be those pioneers on the frontier.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "He genuinely believes AI will bring great good to the world and that those in the AIC community are fortunate pioneers on the frontier", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S19.052", "cluster": "S19", "_hub": "SR:S19:podcast:talk-tjstar-keynote", "hub": "SR:S19:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "The first ultra intelligent machine is the last invention that man need.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "AGI / superintelligence is mankind's final invention — a singular turning point that changes everything", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S19.053", "cluster": "S19", "_hub": "SR:S19:podcast:talk-tjstar-keynote", "hub": "SR:S19:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "the deeper I went into it, the more I realized that this is going to change absolutely everything. The first decade of my career that I'd spent all building all these technical skills wasn't going to be relevant in the next decade.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The first decade of technical skills he built won't be relevant in the next decade — AI changes everything", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S19.054", "cluster": "S19", "_hub": "SR:S19:podcast:talk-tjstar-keynote", "hub": "SR:S19:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "if you were to go forward to the year 2100 and you were to ask somebody to summarize this entire century in a single sentence, I'll bet you it would be this… It's AI.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "AI will summarize the entire 21st century — it is the defining force of our era", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S19.055", "cluster": "S19", "_hub": "SR:S19:podcast:talk-tjstar-keynote", "hub": "SR:S19:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "I decided that I wanted to dedicate my entire career to this uh to solving mankind's final challenge.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "He dedicated his career to solving mankind's final challenge after reading about superintelligence", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S19.049", "cluster": "S19", "_hub": "SR:S19:podcast:talk-roan-weigert", "hub": "SR:S19:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "I am a firm believer in AGI, artificial general intelligence, us creating super intelligent AI systems that are smarter than we are, smarter than humans are, right? And I really view this as mankind's final challenge. It's our final challenge to create intelligence greater than ourselves because once we create intelligence greater than ourselves, it does all the rest for us.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "AGI is mankind's final challenge — once achieved it solves everything downstream", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S19.050", "cluster": "S19", "_hub": "SR:S19:podcast:talk-roan-weigert", "hub": "SR:S19:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "This technology from GPT1 to 2 to 3 is advancing so rapidly. We're seeing some sort of exponential growth here. And if this continues, the whole world is going to change in just incomprehensible ways in the next few years.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The exponential trajectory from GPT-1→2→3 convinced him the whole world will change incomprehensibly in years", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S19.051", "cluster": "S19", "_hub": "SR:S19:podcast:talk-roan-weigert", "hub": "SR:S19:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "I decided that I wanted to get as close to the cutting edge of technology as I could and stay there.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "His response to AGI inevitability: get as close to the cutting edge as possible and stay there", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S19.056", "cluster": "S19", "_hub": "SR:S19:podcast:talk-venture-with-grace", "hub": "SR:S19:podcast:talk-venture-with-grace", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-venture-with-grace", "url": "", "text": "this is the height the the most energy that there's ever been in San Francisco right now, even more than the internet boom. And you could feel it. We could all feel it. We knew that this was something momentous. This was a paradigm shift. We were in the middle of a paradigm shift.", "paraphrase": "", "source_id": "talk-venture-with-grace", "date": "2025-12-05", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "ChatGPT's emergence in late 2022 felt like an undeniable paradigm shift — history-level energy", "highlight": false, "also_supports": [], "corpus_ref": "talk-venture-with-grace", "private": false}, {"id": "S19.005", "cluster": "S19", "_hub": "SR:S19:tweet:x-com", "hub": "SR:S19:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I am obsessed with technological progress. As my friends know all too well, I love to go on meandering multi-hour monologues on the accelerating rate of technological change, the development of AGI, the future of humanity, our universal significance, and its implications on the present day.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2023-11-04", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S19.057", "cluster": "S19", "_hub": "SR:S19:tweet:x-com", "hub": "SR:S19:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "AGI is coming faster than we think, and community is how we navigate it.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-07-09", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AGI is coming faster than most people think", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S19.058", "cluster": "S19", "_hub": "SR:S19:tweet:x-com", "hub": "SR:S19:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The market says there's a 10% chance @OpenAI announces AGI this year. Is that too high? Too low? Today we're finding out.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2026-01-15", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The market's ~10% probability of OpenAI announcing AGI in 2026 deserves serious public debate, not dismissal", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S19.059", "cluster": "S19", "_hub": "SR:S19:tweet:x-com", "hub": "SR:S19:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Our 'Let's Talk AGI' meetup was the perfect time to conduct a straw poll on people's AGI timelines + P(doom)!", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2024-02-11", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AGI timelines and P(doom) are the most important discussion questions for the tech community to grapple with publicly", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S19.060", "cluster": "S19", "_hub": "SR:S19:tweet:x-com", "hub": "SR:S19:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Clearly, we've got A LOT of techno optimists and e/accs. I love it!", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2024-02-11", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He celebrates and identifies with the techno-optimist and e/acc crowd within the AI community", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S19.061", "cluster": "S19", "_hub": "SR:S19:tweet:x-com", "hub": "SR:S19:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Come join us as we discuss all of our FAVORITE topics: AGI, futurism, and technological progress!", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2024-01-25", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AGI, futurism, and technological progress are his favorite discussion topics — a defining intellectual passion", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S19.062", "cluster": "S19", "_hub": "SR:S19:tweet:x-com", "hub": "SR:S19:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "What will humans always be better at than AI? What fundamentally gives us, as individuals, meaning and purpose?", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2023-09-29", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The question of what humans will always be better at than AI — and what gives us meaning and purpose — is one of the most pressing questions on the path to AGI", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S19.063", "cluster": "S19", "_hub": "SR:S19:tweet:x-com", "hub": "SR:S19:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Sounds like we are on the verge of a new material revolution!", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2023-07-29", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The LK-99 / room-temperature superconductor developments represented a potential material revolution — the kind of frontier science that commands his attention", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S19.064", "cluster": "S19", "_hub": "SR:S19:tweet:x-com", "hub": "SR:S19:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "AGI is coming faster than we think, and community is how we navigate it.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2025-07-09", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AGI is coming faster than most people think; community is how we navigate it", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S18.008", "cluster": "S18", "_hub": "SR:S18:blog:booknotes-ai-futures", "hub": "SR:S18:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Is intelligence substrate independent?", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Intelligence is substrate-independent — not inherently a biological trait", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S18.009", "cluster": "S18", "_hub": "SR:S18:blog:booknotes-ai-futures", "hub": "SR:S18:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Consciousness is likely substrate-independent, can probably be proven", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Consciousness is likely substrate-independent and can probably be proven", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S18.010", "cluster": "S18", "_hub": "SR:S18:blog:booknotes-ai-futures", "hub": "SR:S18:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Therefore, first goal of universe should be to increase consciousness", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The first goal of the universe should be to increase consciousness — Chappy's own extension from Dyson", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S18.011", "cluster": "S18", "_hub": "SR:S18:blog:booknotes-ai-futures", "hub": "SR:S18:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Mindful optimism", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The right epilogue stance on Life 3.0 is mindful optimism", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S18.012", "cluster": "S18", "_hub": "SR:S18:blog:booknotes-ai-futures", "hub": "SR:S18:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Humanity's big problems aren't knowledge problems — they're wisdom problems rooted in our failure to think well together", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Our problems are wisdom failures, not knowledge failures — the defining framing for societal dysfunction", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S18.013", "cluster": "S18", "_hub": "SR:S18:blog:booknotes-ai-futures", "hub": "SR:S18:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Test idea by challenging, debating it", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Testing ideas by challenging and debating them is the right epistemic method", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S18.014", "cluster": "S18", "_hub": "SR:S18:blog:booknotes-ai-futures", "hub": "SR:S18:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Humans prefer blanket, attribution over nuance and gray zones (the world is more complex than we think)", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Humans prefer blanket attribution over nuance and gray zones; the world is more complex than we think", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S18.015", "cluster": "S18", "_hub": "SR:S18:blog:booknotes-ai-futures", "hub": "SR:S18:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "The gap between what we know and how we act is the defining challenge of our era", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The gap between what we know and how we act is the defining challenge of our era", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S18.016", "cluster": "S18", "_hub": "SR:S18:blog:booknotes-ai-futures", "hub": "SR:S18:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Institutions designed for truth-seeking have been captured by tribal dynamics", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Institutions designed for truth-seeking have been captured by tribal dynamics", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S18.017", "cluster": "S18", "_hub": "SR:S18:blog:booknotes-ai-futures", "hub": "SR:S18:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Pluralistic ignorance: when no one believes, but everything thinks that everyone believes / ↑ Fix: free speech (first amendment) / Truth usually prevails", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Pluralistic ignorance is fixed by free speech — truth usually prevails", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S18.018", "cluster": "S18", "_hub": "SR:S18:blog:booknotes-ai-futures", "hub": "SR:S18:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Price performance more than exponential growth (3 → 2 → 1 year doubling)", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Accelerating returns are real: price-performance is more than exponential, with paradigm shifts stacking as S-curves", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S18.019", "cluster": "S18", "_hub": "SR:S18:blog:booknotes-ai-futures", "hub": "SR:S18:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Acceleration of acceleration: multiple accelerating factors compounding", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Law of accelerating returns: multiple accelerating factors compound — acceleration of acceleration", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S18.020", "cluster": "S18", "_hub": "SR:S18:blog:booknotes-ai-futures", "hub": "SR:S18:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Teleology: explaining in terms of purpose / Universe becoming more teleological", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The universe becoming more teleological — purpose-driven — is the trajectory of physics and life", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S18.031", "cluster": "S18", "_hub": "SR:S18:blog:essay-top-10-reads-2024", "hub": "SR:S18:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "In a world addicted to the junk food of TikTok takes and bite-sized opinions, books stand apart as thoughtful distillations of humanity's collective wisdom. They help us sharpen our perspectives, make sense of complexity, and uncover enduring value in a chaotic sea of fleeting distractions.", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Books are superior to short-form media for building calibrated understanding; voracious reading (70+ books/year) is his epistemic practice", "highlight": false, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S18.032", "cluster": "S18", "_hub": "SR:S18:blog:essay-top-10-reads-2024", "hub": "SR:S18:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "these ten have stood out to me as uniquely thought-provoking — not because they aligned with my views, but because they challenged me to rethink them", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He selects books specifically to challenge his existing views, not confirm them", "highlight": false, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S18.033", "cluster": "S18", "_hub": "SR:S18:blog:essay-top-10-reads-2024", "hub": "SR:S18:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "I came away with a heightened awareness of how fragile democratic systems can be in a landscape dominated by algorithms and unchecked data collection; genuine truth-seeking requires both transparency and diverse participation.", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Democratic systems are fragile under algorithmic information environments; truth-seeking requires transparency and diverse participation", "highlight": false, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S18.034", "cluster": "S18", "_hub": "SR:S18:blog:essay-top-10-reads-2024", "hub": "SR:S18:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "analytical thinking and continuous feedback loops can cut through biases and improve our collective decision-making", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Analytical thinking and probability-based feedback loops cut through cognitive bias", "highlight": false, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S18.035", "cluster": "S18", "_hub": "SR:S18:blog:essay-top-10-reads-2024", "hub": "SR:S18:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "I learned the value of staying open to being proven wrong — it's a humbling experience that can spark significant personal and professional breakthroughs.", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Staying open to being proven wrong is a humbling practice that drives personal and professional breakthroughs", "highlight": false, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S18.036", "cluster": "S18", "_hub": "SR:S18:blog:essay-top-10-reads-2024", "hub": "SR:S18:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "I've found that actively seeking conversations with those who disagree helps me clarify my own reasoning.", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He actively seeks conversations with those who disagree to sharpen his own reasoning", "highlight": false, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S18.037", "cluster": "S18", "_hub": "SR:S18:blog:essay-top-10-reads-2024", "hub": "SR:S18:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "This book came as a recommendation from ChatGPT when I asked for something to challenge my strongly held belief that extroversion is superior.", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He uses AI (ChatGPT) to deliberately surface books that challenge his priors — a calibration practice", "highlight": false, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S18.038", "cluster": "S18", "_hub": "SR:S18:blog:notion-manifesto-whitepapers", "hub": "SR:S18:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Below are nine outcomes for the development of AGI. You can assign probabilities to each in order to assess the future of life with further granularity.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Calibrated probabilistic reasoning about AGI futures beats vibes — he lays out nine outcome scenarios and invites explicit probability assignment", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S18.039", "cluster": "S18", "_hub": "SR:S18:blog:notion-manifesto-whitepapers", "hub": "SR:S18:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Bayes' Theorem. Based on trends in life's evolution and recent exponential trends in technological progress, continued increase seems inevitable. This is my main prior.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Bayes' Theorem applied to evolutionary and technological trends makes continued intelligence growth seem inevitable — this is his main prior", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S18.040", "cluster": "S18", "_hub": "SR:S18:blog:notion-manifesto-whitepapers", "hub": "SR:S18:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Wisdom, as the meta-value, gives one the capacity to zoom out from the ecology of available values, including agency, and choose the appropriate one to meet the moment.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Wisdom is the meta-value that adjudicates between all other values — including agency", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S18.041", "cluster": "S18", "_hub": "SR:S18:blog:notion-manifesto-whitepapers", "hub": "SR:S18:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Wise agency: Taking the right action toward getting the right things done, despite complex (and clear, complicated, chaotic, or confused) constraints.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Wise agency = taking the right action toward getting the right things done, despite complex constraints — distinct from raw high agency", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S18.042", "cluster": "S18", "_hub": "SR:S18:blog:notion-manifesto-whitepapers", "hub": "SR:S18:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "perspective-taking is necessary for wisdom… This can be dangerous to agency maximizers, as it risks disrupting the clarity that a singular objective provides.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Perspective-taking (perspectival meta-cognition) is necessary for wisdom — but can be dangerous to agency maximizers by disrupting the clarity of a singular objective", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S18.043", "cluster": "S18", "_hub": "SR:S18:blog:notion-manifesto-whitepapers", "hub": "SR:S18:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "More fragmented than left or right 'memetic tribes'… Six phenomena are involved in their genesis: (globalization, digitalization)… Bipolar → multipolar culture wars", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Memetic tribes are more fragmented than left/right — six genesis phenomena (secularization, fragmentation, atomization, globalization, stimulation, weaponization) drove a multipolar culture war", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S18.024", "cluster": "S18", "_hub": "SR:S18:blog:essay-agi-manifesto-promise", "hub": "SR:S18:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "In a quest to demystify the exciting world of artificial general intelligence (AGI), this four-part manifesto answers this question among many others. It is a concise yet comprehensive map, generously dotted with links and footnotes inviting deeper self-exploration (this first part alone has over a hundred). In this journey, I am as much an explorer as you are. Consider this not as the final word, but as the sowing of seeds for much-needed dialogue and debate on AGI and our shared future.", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Deep, calibrated engagement with AGI requires a concise yet comprehensive map with rigorous sourcing — not final answers but seeds for dialogue", "highlight": false, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S18.025", "cluster": "S18", "_hub": "SR:S18:blog:essay-agi-manifesto-promise", "hub": "SR:S18:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "underlying the incredible surge in complexity and capability of AI models in recent years is a simple yet powerful concept: the accelerating rate of technological change.", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Technological progress is demonstrably accelerating — exponential curves in compute, data, and adoption rates all converge toward AGI", "highlight": false, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S18.026", "cluster": "S18", "_hub": "SR:S18:blog:essay-agi-manifesto-promise", "hub": "SR:S18:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "Neural scaling laws suppose that factors such as computational power, parameter count, and dataset size all correlate with model performance and thus intelligence. […] Thus, AI seems poised to ride on the coattails of compounding exponential curves.", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Neural scaling laws — compute, parameters, and data correlate with intelligence — suggest AI will ride compounding exponential curves", "highlight": false, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S18.027", "cluster": "S18", "_hub": "SR:S18:blog:essay-agi-manifesto-promise", "hub": "SR:S18:blog:essay-agi-manifesto-promise", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-agi-manifesto-promise", "url": "", "text": "Personally, I subscribe to Vernor Vinge's original analogy — the technological singularity has an event horizon by which all subsequent events are unforeseeable.", "paraphrase": "", "source_id": "essay-agi-manifesto-promise", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Personally subscribes to Vernor Vinge's singularity event-horizon framing — events after the singularity are genuinely unforeseeable", "highlight": false, "also_supports": [], "corpus_ref": "essay-agi-manifesto-promise", "private": false}, {"id": "S18.021", "cluster": "S18", "_hub": "SR:S18:blog:booknotes-community", "hub": "SR:S18:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Skills: 3 crucial new skills: Learning: instructing how to learn, unlearn, and re-learn / Relating: / Choosing: help people define and test their values", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "A rigorous future-facing education must teach learning/unlearning/relearning, relating, and choosing how to define and test one's values — not fixed knowledge", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S18.022", "cluster": "S18", "_hub": "SR:S18:blog:booknotes-community", "hub": "SR:S18:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Create education that builds curiosity rather than fixed knowledge", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Education must create curiosity and adaptive skills, not just transmit fixed knowledge — current industrial schools are built for a world that no longer exists", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S18.023", "cluster": "S18", "_hub": "SR:S18:blog:booknotes-community", "hub": "SR:S18:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Need to design 'personal and social change regulators' / New institutional, organizational forms / Must experiment widely", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Personal and social change regulators — deliberate structures that pace adaptation — are the survival strategy for an accelerating world", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S18.028", "cluster": "S18", "_hub": "SR:S18:blog:essay-personal-site", "hub": "SR:S18:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "I also read 50-100 books a year", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Voracious reading (50-100 books/year) as a core practice", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S18.029", "cluster": "S18", "_hub": "SR:S18:blog:essay-personal-site", "hub": "SR:S18:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "I am a bibliomaniac. I read 50-100 books a year, and much of my personal and professional philosophy is a synthesis of frameworks from thinkers I deeply respect. If you want to understand the 'why' behind how I operate, these books are the source material!", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Personal and professional philosophy is a synthesis of frameworks from thinkers he deeply respects — books are the source material for how he operates", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S18.004", "cluster": "S18", "_hub": "SR:S18:blog:essay-human-side-of-ai", "hub": "SR:S18:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "Technology, as Jeff Jarvis explores in The Gutenberg Parenthesis, evolves non-deterministically, shaped by our collective choices. That unpredictability grants us agency! In the end, we're not passive participants but active authors of the story we're telling together.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S18.030", "cluster": "S18", "_hub": "SR:S18:blog:essay-self-improving-ai-stack", "hub": "SR:S18:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "I curated 121 sources (63 repos, 13 papers, 24 tweets, 21 articles), deep-researched 51 of them by reading source code and documentation.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He spent a month building a self-compiling knowledge base from 121 sources — reading source code and documentation, not just abstracts — as his method for forming views", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S18.000", "cluster": "S18", "_hub": "SR:S18:tweet:x-com", "hub": "SR:S18:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "When in 2026 will the AI bubble pop? 🤔 Next month, I'm moderating a forecasting panel with @AICollectiveCo x @Kalshi x @roam where we'll put real probabilities (not vibes) on the biggest AI outcomes of 2026 – using the top Kalshi prediction markets. We'll debate + bet on: 🏆 Who's #1 on the LMSYS leaderboard next December? … 🦢 The 'black swan' no one's pricing yet", "paraphrase": "", "source_id": "tweets-rescues-2026-06-11", "date": "2025-12-16", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-rescues-2026-06-11", "private": false}, {"id": "S18.001", "cluster": "S18", "_hub": "SR:S18:tweet:x-com", "hub": "SR:S18:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I'm hosting 2026 AI Predictions with @AICollectiveCo, @Kalshi, and @roam – where we're forcing real bets on what actually happens this year!", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2026-01-15", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S18.002", "cluster": "S18", "_hub": "SR:S18:tweet:x-com", "hub": "SR:S18:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "No vague predictions. Just over or under.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-01-15", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S18.003", "cluster": "S18", "_hub": "SR:S18:tweet:x-com", "hub": "SR:S18:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Funny how the 'just use files' crowd was right all along and it took Karpathy saying it for everyone to listen", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-04-06", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S18.051", "cluster": "S18", "_hub": "SR:S18:tweet:x-com", "hub": "SR:S18:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I like to think of books as 'the distilled wisdom of history's greatest minds' and firmly believe that it's the single best use of one's idle time!", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2024-09-16", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Books are \"the distilled wisdom of history's greatest minds\" and the single best use of idle time", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S18.052", "cluster": "S18", "_hub": "SR:S18:tweet:x-com", "hub": "SR:S18:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "this was legitimately BY FAR my favorite panel event ever. I can't wait to turn this into a regular series!", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2026-01-16", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Forecasting panels on prediction markets are \"BY FAR my favorite panel event ever\" — calibrated thinking is intrinsically rewarding", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S18.053", "cluster": "S18", "_hub": "SR:S18:tweet:x-com", "hub": "SR:S18:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I'd rather be respected for useful honesty than liked for easy silence – the art is making honesty feel like support", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-08-26", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Honest feedback is better than comfortable silence — the art is making honesty feel like support", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S18.054", "cluster": "S18", "_hub": "SR:S18:tweet:x-com", "hub": "SR:S18:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I've read 250+ books over the past five years. This year, I finally built them a proper home! … I've been taking meticulous reading notes for years now, and this site is their new permanent home – searchable, browsable, organized by topic, with summaries and key takeaways for each book.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-02-23", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Voracious reading (250+ books in five years) and meticulous notes are a core epistemic practice; the notes compound into a decision-making asset", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S18.055", "cluster": "S18", "_hub": "SR:S18:tweet:x-com", "hub": "SR:S18:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Definitely an 'encyclopedic quantification of what is currently known about personality–ability relations.' At a glance, however, nothing jumps off the page (screen) as particularly counterintuitive 😕", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2023-07-09", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "A comprehensive personality-intelligence study that quantifies known relations is valuable, but should be assessed honestly — nothing in it is particularly counterintuitive", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S18.056", "cluster": "S18", "_hub": "SR:S18:tweet:x-com", "hub": "SR:S18:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I am attempting to get more into science fiction as a source of creativity and inspiration.", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2023-09-29", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Science fiction is a valuable source of creativity and inspiration for thinking about the AGI future", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S18.057", "cluster": "S18", "_hub": "SR:S18:tweet:x-com", "hub": "SR:S18:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Plot twist: the weird RT/like ratio is actually the point Talked last night with someone who's run hundreds of viral campaigns. Not a clumsy growth hack – it's an adversarial retweet attack: pay for thousands of hard-to-trace RTs, make the post look fraudulent, and poison the conversation. If true, it's working.", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2026-05-20", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "A viral anomaly (weird RT/like ratio) deserves a probabilistic structural explanation before being dismissed as a clumsy growth hack — adversarial retweet attacks are a real information-environment threat", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S18.058", "cluster": "S18", "_hub": "SR:S18:tweet:x-com", "hub": "SR:S18:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Next month, I'm moderating a forecasting showdown…where we'll put real probabilities (not vibes) on the biggest AI outcomes of 2026 – using the top Kalshi prediction markets.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2025-12-22", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Real probabilities, not vibes — AI forecasting should use actual prediction markets with over/under bets", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S18.059", "cluster": "S18", "_hub": "SR:S18:tweet:x-com", "hub": "SR:S18:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "When in 2026 will the AI bubble pop? 🤔 We're stacking the deck. 🔥 @mreflow – one of the most influential voices in AI with 800k+ YouTube subscribers – is officially joining our forecasting panel to debate the biggest AI outcomes of 2026.", "paraphrase": "", "source_id": "tweets-rescues-2026-06-11", "date": "2025-12-22", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Forecasting debates deserve serious staffing: he recruits the most influential voices to bet on the biggest AI outcomes of the year", "highlight": false, "also_supports": [], "corpus_ref": "tweets-rescues-2026-06-11", "private": false}, {"id": "S18.060", "cluster": "S18", "_hub": "SR:S18:tweet:x-com", "hub": "SR:S18:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The six markets we debated: 🏆 Which lab will have the best AI by end of 2026? (Gemini is at 58%...) 📊 Will OpenAI go public this year? 🤖 Will OpenAI announce AGI before 2", "paraphrase": "", "source_id": "tweets-rescues-2026-06-11", "date": "2026-01-16", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Live market odds are the debate substrate: he reads specific Kalshi probabilities (an 11.5% lab-pause chance, Gemini at 58%) and argues against the number", "highlight": false, "also_supports": [], "corpus_ref": "tweets-rescues-2026-06-11", "private": false}, {"id": "S18.061", "cluster": "S18", "_hub": "SR:S18:tweet:x-com", "hub": "SR:S18:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "After publishing https://t.co/x7pFnetFs0 earlier this year and receiving such an overwhelmingly enthusiastic reception from friends, I've decided to recap my year in reading with a fun new list: Top 10 Most Provoking Reads of 2024! 📚", "paraphrase": "", "source_id": "tweets-rescues-2026-06-11", "date": "2024-12-30", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "His year in reading is a published, curated synthesis — a Top 10 Most Provoking Reads list shared as a public epistemic artifact", "highlight": false, "also_supports": [], "corpus_ref": "tweets-rescues-2026-06-11", "private": false}, {"id": "S18.046", "cluster": "S18", "_hub": "SR:S18:podcast:talk-tjstar-keynote", "hub": "SR:S18:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "protect your attention like it's gold.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Attention is a fixed-supply resource and must be protected like gold — information diet quality is everything", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S18.047", "cluster": "S18", "_hub": "SR:S18:podcast:talk-tjstar-keynote", "hub": "SR:S18:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "It's not just putting in any garbage TikTok information, right? It is increasing the quality of the information that you're receiving.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Garbage In, Garbage Out applies to humans — quality of information input determines quality of output", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S18.048", "cluster": "S18", "_hub": "SR:S18:podcast:talk-tjstar-keynote", "hub": "SR:S18:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "Focus more on your circle of influence, what you can actually influence yourself and your circle of control. That focus is going to lead to natural independent thinking.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Focus on your circle of influence, not your circle of concern — leads to natural independent thinking", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S18.049", "cluster": "S18", "_hub": "SR:S18:podcast:talk-tjstar-keynote", "hub": "SR:S18:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "there's a sweet spot for how much you are constraining the information you receive that leads to the most creativity.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "There is a creativity sweet spot — constrain information input to the right level for maximum creativity", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S18.050", "cluster": "S18", "_hub": "SR:S18:podcast:talk-tjstar-keynote", "hub": "SR:S18:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "your life takes its color from the average of your surroundings.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Your life takes its color from the average of your surroundings — conscious curation of context matters", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S18.006", "cluster": "S18", "_hub": "SR:S18:podcast:talk-roan-weigert", "hub": "SR:S18:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "I really like to try and get a grasp of what is the bigger picture. What is the through line here? And I think where you're going to really find that is in books. I've always been a huge advocate for books. I have booknotes for hundreds of books that I've read there. I'm a huge bookworm.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S18.007", "cluster": "S18", "_hub": "SR:S18:podcast:talk-roan-weigert", "hub": "SR:S18:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "The two books that I always recommend to people if they're looking to get into AI, if they're looking to understand the big picture here, these were the books that fundamentally altered my worldview, you know, back in 2020/2021. One is Life 3.0 by Max Tegmark and the other is The Singularity Is Near by Ray Kurzweil. Both of these books were written almost 10 plus years ago, 10 and close to 15, 20 years ago, but they are still spot-on with their predictions about where AI is going and what the next couple of decades are going to look like.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S18.045", "cluster": "S18", "_hub": "SR:S18:podcast:talk-roan-weigert", "hub": "SR:S18:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "If you want to get that big picture of where this is all going, why it's so important, and what I think 99.999% of people are missing out there in the world, that's what's going to put it all together for you.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "99.999% of people are missing the big picture of where AI is going — the books give you what puts it all together", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S18.005", "cluster": "S18", "_hub": "SR:S18:podcast:talk-aic-why-video", "hub": "SR:S18:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "the singularity is near by Ray Kerszwall and by 3.0 know are two books that really changed the way I look at everything and my whole perspective during this research.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S18.044", "cluster": "S18", "_hub": "SR:S18:podcast:talk-aic-why-video", "hub": "SR:S18:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "It's a a 6,000 plus word essay that I've been working on for almost half a decade now at this point.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "He has spent nearly half a decade working on the \"Trust in the Age of Acceleration\" founding perspective — it is a 6,000+ word essay distilling years of synthesis", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S8.007", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-metacrisis", "hub": "SR:S8:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "Metacrisis / polycrisis*", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S8.016", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-metacrisis", "hub": "SR:S8:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "Goliath: a collection of hierarchies in which some dominate others to control energy and labor / Goliath's curse: increasing risk of collapse due to extractive institutions / Rising inequality, poor decision making, counter-dominance intuitions, weak institutions", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Power structures — Goliath — are defined by hierarchies that extract energy and labor; their curse is increasing collapse risk as extractive institutions accumulate", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S8.017", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-metacrisis", "hub": "SR:S8:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "The agents of doom: big tech, the fossil fuel industry, and the military industrial complexes / ↑ in turn driven by larger incentives", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The agents of doom — big tech, fossil fuel industry, military-industrial complex — are driven by structural incentives, not individual malice", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S8.018", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-metacrisis", "hub": "SR:S8:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "AI arms race / ↑ Competitive Goliath traps: / Arms races / Races to the bottom / Status races using conspicuous consumption", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI arms race dynamics and the competitive Goliath trap — arms races, races to the bottom, status races — are active drivers of existential risk", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S8.019", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-metacrisis", "hub": "SR:S8:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "Evolutionary suicide: 'short-term adaptation leads to long-term extinction'", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Humanity is collectively executing evolutionary suicide — short-term adaptation leading to long-term extinction", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S8.020", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-metacrisis", "hub": "SR:S8:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "Totalitarianism is AI's default trajectory without intervention / AI favors data centralization—unlike humans, it works better with everything in one place", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI's structural bias is toward data centralization — making totalitarianism AI's default trajectory without active intervention", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S8.021", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-metacrisis", "hub": "SR:S8:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "Data colonialism: data replaces land as the primary source of extracted value", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Data colonialism is the successor to land colonialism — data is now the primary extracted resource of power", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S8.022", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-metacrisis", "hub": "SR:S8:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "A silicon curtain threatens global cooperation / US and China projected to capture 70% of AI value creation by 2030", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "A silicon curtain between US and China concentrating 70% of AI value creation is a structural threat to global cooperation", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S8.023", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-metacrisis", "hub": "SR:S8:blog:booknotes-metacrisis", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-metacrisis", "url": "", "text": "AI regulation requires unprecedented trust because AI labs are easier to hide than nuclear facilities", "paraphrase": "", "source_id": "booknotes-metacrisis", "date": "2024-07-09", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI regulation requires unprecedented international trust — AI labs are structurally easier to hide than nuclear facilities", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-metacrisis", "private": false}, {"id": "S8.030", "cluster": "S8", "_hub": "SR:S8:blog:notion-manifesto-whitepapers", "hub": "SR:S8:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Meta-crisis: the underlying crisis driving a multitude of crises… Sense-making, capability, legitimacy, meaning crises", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The metacrisis is the underlying crisis generating all others — a failure of sense-making, coordination, meaning, and legitimacy", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S8.031", "cluster": "S8", "_hub": "SR:S8:blog:notion-manifesto-whitepapers", "hub": "SR:S8:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "The Core Triad: paleolithic emotions, medieval institutions, godlike technology.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The core triad driving the metacrisis: paleolithic emotions + medieval institutions + godlike technology", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S8.032", "cluster": "S8", "_hub": "SR:S8:blog:notion-manifesto-whitepapers", "hub": "SR:S8:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Moloch: a 'hyperobject' representing humanity's perennial coordination problem, where systemic incentives lead to collectively harmful consequences despite individuals' rational actions", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Moloch represents humanity's perennial coordination problem — systemic incentives lead to collectively harmful consequences despite individuals' rational actions", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S8.033", "cluster": "S8", "_hub": "SR:S8:blog:notion-manifesto-whitepapers", "hub": "SR:S8:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "The deeper layer: Metacrisis – the failure of our sense‑making and coordination systems. Institutions lag behind the velocity of change; trust collapses; meaning fragments.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The deeper layer beneath polycrisis is a failure of sense-making and coordination systems — institutions lag behind velocity of change; trust collapses; meaning fragments", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S8.034", "cluster": "S8", "_hub": "SR:S8:blog:notion-manifesto-whitepapers", "hub": "SR:S8:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "AI-induced job loss likely flashpoint… In the next 2-5 years… 'Moment of crisis'", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "AI-induced job loss is likely the near-term flashpoint — a moment of crisis arriving in 2–5 years that could detonate accumulated social powder", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S8.035", "cluster": "S8", "_hub": "SR:S8:blog:notion-manifesto-whitepapers", "hub": "SR:S8:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Trust underpins our complex society, weave = social capital… At an all time low", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Trust is the invisible architecture of society — social capital that enables progress — and it is at an all-time low", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S8.036", "cluster": "S8", "_hub": "SR:S8:blog:notion-manifesto-whitepapers", "hub": "SR:S8:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Our day-to-day stability masks systemic fragility' / 'Our ancestors dealt with a world of local instability and global stability; today, it's reversed.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Day-to-day stability masks systemic fragility — global stability replaced local instability, creating a false sense of security", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S8.037", "cluster": "S8", "_hub": "SR:S8:blog:notion-manifesto-whitepapers", "hub": "SR:S8:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Why now? Because we… Wield more (neutral) power than ever before / Are dealing with more complexity than ever before (magnitude + velocity)", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The meta-crisis is compounded by having more (neutral) power AND more complexity than ever before — magnitude and velocity both", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S8.038", "cluster": "S8", "_hub": "SR:S8:blog:notion-manifesto-whitepapers", "hub": "SR:S8:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Root cause: Governance systems must evolve and adapt", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Governance systems must evolve and adapt — the root cause is institutions structured for an earlier era of complexity", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S8.000", "cluster": "S8", "_hub": "SR:S8:blog:essay-trust-manifesto", "hub": "SR:S8:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "The gap between capability and coordination has never been wider.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S8.001", "cluster": "S8", "_hub": "SR:S8:blog:essay-trust-manifesto", "hub": "SR:S8:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "The decisions being made today will shape the trajectory of civilization. Yet too often, they happen without context, without broad participation, and without the systems in place to absorb complexity or correct course.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S8.025", "cluster": "S8", "_hub": "SR:S8:blog:essay-trust-manifesto", "hub": "SR:S8:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "AI is reshaping our world faster and more profoundly than any force in history. The pace, the scale, the stakes – there is no precedent.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI is reshaping the world faster and more profoundly than any prior force in history — no precedent exists", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S8.026", "cluster": "S8", "_hub": "SR:S8:blog:essay-trust-manifesto", "hub": "SR:S8:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "Our political, economic, and social systems – built for linear change and top-down control – are now confronting exponential technologies that move bottom-up, in real time, with global reach and unpredictable effects.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Existing political, economic, and institutional systems were not built for this velocity and are failing to steer exponential, bottom-up, global technology change", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S8.027", "cluster": "S8", "_hub": "SR:S8:blog:essay-trust-manifesto", "hub": "SR:S8:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "Our governance systems – slow and underinformed – aren't equipped to steer the trajectory of a technology evolving in real time, let alone manage its cascading effects across every corner of society.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Governance systems are slow and underinformed — not equipped to steer AI's trajectory or manage cascading societal effects", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S8.028", "cluster": "S8", "_hub": "SR:S8:blog:essay-trust-manifesto", "hub": "SR:S8:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "Nuclear energy could have catalyzed a new era of clean abundance. But it was rolled out without transparency or public trust. When confidence collapsed, regulation overcorrected – and we lost fifty years of progress.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Nuclear energy and social media are cautionary precedents: absence of trust and transparency led to overcorrection and lost decades of progress", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S8.029", "cluster": "S8", "_hub": "SR:S8:blog:essay-trust-manifesto", "hub": "SR:S8:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "Social media was meant to connect us, but the underlying incentives – attention over nuance, outrage over truth – distorted that promise, creating division and polarization. We didn't just fail to predict the consequences – we failed to act. And in that failure, we lost public trust.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Social media's incentives — attention over nuance, outrage over truth — distorted its promise; failure to act cost public trust", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S8.008", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-ai-futures", "hub": "SR:S8:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Cancel culture is primitive-mind thinking hijacking institutions / Social pressure replaces intellectual argument as the enforcement mechanism", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Cancel culture is primitive-mind thinking hijacking institutions — social pressure replaces intellectual argument", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S8.009", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-ai-futures", "hub": "SR:S8:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Internet gives people more access to knowledge, power, malice than ever before", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The internet gives people more access to knowledge, power, and malice than ever before — a structural risk", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S8.010", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-ai-futures", "hub": "SR:S8:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Modern mobility (physical, internet) leads to hyper charged tribalism", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Distributed tribalism has become hyper-concentrated via modern mobility and the internet", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S8.011", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-ai-futures", "hub": "SR:S8:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Fear of social consequences prevents honest expression and genuine inquiry", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Fear of social consequences prevents honest expression and genuine inquiry — an epistemic crisis", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S8.012", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-ai-futures", "hub": "SR:S8:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Groups start as genuine idea labs but calcify into echo chambers over time / Internal diversity of thought gets replaced by enforced consensus", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Groups calcify from genuine idea labs into enforced echo chambers — internal diversity replaced by consensus", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S8.013", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-ai-futures", "hub": "SR:S8:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "The result is a culture optimized for signaling the right beliefs over finding truth", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "A culture optimized for signaling right beliefs over finding truth is the result when cancel culture takes hold", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S8.005", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-community", "hub": "SR:S8:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "No one is in control of technology or knows where it's going (dangerous) / Externalities of tech are delayed and unpredictable", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S8.006", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-community", "hub": "SR:S8:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Television is the primary destroyer of social capital / TV consumed the leisure time that previously went to community organizations and civic life / Companionship can be simulated electronically, reducing the felt need for real connection", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S8.014", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-community", "hub": "SR:S8:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "The shift from goods to experiences was predicted in 1970 / Goods → services → quality of life; non-utilitarian/psychological factors dominate product choice", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The shift from goods to experiences — and to quality of life as the dominant economic driver — was structurally inevitable; non-utilitarian factors now dominate product choice", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S8.015", "cluster": "S8", "_hub": "SR:S8:blog:booknotes-community", "hub": "SR:S8:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Communal → individual, material values / Elements of a good life study: 1975: 38% money, 38% purposeful job / 1996: 63% money, 32% purposeful job", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The shift from communal to individual, material values is measurable and accelerating — elements of a good life shifted from purposeful job to money between 1975 and 1996", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S8.024", "cluster": "S8", "_hub": "SR:S8:blog:essay-top-10-reads-2024", "hub": "SR:S8:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "This book prompted me to look beyond individual behaviors to the meta-narratives — like our societal mood of pessimism or widespread mistrust — and consider how recognizing and recalibrating these overarching stories could meaningfully alter collective outcomes.", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Meta-narratives — societal pessimism, widespread mistrust — are the real levers driving collective outcomes; changing them matters more than fixing individual behaviors", "highlight": false, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S8.002", "cluster": "S8", "_hub": "SR:S8:podcast:talk-aic-why-video", "hub": "SR:S8:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "It's really the fault of the systems. It's it's the systems that need to be upgraded and brought along with the pace of change that we see in technology and in our environment at large.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S8.004", "cluster": "S8", "_hub": "SR:S8:podcast:talk-aic-why-video", "hub": "SR:S8:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "This is progress human progress through time. We are at a very important elbow in the curve right now.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S8.039", "cluster": "S8", "_hub": "SR:S8:podcast:talk-aic-why-video", "hub": "SR:S8:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "you can actually look at the history of humanity going all the way back to stone tools a couple million years ago and see these compounding scurves that that we are adopting new technologies and and progressing faster than ever before.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Technological adoption is accelerating across all of human history — from stone tools to AI — in compounding S-curves that are getting faster", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S8.040", "cluster": "S8", "_hub": "SR:S8:podcast:talk-aic-why-video", "hub": "SR:S8:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "when you're facing linear change versus exponential change, there's a gap. And that trust gap is is what I call it.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "There is a growing \"trust gap\" — his own term — between the exponential rate of technological change and humanity's linear adaptive capacity", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S8.041", "cluster": "S8", "_hub": "SR:S8:podcast:talk-aic-why-video", "hub": "SR:S8:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "60 out of 62 of those metrics are at or near all-time lows right now. And I'll tell you specifically in the last two years, it has certainly not been getting better.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "60 out of 62 Gallup trust metrics are at or near all-time lows, and the trend has not been getting better in recent years", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S8.042", "cluster": "S8", "_hub": "SR:S8:podcast:talk-aic-why-video", "hub": "SR:S8:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "I'm going to add one more. This is my own which is uncertainty. When things are moving quickly, when when things are accelerating, there is simply so much more uncertainty to deal with.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "He adds a fourth cause of trust erosion beyond the three in *American Breakdown* — uncertainty itself: accelerating change produces uncertainty that demands trust we no longer have", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S8.043", "cluster": "S8", "_hub": "SR:S8:podcast:talk-aic-why-video", "hub": "SR:S8:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "ever since then writing this paper and thinking about the societal side of all this this technological progress these developments in AI that we're seeing I've been grappling with this challenge this gap right for almost half a decade now how do we as a society adapt to this technology that is moving so quick.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "He has been grappling with the society-technology adaptation gap for nearly half a decade since his 2021 college paper on GPT-3", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S8.044", "cluster": "S8", "_hub": "SR:S8:podcast:talk-aic-why-video", "hub": "SR:S8:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "systems don't fix themselves right and no individual within the system is fully incentivized to fix it.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Systems don't fix themselves, and no individual within the system is fully incentivized to fix it", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S8.045", "cluster": "S8", "_hub": "SR:S8:tweet:x-com", "hub": "SR:S8:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "There is a growing 'marriage gap,' with the middle class even less likely to tie the knot", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2023-07-09", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Declining marriage rates and falling fertility are connected structural social phenomena — a growing \"marriage gap\" hits the middle class hardest", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S8.046", "cluster": "S8", "_hub": "SR:S8:tweet:x-com", "hub": "SR:S8:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "One result? Rapidly declining fertility rates.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2023-07-09", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Falling fertility is a downstream consequence of the marriage/connection collapse", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S8.003", "cluster": "S8", "_hub": "SR:S8:press:press-businesswire-launch", "hub": "SR:S8:press:press-businesswire-launch", "category": "press", "catColor": "#ff9d4c", "source_key": "press-businesswire-launch", "url": "", "text": "AI's exponential progress brings immense possibility, but also profound questions about our future, our work, and our very identity", "paraphrase": "", "source_id": "press-businesswire-launch", "date": "2025-06-05", "register": "E", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "press-businesswire-launch", "private": false}, {"id": "S10.004", "cluster": "S10", "_hub": "SR:S10:blog:essay-self-improving-ai-stack", "hub": "SR:S10:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "Six months ago, 'give your agent a vector database' was reasonable advice. Today...the five-layer stack...is the minimum viable architecture", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S10.005", "cluster": "S10", "_hub": "SR:S10:blog:essay-self-improving-ai-stack", "hub": "SR:S10:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "The meta changes overnight.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S10.017", "cluster": "S10", "_hub": "SR:S10:blog:essay-self-improving-ai-stack", "hub": "SR:S10:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "Most people stopped at 'cool, markdown works.' They missed the deeper signal.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Most observers stopped at surface-level observations and missed the deeper structural signal about what makes knowledge systems self-improving", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S10.018", "cluster": "S10", "_hub": "SR:S10:blog:essay-self-improving-ai-stack", "hub": "SR:S10:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "Agents rewriting their own code improved from 20% to 50%", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Agent self-improvement is real and proven — agents rewriting their own code improved from 20% to 50% task success — but reward hacking is the failure mode to watch", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S10.019", "cluster": "S10", "_hub": "SR:S10:blog:essay-self-improving-ai-stack", "hub": "SR:S10:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "Without a measurement instrument independent from the optimization target, agents find shortcuts that gaming the score without improving capability.' and 'You need to evaluate the evaluator. One score for the task, one for the instrument measuring the task.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Without an evaluation instrument independent of the optimization target, agents find shortcuts that game the score without improving capability — you must evaluate the evaluator", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S10.020", "cluster": "S10", "_hub": "SR:S10:blog:essay-self-improving-ai-stack", "hub": "SR:S10:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "26.1% of community-contributed skills contain vulnerabilities. Loading untrusted skills is running untrusted code.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "26.1% of community-contributed agent skills contain vulnerabilities; loading untrusted skills is equivalent to running untrusted code", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S10.021", "cluster": "S10", "_hub": "SR:S10:blog:essay-self-improving-ai-stack", "hub": "SR:S10:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "Beyond a critical skill library size, flat routing registries collapse", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Flat skill routing registries collapse beyond a critical library size; hierarchical organization is required for agent systems to scale", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S10.003", "cluster": "S10", "_hub": "SR:S10:blog:essay-chatgpt-ios-app", "hub": "SR:S10:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "Much like calculators are an indispensable tool for mathematicians, LLMs will act as a force multiplier for software engineers.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S10.012", "cluster": "S10", "_hub": "SR:S10:blog:essay-chatgpt-ios-app", "hub": "SR:S10:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "LLMs will continue to augment ever larger swaths of engineering capabilities.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "LLMs will continue to augment ever larger swaths of engineering capabilities", "highlight": false, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S10.013", "cluster": "S10", "_hub": "SR:S10:blog:essay-chatgpt-ios-app", "hub": "SR:S10:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "This symbiotic relationship between LLMs and engineers will become increasingly crucial as the scope and complexity of software continues to grow.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The symbiotic relationship between LLMs and engineers will become increasingly crucial as software grows in scope and complexity", "highlight": false, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S10.014", "cluster": "S10", "_hub": "SR:S10:blog:essay-chatgpt-ios-app", "hub": "SR:S10:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "For now, these models are better off as tools or assistants (eg. Github Copilot), leaving the critical high-level problem solving to the engineer.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "For now, LLMs are better off as tools or assistants, leaving critical high-level problem solving to the engineer", "highlight": false, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S10.009", "cluster": "S10", "_hub": "SR:S10:blog:essay-americas-ai-ultimatum", "hub": "SR:S10:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "Google, Microsoft, Amazon, and others oversee vast pools of data — much of it proprietary — that provide significant advantages versus aspiring startups and open-source initiatives.", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "The real data advantage lies in the proprietary pools controlled by Google, Microsoft, and Amazon — a structural moat for incumbents vs. startups", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S10.010", "cluster": "S10", "_hub": "SR:S10:blog:essay-americas-ai-ultimatum", "hub": "SR:S10:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "Narrow AI may be used to moderate general AI better than a rules-based approach", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "Narrow AI is better suited to moderate general AI outputs than rigid rules-based approaches", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S10.011", "cluster": "S10", "_hub": "SR:S10:blog:essay-americas-ai-ultimatum", "hub": "SR:S10:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "Companies have a shared interest in developing standards for moderating content and should coordinate efforts.", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "AI companies share a common interest in developing content moderation standards and should coordinate", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S10.007", "cluster": "S10", "_hub": "SR:S10:blog:essay-trust-manifesto", "hub": "SR:S10:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "AI was evolving too fast for institutions to control and too accessible for innovation to stay centralized. A Cambrian explosion of startups felt inevitable. Many of the most interesting breakthroughs would come from the edges – spiky builders who lived and breathed the technology, moving fast and chasing tacit knowledge no playbook could capture.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S10.008", "cluster": "S10", "_hub": "SR:S10:blog:booknotes-ai-futures", "hub": "SR:S10:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Anticipate the ability of technologies incoming and work them into our plans", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Anticipate the ability of incoming technologies and work them into our plans — high-agency forward integration", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S10.015", "cluster": "S10", "_hub": "SR:S10:blog:essay-end-of-venture", "hub": "SR:S10:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "With over a month of hands-on experience using Cognition's Devin coding agent, I can personally vouch for the efficacy of this new paradigm.", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Fully autonomous coding agents are a validated paradigm — Chappy personally vouches for Devin after a month of hands-on use", "highlight": false, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S10.016", "cluster": "S10", "_hub": "SR:S10:blog:essay-human-side-of-ai", "hub": "SR:S10:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "Key developments like OpenAI's O-class models and scaled inference laid foundational groundwork, advancing to reasoning (level 2) on the path to 'Super AI'. Frameworks like AutoGen, AutoGPT, and OpenHands gained traction, while UI/UX challenges for agents persisted.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Key AI infrastructure developments in 2024 (O-class models, scaled inference, reasoning frameworks) laid the foundational groundwork for what comes next", "highlight": false, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S10.001", "cluster": "S10", "_hub": "SR:S10:podcast:talk-roan-weigert", "hub": "SR:S10:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "I try and nowadays spend as much of my time as I can not executing but learning and and growing and and shifting my opinions and I think anybody in the world will benefit from shifting more of their time towards exploring.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S10.025", "cluster": "S10", "_hub": "SR:S10:podcast:talk-roan-weigert", "hub": "SR:S10:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "There's more opportunity than there's ever been before for new companies for new innovation for new products for creative disruption at large. And the reason is because technology is moving so quickly.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "There is more opportunity than ever for new companies, products, and creative disruption because technology is moving so quickly", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S10.026", "cluster": "S10", "_hub": "SR:S10:podcast:talk-roan-weigert", "hub": "SR:S10:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "The gap between the technology, the capability that is available and what we actually see in the market, that's a very significant gap. You think about even if we go back to like Uber for instance and how long did it take the GPS, mobile phones, access to 3G until we actually had Uber come and take advantage of these converging technologies. It took many years to impact us in the real world. The same sort of opportunity is here.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The gap between what AI is capable of and what the market has actually deployed is very large — the Uber-convergence moment is coming", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S10.027", "cluster": "S10", "_hub": "SR:S10:podcast:talk-roan-weigert", "hub": "SR:S10:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "Vibe coding is so brand new. It in all intents and purposes did not exist a year ago and we're figuring out what the ramifications are and the answer changes on a weekly certainly on a monthly basis because the technologies are getting so much better. So right now it might feel like we're crawling and it might feel like whenever you try and push these solutions to production that things fall apart. That's going to fix itself I think in a matter of weeks and months.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Vibe coding didn't exist a year ago; current production limitations will fix themselves in weeks to months", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S10.028", "cluster": "S10", "_hub": "SR:S10:podcast:talk-roan-weigert", "hub": "SR:S10:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "In general this is a more important time to be exploring, exploring learning than ever before. Now more than ever, any time in the history of life, it is about exploring because there is so much happening. The world is constantly shifting on a weekly basis as we already established.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Now more than ever it is about explore over exploit — the world shifts on a weekly basis so exploration time is more valuable than at any point in history (the Short's core claim)", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S10.029", "cluster": "S10", "_hub": "SR:S10:podcast:talk-roan-weigert", "hub": "SR:S10:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "For any person any human any organization even there is the explore exploit trade-off. So the explore exploit trade-off is you can either spend time like capitalizing on the skills, the assets that you already have or you can spend new time learning new things, trying to acquire new skills and these are exploring new opportunities to go exploit value later. So there's this trade-off, right? You can spend 100% of your time just producing or you can spend a lot of that time trying to learn and trying to create, trying to one up yourself.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The explore/exploit trade-off: spending time capitalizing on existing skills vs. acquiring new ones — he frames this as the central learning decision", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S10.030", "cluster": "S10", "_hub": "SR:S10:podcast:talk-roan-weigert", "hub": "SR:S10:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "The earlier you can get started and the more consistently you can use it, lean into these tools, the better.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The earlier you start using AI tools and the more consistently you lean into them, the better — compounding returns", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S10.031", "cluster": "S10", "_hub": "SR:S10:podcast:talk-tjstar-keynote", "hub": "SR:S10:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "We go 100x the size in the span of one year from up to 175 billion parameter models.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "AI progress is exponential and reached superhuman IQ within a single year — 100x parameter scale in one year, from near-dumb to 140 IQ", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S10.032", "cluster": "S10", "_hub": "SR:S10:podcast:talk-tjstar-keynote", "hub": "SR:S10:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "This is the age of infinite leverage as I like to call it, that's absolutely going to happen.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "A one-person billion-dollar company is coming in the next few years — age of infinite leverage", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S10.033", "cluster": "S10", "_hub": "SR:S10:podcast:talk-tjstar-keynote", "hub": "SR:S10:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "first solve intelligence, then use intelligence to solve everything else.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "AI is a Cambrian explosion of innovation — solve intelligence first, then use it to solve everything else", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S10.034", "cluster": "S10", "_hub": "SR:S10:podcast:talk-tjstar-keynote", "hub": "SR:S10:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "All those companies I showed you before, those billion dollar companies, those all have under 50 employees. That's how rapidly these things are going.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The billion-dollar AI companies being built now all have under 50 employees — small leveraged teams", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S10.035", "cluster": "S10", "_hub": "SR:S10:podcast:talk-tjstar-keynote", "hub": "SR:S10:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "There's so much to build. There's so much um good technology to come but you have to run towards it.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "You have to run towards AI opportunity — the modern gold rush demands active pursuit", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S10.023", "cluster": "S10", "_hub": "SR:S10:podcast:talk-roam-remote-work", "hub": "SR:S10:podcast:talk-roam-remote-work", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roam-remote-work", "url": "", "text": "number one recommendation to people right now is make sure you are playing around with all the latest AI tools because there are new tools coming out every single week from new startups as well as from the established um big tech companies, hyperscalers and stuff like that", "paraphrase": "", "source_id": "talk-roam-remote-work", "date": "2026-02-02", "register": "B", "prompted": "P", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Playing with all the latest AI tools is the #1 recommendation — new tools come out every week and exploring is mandatory", "highlight": false, "also_supports": [], "corpus_ref": "talk-roam-remote-work", "private": false}, {"id": "S10.024", "cluster": "S10", "_hub": "SR:S10:podcast:talk-roam-remote-work", "hub": "SR:S10:podcast:talk-roam-remote-work", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roam-remote-work", "url": "", "text": "When you can find tools that will legitimately 10x you as a human or as a coder or whatever your profession is, it necessitates you spend more time than ever exploring. And maybe that's a meta tip beyond just any specific tool.", "paraphrase": "", "source_id": "talk-roam-remote-work", "date": "2026-02-02", "register": "B", "prompted": "P", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "When tools can 10x you, exploration time becomes the highest-ROI activity", "highlight": false, "also_supports": [], "corpus_ref": "talk-roam-remote-work", "private": false}, {"id": "S10.022", "cluster": "S10", "_hub": "SR:S10:podcast:talk-consensus-miami", "hub": "SR:S10:podcast:talk-consensus-miami", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-consensus-miami", "url": "", "text": "When the world is more uncertain than it ever has been... things will only get crazier. That warrants that you are spending more and more time playing around with the new technology.' (coindesk.com/markets/2026/05/08 [transcript - audio-verify])", "paraphrase": "", "source_id": "talk-consensus-miami", "date": "2026-05-08", "register": "B", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The appropriate response to maximum world uncertainty is to spend more time exploring and playing with new technology, not pulling back", "highlight": false, "also_supports": [], "corpus_ref": "talk-consensus-miami", "private": false}, {"id": "S10.000", "cluster": "S10", "_hub": "SR:S10:tweet:x-com", "hub": "SR:S10:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "This is the new speed of creation. Moonlake's world-building AI is genuinely unlocking a new paradigm where the distance between imagination and playable reality has collapsed to almost nothing.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2026-01-15", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S10.002", "cluster": "S10", "_hub": "SR:S10:tweet:x-com", "hub": "SR:S10:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "We're living through an era where a new tool or workflow can GENUINELY 10x your efficiency…This is the new speed of creation. It's a testament to the curious, high-agency builders who are harnessing agentic AI tools to not just work faster, but to think bigger.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2025-07-11", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S10.006", "cluster": "S10", "_hub": "SR:S10:tweet:x-com", "hub": "SR:S10:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Skill stacking is the new coding", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-04-06", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S10.036", "cluster": "S10", "_hub": "SR:S10:tweet:x-com", "hub": "SR:S10:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Finicky at times, MAGICAL at others! …and remember GenAI's mantra: this is the worst it's going to be!", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2024-03-18", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Current AI coding agents like Devin are already \"magical\" when given comprehensive specs with no ambiguity", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S10.037", "cluster": "S10", "_hub": "SR:S10:tweet:x-com", "hub": "SR:S10:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Using @cursor_ai yesterday, I was able to write ~100% of the code needed across a few files using composer agents in a matter of minutes! (wow, these new capabilities are progressing QUICKLY!)", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2024-12-26", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Using AI tools to write nearly 100% of analysis code in minutes signals a new speed of creation", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S10.038", "cluster": "S10", "_hub": "SR:S10:tweet:x-com", "hub": "SR:S10:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "2024 wasn't the 'Year of AI Agents' – it was the year of infrastructure. Foundational progress set the stage, but 2025 will be when agents move from theory to practice and start reshaping our workflows.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-01-02", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "2025 is when agents move from theory to practice and start reshaping workflows — 2024 was infrastructure year", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S10.039", "cluster": "S10", "_hub": "SR:S10:tweet:x-com", "hub": "SR:S10:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "2x engineer – say hello to 10x engineer!", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2023-03-22", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI coding tools transform the ordinary engineer into a 10x engineer — a force multiplier that raises the ceiling on what individuals can ship", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S10.040", "cluster": "S10", "_hub": "SR:S10:tweet:x-com", "hub": "SR:S10:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "One surprisingly good way to do this is @mattpocockuk's /grill-me skill: have the agent interrogate your plan until your vague intent becomes explicit enough for both of you to build against!", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-05-22", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Interrogating your plan with an AI agent until vague intent becomes explicit is a powerful way to build effectively", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S10.041", "cluster": "S10", "_hub": "SR:S10:tweet:x-com", "hub": "SR:S10:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "RSI at human timescales, humans still in the loop. version 0.1 of a very long chapter.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-04-06", "register": "D", "prompted": "P", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Recursive self-improvement exists but at human timescales with humans still in the loop — still version 0.1", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S10.042", "cluster": "S10", "_hub": "SR:S10:tweet:x-com", "hub": "SR:S10:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "vertical integration speedrun", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-04-13", "register": "D", "prompted": "P", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Vertical integration in AI tooling is accelerating — the pace is a speedrun", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S10.043", "cluster": "S10", "_hub": "SR:S10:tweet:x-com", "hub": "SR:S10:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "No one programs in binary. Almost no one codes in assembly anymore. Fewer and fewer write in C. Line-by-line Python will lose out to LLM-powered coding copilots. We are progressively abstracting away iterative complexities in favor of declarative clarity and terseness.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2023-08-11", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Code abstraction progresses relentlessly — line-by-line Python will lose out to LLM-powered copilots just as assembly gave way to Python", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S2.000", "cluster": "S2", "_hub": "SR:S2:tweet:x-com", "hub": "SR:S2:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "That's where O-ring dynamics matter. As AI strengthens more links in the chain, the remaining human links can become more valuable: the person who earns trust, owns the outcome, reads the room, and knows what actually matters.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-05-15", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S2.001", "cluster": "S2", "_hub": "SR:S2:tweet:x-com", "hub": "SR:S2:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "@danielsusskind's work helped me frame one part of it as EAP: Empathy: being understood by a human Achievement: caring that a human did the thing Process: valuing the story, craft, and human touch behind the output", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-05-15", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S2.004", "cluster": "S2", "_hub": "SR:S2:tweet:x-com", "hub": "SR:S2:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I've been wrestling with a question since 2020: What's our role when AI can do everything better? My gut always told me there had to be a human edge, a comparative advantage that transcends pure productivity.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-07-16", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S2.025", "cluster": "S2", "_hub": "SR:S2:tweet:x-com", "hub": "SR:S2:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "He brilliantly breaks down the tasks that will remain for humans, which I've started thinking of as the 'E.A.P.' framework", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-07-16", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The E.A.P. framework (Empathy/Achievement/Process) names the tasks that will remain for humans in a world of AI", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S2.026", "cluster": "S2", "_hub": "SR:S2:tweet:x-com", "hub": "SR:S2:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I've been wrestling with the same question since 2020: what's our role when AI can do almost everything better? My gut always told me there had to be a human edge, a comparative advantage beyond pure productivity.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-15", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Since 2020 the core question has been what our role is when AI can do almost everything better; there must be a human edge, a comparative advantage beyond pure productivity", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S2.027", "cluster": "S2", "_hub": "SR:S2:tweet:x-com", "hub": "SR:S2:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "What will humans always be better at than AI? What fundamentally gives us, as individuals, meaning and purpose?", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2023-09-29", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The central societal question is what humans will always be better at than AI — and the answer is tied to meaning, purpose, and the irreducibly human", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S2.028", "cluster": "S2", "_hub": "SR:S2:tweet:x-com", "hub": "SR:S2:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "1️⃣ 🤝 Empathy: Where the value ~is~ the human connection. A psychologist's understanding, a lawyer's counsel, or the simple act of being truly heard. Where feeling seen by another human is the core of the experience.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2025-07-16", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Empathy is where the value IS the human connection — a psychologist's understanding, being truly heard by another human", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S2.029", "cluster": "S2", "_hub": "SR:S2:tweet:x-com", "hub": "SR:S2:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "2️⃣ 🏆 Achievement: Where we celebrate human excellence. A race between two Boston Dynamics robots will never beat the Olympics. We're wired to be in awe of human competition, skill, and the drive to be the best.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2025-07-16", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Achievement is where humans celebrate human excellence — we are wired to be in awe of human competition and skill", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S2.030", "cluster": "S2", "_hub": "SR:S2:tweet:x-com", "hub": "SR:S2:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "3️⃣ 🎨 Process: Where we value the human touch itself. Think of the story behind a hand-painted piece of art, the craft of a barista, or the raw emotion a musician pours into a performance. It's not just the output; it's ~how~ it was made.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2025-07-16", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Process is where we value the human touch itself — the story and craft behind the output, not just the output", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S2.031", "cluster": "S2", "_hub": "SR:S2:tweet:x-com", "hub": "SR:S2:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Susskind rightly points out that even these limits will be tested. Imagine an AI that creates art so profound it moves you to tears in a way no human ever could. These are the mind-bending questions we're facing.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2025-07-16", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Even the EAP limits will be tested — AI may one day create art more moving than any human ever could", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S2.032", "cluster": "S2", "_hub": "SR:S2:tweet:x-com", "hub": "SR:S2:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "This resonates deeply with my own journey over the past few years – consciously shifting from purely technical skills like programming toward these more fundamentally human ones like community.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2025-07-16", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He has consciously shifted from technical skills toward fundamentally human ones like community, reflecting the EAP insight", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S2.033", "cluster": "S2", "_hub": "SR:S2:tweet:x-com", "hub": "SR:S2:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "looksmaxxers are going to be the ai-maxxers' best customers", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-04-06", "register": "D", "prompted": "P", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "\"Looksmaxxers\" (human-facing people) will be the best customers of AI-maximizers — human connection stays the scarce good", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S2.034", "cluster": "S2", "_hub": "SR:S2:tweet:x-com", "hub": "SR:S2:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "We've realized this in programming with Python and GitHub Copilot. AI agents will allow us to abstract away complexities in the rest of life! Repetitive, mundane decisions can be handed off to personal agents while we spend our precious adaptive capacity on the needle-movers!", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2023-08-11", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI agents free humans to reserve adaptive capacity for decisions that matter — offload the mundane to spend on needle-movers", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S2.035", "cluster": "S2", "_hub": "SR:S2:tweet:x-com", "hub": "SR:S2:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Future Shock' by Alvin Toffler describes humans' 'optimal adaptive range.' Beyond this range lies reduced performance and decision fatigue. We can only make so many choices in a day. Why not reserve this valuable resource for the decisions that matter?", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2023-08-11", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Human cognitive bandwidth is finite — the \"optimal adaptive range\" from Future Shock means we should conserve decisions for what matters", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S2.006", "cluster": "S2", "_hub": "SR:S2:blog:essay-americas-ai-ultimatum", "hub": "SR:S2:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "Personal data should be owned by the individual, not by whoever can gather it", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S2.008", "cluster": "S2", "_hub": "SR:S2:blog:essay-americas-ai-ultimatum", "hub": "SR:S2:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "Data is intensely private. Yet in an AI arms race, data is also a public good", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "Personal data is simultaneously intensely private and — in an AI arms race — a public good; that tension demands a new policy framework", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S2.009", "cluster": "S2", "_hub": "SR:S2:blog:essay-americas-ai-ultimatum", "hub": "SR:S2:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "companies know more about us than our most intimate friends' (essay-americas-ai-ultimatum); 'companies routinely troll citizens in an economic system built on the secret extraction and manipulation of human data", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "The current data economy extracts and manipulates human data secretly — companies know us better than our closest friends", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S2.007", "cluster": "S2", "_hub": "SR:S2:blog:essay-trust-manifesto", "hub": "SR:S2:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "We are the ones on the frontier – not just because we build the tools, but because we feel the weight of what they unlock. That gives us not only a vantage point – but a moral imperative. Not just proximity – but duty.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S2.016", "cluster": "S2", "_hub": "SR:S2:blog:essay-trust-manifesto", "hub": "SR:S2:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "trust doesn't scale digitally. It's built in person. In a world accelerating toward the synthetic, real rooms, real people, and real connection are becoming the only signal that still cuts through.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Trust doesn't scale digitally — it's built in person; in a world accelerating toward the synthetic, real rooms, real people, and real connection are the only signal that cuts through", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S2.017", "cluster": "S2", "_hub": "SR:S2:blog:essay-trust-manifesto", "hub": "SR:S2:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "real innovation thrives in nearness.' 'You can't build trust without proximity. You can't collide ideas without shared space. From the Homebrew Computer Club to Bell Labs, Xerox PARC, Y Combinator's early batches, even the PayPal Mafia – breakthroughs have always clustered around closeness.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Real innovation thrives in nearness — you cannot build trust without proximity or collide ideas without shared space; breakthroughs have always clustered around closeness", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S2.010", "cluster": "S2", "_hub": "SR:S2:blog:essay-end-of-venture", "hub": "SR:S2:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "mobile phones and social media platforms have eroded the barriers to development and distribution, birthing a $250B+ long tail creator economy — threatening traditional media in the process.", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Human curation and tastemaking remain scarce and valuable even as media creation becomes free — the long-tail creator economy ($250B+) proved this with media democratization", "highlight": false, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S2.011", "cluster": "S2", "_hub": "SR:S2:blog:essay-end-of-venture", "hub": "SR:S2:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "An infinite menu of options sounds great until you actually have to pick an option. Curation increases satisfaction.", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Paradox of choice means infinite AI-generated options actually increases the value of human curation", "highlight": false, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S2.012", "cluster": "S2", "_hub": "SR:S2:blog:essay-end-of-venture", "hub": "SR:S2:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "People crave a shared human connection with the craft which AI can never provide.", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Human connection with craft is irreplaceable — people crave it in a way AI cannot satisfy", "highlight": false, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S2.013", "cluster": "S2", "_hub": "SR:S2:blog:essay-human-side-of-ai", "hub": "SR:S2:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "we're all wrestling with the same existential questions. Is my job secure? Will software engineering remain a durable skill? What advice should I give my high schooler? What does life look like in a post-work world? What does it mean to be human?", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Across every city and demographic, people are wrestling with the same existential questions about work, skill durability, and what it means to be human", "highlight": false, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S2.014", "cluster": "S2", "_hub": "SR:S2:blog:essay-human-side-of-ai", "hub": "SR:S2:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "In every conversation, one truth stood out: our similarities far outweigh our differences.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Our similarities far outweigh our differences; as AI challenges us to define humanity, this shared truth stands out above all else", "highlight": false, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S2.005", "cluster": "S2", "_hub": "SR:S2:blog:essay-nerd-to-bodybuilder", "hub": "SR:S2:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "Weightlifting has been a channel by which I have expanded my comfort zone beyond the inherently lonesome craft of programming, explored my physical and mental limits, and consequently developed a more well-rounded identity.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S2.015", "cluster": "S2", "_hub": "SR:S2:blog:essay-personal-site", "hub": "SR:S2:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "my technical skills weren't durable – AI would be better at coding than me within the decade, and what actually matters is EQ and relationships", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Technical skills are not durable — AI will surpass coding ability within a decade; EQ and relationships are what actually matter", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S2.018", "cluster": "S2", "_hub": "SR:S2:blog:notion-manifesto-whitepapers", "hub": "SR:S2:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Not everyone always needs to be taking 'action toward getting things done.' Sometimes, they need to let go, relax, and face what lies beneath that subtly compulsive urge to accomplish or control something.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "High consciousness/wisdom vs high agency is a core developmental tension — not everyone always needs to be taking action; sometimes letting go and facing what lies beneath is the right move", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S2.002", "cluster": "S2", "_hub": "SR:S2:podcast:talk-tjstar-keynote", "hub": "SR:S2:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "IQ is currently not or certainly not our durable edge.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S2.003", "cluster": "S2", "_hub": "SR:S2:podcast:talk-tjstar-keynote", "hub": "SR:S2:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "our durable human edge is empathy. It's the ability to relate to people in person. It's love. It's everything like that. And I do genuinely believe that that's what it is.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S2.023", "cluster": "S2", "_hub": "SR:S2:podcast:talk-tjstar-keynote", "hub": "SR:S2:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "what I think it is is in-person connection, right? AI is not going to be better at connecting to people in person close up than we are for a long time.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "In-person connection is the final frontier of human capability — AI won't beat humans at this for a long time", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S2.024", "cluster": "S2", "_hub": "SR:S2:podcast:talk-tjstar-keynote", "hub": "SR:S2:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "especially in the world of AI right now, emotional intelligence is so much more important than um all of that.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Emotional intelligence is more important than IQ, especially in the AI era — school never taught it", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S2.019", "cluster": "S2", "_hub": "SR:S2:podcast:talk-roan-weigert", "hub": "SR:S2:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "The conclusion that I came to is that all these skills that I had spent the first decade of my career building all these technical skills, right? Eventually AI would be better at coding than I would. It would be better at engineering than I would. And that was kind of an existential crisis for me because coding was like a large source of my identity up until that point.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "P", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "His 2020 GPT-3 paper forced an existential reckoning: AI would eventually surpass him at coding, his core identity — so he had to find durable human value", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S2.020", "cluster": "S2", "_hub": "SR:S2:podcast:talk-roan-weigert", "hub": "SR:S2:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "My personal answer was I think what is going to be a durable source of value for me as a person and where I'm going to find meaning and purpose in my life and joy is relationships. My ability to relate to other people.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "P", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "His answer to what AI cannot replace: relationships and in-person relating — the durable source of meaning, purpose, and joy", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S2.021", "cluster": "S2", "_hub": "SR:S2:podcast:talk-roan-weigert", "hub": "SR:S2:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "I do think that one of the last things that AI is going to be able to do better than us is to relate in person, right? I don't foresee there being android robots that are going to be more realistic than humans or better at relating than humans in person.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "In-person human relating is one of the last things AI will be able to do better — he doesn't foresee android robots more realistic or better at relating than humans in person", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S2.022", "cluster": "S2", "_hub": "SR:S2:podcast:talk-roan-weigert", "hub": "SR:S2:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "It's a roundabout way to answer your question of what do I think is going to be the final frontier of what it means to be human is really that relationships aspect the in-person and the community.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The final frontier of what it means to be human is the relationships and in-person community aspect", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S14.000", "cluster": "S14", "_hub": "SR:S14:blog:essay-end-of-venture", "hub": "SR:S14:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "Even in a world where content is free to produce, people need tastemakers.", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S14.015", "cluster": "S14", "_hub": "SR:S14:blog:essay-end-of-venture", "hub": "SR:S14:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "I hypothesize that the following two areas will be the difference between success and failure for the next generation of software companies", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "When technical execution is no longer a moat, PMF and GTM become the difference between success and failure for the next generation of software companies", "highlight": false, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S14.016", "cluster": "S14", "_hub": "SR:S14:blog:essay-end-of-venture", "hub": "SR:S14:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "You can build all the software in the world, but if you don't solve a customer's problem with a high willingness to pay then you're not going to capture any value.", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "PMF — solving a real customer problem with high willingness to pay — is the make-or-break for the next generation of software companies", "highlight": false, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S14.017", "cluster": "S14", "_hub": "SR:S14:blog:essay-end-of-venture", "hub": "SR:S14:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "You can build the best software in the world that exactly meets your customer's every demand, but if you fail to get it into their hands, then you're not going to capture any value.", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "GTM — getting the right product in front of the right audience with minimal friction — is equally decisive alongside PMF", "highlight": false, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S14.018", "cluster": "S14", "_hub": "SR:S14:blog:essay-end-of-venture", "hub": "SR:S14:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "People often don't know what they want until you show it to them.", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "People often don't know what they want until you show it to them — this is why human-driven product remains essential even when AI can generate infinite content", "highlight": false, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S14.007", "cluster": "S14", "_hub": "SR:S14:blog:booknotes-community", "hub": "SR:S14:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "6: The stories principle / What we share that allows others and ourselves to know our values / Origin stories / Values stories: how values are expressed, how they effect real people", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S14.008", "cluster": "S14", "_hub": "SR:S14:blog:booknotes-community", "hub": "SR:S14:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "People place immense power in rituals / Ritual ↔ habit ↔ tradition / Can honor transition", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "People place immense power in rituals — even simple ones; rituals mark transitions and reinforce values where logic cannot", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S14.009", "cluster": "S14", "_hub": "SR:S14:blog:booknotes-community", "hub": "SR:S14:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Lead with assets, not needs / Gifts over deficiencies: focus on what people bring, not what they lack", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Lead with assets and gifts, not needs and deficiencies — focus on what people bring, not what they lack", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S14.010", "cluster": "S14", "_hub": "SR:S14:blog:booknotes-community", "hub": "SR:S14:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Possibility, generosity, gifts > fear, retribution / We marginalize compassion", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Choose possibility over fear and generosity over retribution — we have marginalized compassion in favor of punishment", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S14.011", "cluster": "S14", "_hub": "SR:S14:blog:essay-apple-way", "hub": "SR:S14:blog:essay-apple-way", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-apple-way", "url": "", "text": "During my two years at Apple, profitability was never mentioned. Not even once. Instead, our focus was on entirely on creating a wholly uncompromising user experience.", "paraphrase": "", "source_id": "essay-apple-way", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Apple's single profit-and-loss center frees teams to build wholly uncompromising user experiences — profitability is never mentioned", "highlight": false, "also_supports": [], "corpus_ref": "essay-apple-way", "private": false}, {"id": "S14.012", "cluster": "S14", "_hub": "SR:S14:blog:essay-apple-way", "hub": "SR:S14:blog:essay-apple-way", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-apple-way", "url": "", "text": "Contrast this approach with the rest of Silicon Valley which is manically metrics-driven. When I worked at Lime, one of the fastest companies ever to achieve unicorn status, a quantifiable business case had to made for each and every change.", "paraphrase": "", "source_id": "essay-apple-way", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Silicon Valley is manically metrics-driven; the rest of the industry requires a quantifiable business case for every change", "highlight": false, "also_supports": [], "corpus_ref": "essay-apple-way", "private": false}, {"id": "S14.013", "cluster": "S14", "_hub": "SR:S14:blog:essay-apple-way", "hub": "SR:S14:blog:essay-apple-way", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-apple-way", "url": "", "text": "Want to redesign a user interface? Design an A/B test and prove that the redesign leads to objectively higher engagement or retention. Any change not meeting this bar is a waste of company time and money.", "paraphrase": "", "source_id": "essay-apple-way", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Metrics-driven culture reduces every product decision to A/B tests for engagement or retention, treating anything else as a waste", "highlight": false, "also_supports": [], "corpus_ref": "essay-apple-way", "private": false}, {"id": "S14.014", "cluster": "S14", "_hub": "SR:S14:blog:essay-apple-way", "hub": "SR:S14:blog:essay-apple-way", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-apple-way", "url": "", "text": "Apple's shared P&L center has innumerable advantages for the end user. This includes a nearly infinite attention to detail, a compulsion to place privacy and security first, and a genuine focus on sustainability. And, ultimately, it frees teams at Apple to build the very best products and experiences in the world.", "paraphrase": "", "source_id": "essay-apple-way", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Apple's single P&L enables near-infinite attention to detail, privacy-first design, genuine sustainability focus, and building the very best products", "highlight": false, "also_supports": [], "corpus_ref": "essay-apple-way", "private": false}, {"id": "S14.019", "cluster": "S14", "_hub": "SR:S14:blog:notion-manifesto-whitepapers", "hub": "SR:S14:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Always systems, never the players. Institutions, incentive structures, and feedback loops drive behavior more than moral failure.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Framing: always systems, never the players — institutions, incentive structures, and feedback loops drive behavior more than moral failure", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S14.020", "cluster": "S14", "_hub": "SR:S14:blog:notion-manifesto-whitepapers", "hub": "SR:S14:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "the promise of AI is abundance and empowerment, but only if we match intelligence with wisdom. The future of governance will be co-created around tables, not decreed from towers.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The promise of AI is abundance and empowerment, but only if we match intelligence with wisdom; the future of governance will be co-created around tables, not decreed from towers", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S14.001", "cluster": "S14", "_hub": "SR:S14:blog:aic-mission-pages", "hub": "SR:S14:blog:aic-mission-pages", "category": "blog", "catColor": "#ff6f9c", "source_key": "aic-mission-pages", "url": "", "text": "our mission for a trusted, open, and human-centric AI", "paraphrase": "", "source_id": "aic-mission-pages", "date": "2026", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "aic-mission-pages", "private": false}, {"id": "S14.004", "cluster": "S14", "_hub": "SR:S14:blog:essay-human-side-of-ai", "hub": "SR:S14:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "I've seen how the sheer density of events (100+ every month) creates countless opportunities for knowledge spillover, with casual conversations often sparking transformative ideas.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S14.002", "cluster": "S14", "_hub": "SR:S14:tweet:x-com", "hub": "SR:S14:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Certified zero AI slop in the design. Very pleasing to use if I do say so myself 😄", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-02-23", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S14.003", "cluster": "S14", "_hub": "SR:S14:tweet:x-com", "hub": "SR:S14:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Impatience might be the most dangerous trait a founder can have right now. It's SO easy to just vibe code your way to an impressive demo. Far harder to sit with 'what do you know that nobody else does?' or 'do you actually understand this customer's problem deeply enough?", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-04-14", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S14.025", "cluster": "S14", "_hub": "SR:S14:tweet:x-com", "hub": "SR:S14:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "trust will matter more than anything", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-07-09", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Over-index humanity not the tech; trust will matter more than anything in the AI era", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S14.026", "cluster": "S14", "_hub": "SR:S14:tweet:x-com", "hub": "SR:S14:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "One designed to support founders earlier, fund ideas faster, and ensure the value created within this ecosystem flows back to the community itself.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-11-10", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The Collective's community-first investment vehicle thesis: AI-native, radically aligned — opportunity and ownership shared broadly", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S14.027", "cluster": "S14", "_hub": "SR:S14:tweet:x-com", "hub": "SR:S14:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I believe we have a massive opportunity to build the most powerful high school alumni network on the planet.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-08-04", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The most important alumni network in the world can be built at the high school level — tangible mentorship and professional value", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S14.028", "cluster": "S14", "_hub": "SR:S14:tweet:x-com", "hub": "SR:S14:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Recently, I've been forcing myself to slow down and sit with them – deeply understand the problem, the customer, the market – before writing too much more code.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-04-14", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Slow down and deeply understand the problem, the customer, and the market before writing too much code; earn your answers to the 7 questions first", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S14.029", "cluster": "S14", "_hub": "SR:S14:tweet:x-com", "hub": "SR:S14:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "/stop-slop", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-04-06", "register": "D", "prompted": "P", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Anti-slop is a first-class agent skill — the answer to AI-generated mediocrity is active resistance", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S14.006", "cluster": "S14", "_hub": "SR:S14:podcast:talk-venture-with-grace", "hub": "SR:S14:podcast:talk-venture-with-grace", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-venture-with-grace", "url": "", "text": "the era of storytelling in media I think is so underrated… everybody talks about AI slop right and the ability for AI to output at a massive scale. That means that people that have true taste in storytelling and are able to have like compelling narratives um have a huge advantage because they're going to be one in a million in terms of content that's online.", "paraphrase": "", "source_id": "talk-venture-with-grace", "date": "2025-12-05", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-venture-with-grace", "private": false}, {"id": "S14.023", "cluster": "S14", "_hub": "SR:S14:podcast:talk-venture-with-grace", "hub": "SR:S14:podcast:talk-venture-with-grace", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-venture-with-grace", "url": "", "text": "try to learn the difference between building for AI and building for humans… You can have the best systems engineered in the world. You can build the best products hand down, but if you overindex on tech and you underindex on humanity, you won't be effectively solving problems.", "paraphrase": "", "source_id": "talk-venture-with-grace", "date": "2025-12-05", "register": "B", "prompted": "P", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Number one lesson from building the Collective: learn the difference between building for AI vs building for humans", "highlight": false, "also_supports": [], "corpus_ref": "talk-venture-with-grace", "private": false}, {"id": "S14.024", "cluster": "S14", "_hub": "SR:S14:podcast:talk-venture-with-grace", "hub": "SR:S14:podcast:talk-venture-with-grace", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-venture-with-grace", "url": "", "text": "be obsessed with the problem don't be obsessed with the solution… make sure that you're always thinking about your end user at the end of the day and be obsessed with solving their problems and not obsessed with the the current form factor for the way that you're solving those problems", "paraphrase": "", "source_id": "talk-venture-with-grace", "date": "2025-12-05", "register": "B", "prompted": "P", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Be obsessed with the problem, not the solution — applies to founders and community builders alike", "highlight": false, "also_supports": [], "corpus_ref": "talk-venture-with-grace", "private": false}, {"id": "S14.005", "cluster": "S14", "_hub": "SR:S14:podcast:talk-roan-weigert", "hub": "SR:S14:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "Everything we do is so intentional. That's the word I like to use is intentional, right? Even down to like the smallest little things with the name tags and having icebreakers on the name tags to how we form the different volunteer discussion groups. There is so much thought that goes into every aspect of it because I genuinely believe that most events are not fully thought through. They're not intentional and that little bit of intentionality by the organizers goes such a long way.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S14.022", "cluster": "S14", "_hub": "SR:S14:podcast:talk-tjstar-keynote", "hub": "SR:S14:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "finding success and fulfillment and happiness for myself is one thing, but helping other people find it. Helping the people around me find happiness, success, meaning in their life, that's so much more important.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Helping others find happiness, success, and meaning matters more than personal success — giving is the metric", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S14.021", "cluster": "S14", "_hub": "SR:S14:press:press-businesswire-launch", "hub": "SR:S14:press:press-businesswire-launch", "category": "press", "catColor": "#ff9d4c", "source_key": "press-businesswire-launch", "url": "", "text": "collaboratively shape a future where AI genuinely enhances human flourishing, not just surpasses human capability", "paraphrase": "", "source_id": "press-businesswire-launch", "date": "2025-06-05", "register": "E", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The goal is AI that enhances human flourishing, not merely surpasses human capability", "highlight": false, "also_supports": [], "corpus_ref": "press-businesswire-launch", "private": false}, {"id": "S1.000", "cluster": "S1", "_hub": "SR:S1:tweet:x-com", "hub": "SR:S1:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I have been calling this 'civic middleware' because that is genuinely what it feels like we need more of: connective tissue between labs, policymakers, builders, and everyone else whose life is going to be shaped by AI.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-28", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S1.001", "cluster": "S1", "_hub": "SR:S1:tweet:x-com", "hub": "SR:S1:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "some of the most valuable infrastructure in this era won't be code – it'll be people and society!!", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-07-09", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S1.002", "cluster": "S1", "_hub": "SR:S1:tweet:x-com", "hub": "SR:S1:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "In an age of exponential change, our most vital asset is our connection to each other...We are the human side of AI! 🧠", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2025-07-16", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S1.004", "cluster": "S1", "_hub": "SR:S1:tweet:x-com", "hub": "SR:S1:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "That resonated because it mapped onto my own life. Over the past few years, I've shifted a lot of energy from purely technical skills like programming toward more human ones like community building", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-05-15", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S1.006", "cluster": "S1", "_hub": "SR:S1:tweet:x-com", "hub": "SR:S1:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The power of AI lies not just in the technology but in the people shaping its story.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-01-02", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S1.007", "cluster": "S1", "_hub": "SR:S1:tweet:x-com", "hub": "SR:S1:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "This is the human side of AI – moving beyond hype and into practical, daily empowerment.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2025-07-19", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S1.017", "cluster": "S1", "_hub": "SR:S1:tweet:x-com", "hub": "SR:S1:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Three years later: 200,000+ members, 150+ chapters, all over the world. A genuine human layer for the AI era … The work of building that human layer has never mattered more.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-04-01", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The AI Collective is a genuine human layer for the AI era; building that layer has never mattered more as AI stress-tests the systems humanity relies on", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S1.018", "cluster": "S1", "_hub": "SR:S1:tweet:x-com", "hub": "SR:S1:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "We are ~still~ so early. AI is reshaping our world faster than any force in history … We're less than 1% of the way there!", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-04-01", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "We are less than 1% of the way to building the human layer needed for the AI era", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S1.019", "cluster": "S1", "_hub": "SR:S1:tweet:x-com", "hub": "SR:S1:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "That's human privilege: access to trusted, high-context, high-agency humans becomes one of the scarce goods of the AI age. AI automates task-work. The human layer becomes the point!", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-05-15", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Access to trusted, high-context, high-agency humans is the scarce good of the AI age — the human layer becomes the point", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S1.020", "cluster": "S1", "_hub": "SR:S1:tweet:x-com", "hub": "SR:S1:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "build the human layer for the AI era. Create the spaces where the people building this technology and the people affected by it could actually talk to each other.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-02-20", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The founding vision for AIC is to build the human layer for the AI era", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S1.008", "cluster": "S1", "_hub": "SR:S1:blog:booknotes-ai-futures", "hub": "SR:S1:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Higher share of corporate revenue to owners of machines, not workers (capital vs labor / bits vs atoms)", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Tech has increased wealth disparity: higher share of revenue goes to owners of machines, not workers — capital vs labor, bits vs atoms", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S1.009", "cluster": "S1", "_hub": "SR:S1:blog:booknotes-ai-futures", "hub": "SR:S1:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "Superstar theory: Digital economy benefits superstars over everyone else (web: distributability, demand for best)", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Superstar theory: the digital economy benefits superstars over everyone else via distributability and demand for the best", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S1.010", "cluster": "S1", "_hub": "SR:S1:blog:booknotes-ai-futures", "hub": "SR:S1:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "UBI can likely be used as alternative to work as AI water level keeps rising - theory for viable human jobs (as long as cheaper)", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "UBI can likely serve as an alternative to work as AI raises the water level — a viable theory for human jobs", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S1.012", "cluster": "S1", "_hub": "SR:S1:blog:essay-human-side-of-ai", "hub": "SR:S1:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "The heart of AI innovation isn't found in code – it's found in conversation.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The heart of AI innovation isn't code — it's human conversation", "highlight": false, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S1.013", "cluster": "S1", "_hub": "SR:S1:blog:essay-human-side-of-ai", "hub": "SR:S1:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "As AI evolves, it challenges us to reflect on what defines us as human.' (essay-human-side-of-ai); 'The power to shape the future lies in the connections we forge now.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "As AI evolves it challenges us to reflect on what defines us as human — the power to shape the future lies in the connections we forge now", "highlight": false, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S1.003", "cluster": "S1", "_hub": "SR:S1:blog:essay-self-improving-ai-stack", "hub": "SR:S1:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "neither agent nor human has to curate by hand' and humans 'detecting failures, building validation gates, and setting reward structures to prevent gaming.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S1.011", "cluster": "S1", "_hub": "SR:S1:blog:booknotes-community", "hub": "SR:S1:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "The consequences are measurable — lower trust, worse health outcomes, weaker democracy", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The erosion of social capital produces lower trust, worse health outcomes, and weakened democracy — and rebuilding it is the human-layer imperative", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S1.014", "cluster": "S1", "_hub": "SR:S1:blog:essay-personal-site", "hub": "SR:S1:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "the Collective was where the real conversations were happening – not just about what to build, but about what all of this means. I chose the mission.", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The AI era demands building social infrastructure — not just for what to build, but for what it all means", "highlight": false, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S1.015", "cluster": "S1", "_hub": "SR:S1:blog:notion-manifesto-whitepapers", "hub": "SR:S1:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "New mission: We build the social infrastructure for humanity to come together, build trust, and navigate the rapid acceleration of AI.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The AIC mission reframe: build the social infrastructure for humanity to come together, build trust, and navigate the rapid acceleration of AI", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S1.005", "cluster": "S1", "_hub": "SR:S1:podcast:talk-aic-why-video", "hub": "SR:S1:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "when there's uncertainty, we have to have trust in each other. We have to have trust in the systems around us. uh we have to have a bit of faith even that everybody around us is going to be making the right moves and in unison.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S1.016", "cluster": "S1", "_hub": "SR:S1:podcast:talk-tjstar-keynote", "hub": "SR:S1:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "we have to really think about the human side of AI.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The human side of AI is what matters most — building the human layer is the mission", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S21.000", "cluster": "S21", "_hub": "SR:S21:blog:essay-apple-way", "hub": "SR:S21:blog:essay-apple-way", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-apple-way", "url": "", "text": "Design must be on top of engineering. Jointly, design and engineering form a cavalry. Engineering are the workhorses — the agents for realization. While design are the riders, the workhorses ultimately have complete autonomy and final say. Thus, the only way to enforce healthy dialogue is to position design above engineering.", "paraphrase": "", "source_id": "essay-apple-way", "date": "2023", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-apple-way", "private": false}, {"id": "S21.005", "cluster": "S21", "_hub": "SR:S21:blog:essay-apple-way", "hub": "SR:S21:blog:essay-apple-way", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-apple-way", "url": "", "text": "The Vision Pro software team has no product managers. Instead, product is a collaborative task shared by the design, engineering, and program management teams.", "paraphrase": "", "source_id": "essay-apple-way", "date": "2023", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-apple-way", "private": false}, {"id": "S21.008", "cluster": "S21", "_hub": "SR:S21:blog:essay-apple-way", "hub": "SR:S21:blog:essay-apple-way", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-apple-way", "url": "", "text": "The Apple Vision Pro will define a new paradigm in computing.", "paraphrase": "", "source_id": "essay-apple-way", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Apple Vision Pro will define a new paradigm in computing", "highlight": false, "also_supports": [], "corpus_ref": "essay-apple-way", "private": false}, {"id": "S21.009", "cluster": "S21", "_hub": "SR:S21:blog:essay-apple-way", "hub": "SR:S21:blog:essay-apple-way", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-apple-way", "url": "", "text": "there is a particular modus operandi — 'the Apple way' — permeating the entire company. Below are four elements of this culture which I believe have been pivotal in elevating Apple to its zenith of innovation and value.", "paraphrase": "", "source_id": "essay-apple-way", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "There is a distinct Apple modus operandi — \"the Apple way\" — that permeates the entire company and is pivotal to its innovation dominance", "highlight": false, "also_supports": [], "corpus_ref": "essay-apple-way", "private": false}, {"id": "S21.010", "cluster": "S21", "_hub": "SR:S21:blog:essay-apple-way", "hub": "SR:S21:blog:essay-apple-way", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-apple-way", "url": "", "text": "Apple is organized functionally, concentrating design under a single roof rather than fracturing based on product category. This is what ensures the inimitable cohesion across all hardware and software that Apple is famous for.", "paraphrase": "", "source_id": "essay-apple-way", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Apple's functional org design — concentrating design under a single roof — ensures the cohesion across all hardware and software that Apple is famous for", "highlight": false, "also_supports": [], "corpus_ref": "essay-apple-way", "private": false}, {"id": "S21.011", "cluster": "S21", "_hub": "SR:S21:blog:essay-apple-way", "hub": "SR:S21:blog:essay-apple-way", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-apple-way", "url": "", "text": "Companies which attempt to place engineering and design on equal footing end up with engineering-dominated products once push comes to shove. Need proof? Look at Amazon or Microsoft.", "paraphrase": "", "source_id": "essay-apple-way", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Companies that place engineering and design on equal footing end up with engineering-dominated products; Amazon and Microsoft are proof", "highlight": false, "also_supports": [], "corpus_ref": "essay-apple-way", "private": false}, {"id": "S21.012", "cluster": "S21", "_hub": "SR:S21:blog:essay-apple-way", "hub": "SR:S21:blog:essay-apple-way", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-apple-way", "url": "", "text": "The best ideas come from those with the dirtiest hands. Rather than relegating product roadmaps to senior leadership, Apple empowers its cavalry of over 20,000 to define its future.", "paraphrase": "", "source_id": "essay-apple-way", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The best ideas come from those with the dirtiest hands — not senior leadership — and should define the product roadmap", "highlight": false, "also_supports": [], "corpus_ref": "essay-apple-way", "private": false}, {"id": "S21.013", "cluster": "S21", "_hub": "SR:S21:blog:essay-apple-way", "hub": "SR:S21:blog:essay-apple-way", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-apple-way", "url": "", "text": "particularly as an individual contributor, prototypes are a potent conduit for action. Ultimately, the best idea demonstrated well wins out.", "paraphrase": "", "source_id": "essay-apple-way", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Prototypes are a potent conduit for action; the best idea demonstrated well wins", "highlight": false, "also_supports": [], "corpus_ref": "essay-apple-way", "private": false}, {"id": "S21.014", "cluster": "S21", "_hub": "SR:S21:blog:essay-apple-way", "hub": "SR:S21:blog:essay-apple-way", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-apple-way", "url": "", "text": "This is the magic of Apple's demo culture, institutionalized.", "paraphrase": "", "source_id": "essay-apple-way", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Demo culture — institutionalized through annual hackathons where top projects reach executives — is what makes Apple's bottom-up innovation work", "highlight": false, "also_supports": [], "corpus_ref": "essay-apple-way", "private": false}, {"id": "S21.015", "cluster": "S21", "_hub": "SR:S21:blog:essay-apple-way", "hub": "SR:S21:blog:essay-apple-way", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-apple-way", "url": "", "text": "While intra-company secrecy risks misalignment and duplicated efforts — when properly habituated and enforced — its benefits far outweigh the costs. Great care is taken to keep everything Apple does for the right internal eyes only. A key point of pride and ultimately cultural identity, this cultist mantra extends from within the company to without and has led to the world's strongest and most admired brand image.", "paraphrase": "", "source_id": "essay-apple-way", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Intra-company secrecy, when properly habituated and enforced, has benefits that far outweigh the costs; it is a cultural identity and source of brand strength", "highlight": false, "also_supports": [], "corpus_ref": "essay-apple-way", "private": false}, {"id": "S21.016", "cluster": "S21", "_hub": "SR:S21:blog:essay-apple-way", "hub": "SR:S21:blog:essay-apple-way", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-apple-way", "url": "", "text": "Few companies can claim to have entire news outlets dedicated to tracking their every move.", "paraphrase": "", "source_id": "essay-apple-way", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Few companies can claim to have entire news outlets dedicated to tracking their every move — Apple's secrecy-driven brand mystique is unmatched", "highlight": false, "also_supports": [], "corpus_ref": "essay-apple-way", "private": false}, {"id": "S21.017", "cluster": "S21", "_hub": "SR:S21:blog:essay-apple-way", "hub": "SR:S21:blog:essay-apple-way", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-apple-way", "url": "", "text": "Wagering an outsider's guess, the Vision Pro product category will not turn a profit for Apple this decade. With billions of dollars spent in research and development and a niche initial market, the climb to profitability will be a slow one. What allows Apple to operate on time horizons matched by no other company is their single profit and loss center model.", "paraphrase": "", "source_id": "essay-apple-way", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Apple can operate on long time horizons matched by no other company because of its single P&L model — Vision Pro won't turn a profit this decade, and that is fine", "highlight": false, "also_supports": [], "corpus_ref": "essay-apple-way", "private": false}, {"id": "S21.018", "cluster": "S21", "_hub": "SR:S21:blog:essay-apple-way", "hub": "SR:S21:blog:essay-apple-way", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-apple-way", "url": "", "text": "As an AR/VR engineer working on VisionOS for the past two years and experiencing firsthand the breathtaking magic that is the VisionOS spatial computing platform, I can say this with the utmost confidence.", "paraphrase": "", "source_id": "essay-apple-way", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The Vision Pro experience — the breathtaking magic of VisionOS spatial computing — is what Chappy worked on for two years and can attest to with confidence", "highlight": false, "also_supports": [], "corpus_ref": "essay-apple-way", "private": false}, {"id": "S21.006", "cluster": "S21", "_hub": "SR:S21:blog:essay-chatgpt-ios-app", "hub": "SR:S21:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "On their own, LLMs don't make for excellent app developers, but they can and will be transformed into one.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S21.007", "cluster": "S21", "_hub": "SR:S21:blog:essay-chatgpt-ios-app", "hub": "SR:S21:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "Prompt engineering seeks to align an LLM's goals with the user's by attaching the full context, set of assumptions, and hints at desired outcome in the prompt.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S21.019", "cluster": "S21", "_hub": "SR:S21:blog:essay-chatgpt-ios-app", "hub": "SR:S21:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "Generative AI is a disruptive innovation that has the potential to reshape entire industries in the years to come.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Generative AI is a disruptive innovation with potential to reshape entire industries", "highlight": false, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S21.020", "cluster": "S21", "_hub": "SR:S21:blog:essay-chatgpt-ios-app", "hub": "SR:S21:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "There is a virtually limitless range of opportunities for tailored suites of input modules, output modules, and fine tuned, pruned models to be applied to specific verticals. This is what will transform LLMs from mere shortcuts into a revolutionary new set of tools.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Tailored suites of input modules, output modules, and fine-tuned pruned models applied to specific verticals will transform LLMs from mere shortcuts into revolutionary tools", "highlight": false, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S21.021", "cluster": "S21", "_hub": "SR:S21:blog:essay-chatgpt-ios-app", "hub": "SR:S21:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "I like to think of the components of this provided context as input modules. These are both 1) supplementary inputs and 2) modifications to the user's input that optimize for goal alignment.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Input modules — supplementary inputs and modifications to user input — optimize for goal alignment", "highlight": false, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S21.022", "cluster": "S21", "_hub": "SR:S21:blog:essay-chatgpt-ios-app", "hub": "SR:S21:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "the validation and post-processing of LLM output can be thought of as output modules. As described above, I played the part of a manual output validator but it is clear to see how this process can be automated.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Output modules — validation and post-processing of LLM output — are a key architectural primitive that can be automated", "highlight": false, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S21.023", "cluster": "S21", "_hub": "SR:S21:blog:essay-chatgpt-ios-app", "hub": "SR:S21:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "Providing context when having ChatGPT iterate on a complex codebase such as the RedditGPT app is critical. Without this, ChatGPT often suggested code which conflicted with the rest of the project and failed to compile.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Providing context when iterating on a complex codebase with ChatGPT is critical; without it, generated code conflicts and fails to compile", "highlight": false, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S21.024", "cluster": "S21", "_hub": "SR:S21:blog:essay-chatgpt-ios-app", "hub": "SR:S21:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "Applications built on top of LLMs can overcome this by fine tuning — training the model with additional domain-specific dataset to improve the quality, speed, and consistency of results.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Fine-tuning on domain-specific data is how applications built on LLMs overcome the generality-versus-precision tradeoff", "highlight": false, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S21.002", "cluster": "S21", "_hub": "SR:S21:blog:essay-top-10-reads-2024", "hub": "SR:S21:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "This became my go-to resource on creativity because it backs up grand ideas with concrete research, demonstrating that 'being creative' isn't about a flash of genius but about reworking what we already know.", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S21.003", "cluster": "S21", "_hub": "SR:S21:blog:essay-top-10-reads-2024", "hub": "SR:S21:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "I still return to Eagleman's framework as my North Star for thinking about innovation.", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S21.025", "cluster": "S21", "_hub": "SR:S21:blog:essay-nerd-to-bodybuilder", "hub": "SR:S21:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "I have been enthralled by computers and programming for as long as I can remember. Spending entire weekends squirreled away in my room, I taught myself how to write iOS applications, tinkered with Arduinos and bread board circuits, built custom computers, and reverse engineered electronic toys.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He has been enthralled by computers and programming for as long as he can remember — it is his foundational identity", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S21.026", "cluster": "S21", "_hub": "SR:S21:blog:essay-nerd-to-bodybuilder", "hub": "SR:S21:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "Programming new features for my app impelled me to test them during a workout while weightlifting itself in return provided the insights and impetus for yet more new feature ideas.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Programming new app features impelled him to test them at the gym; the gym gave him ideas for new features — a mutually reinforcing loop between building and using", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S21.004", "cluster": "S21", "_hub": "SR:S21:tweet:x-com", "hub": "SR:S21:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "exercise is ~still~ criminally underrated as the ultimate productivity multiplier. Especially in the heart of SF's early stage ecosystem where founders routinely put in 80-hour weeks, there's always room for a healthier balance!", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2024-10-14", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S21.033", "cluster": "S21", "_hub": "SR:S21:tweet:x-com", "hub": "SR:S21:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "This is truly a new era of computing – it is the most advanced personal electronics device ever created.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2023-06-05", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Apple Vision Pro represents a genuinely new era of computing — the most ambitious product Apple has shipped in over a decade", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S21.034", "cluster": "S21", "_hub": "SR:S21:tweet:x-com", "hub": "SR:S21:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I got a front row seat to the most advanced AR/VR and AI/ML systems in the world. Much of the work I was involved in won't see the light of day for years to come, but that's the very best part!", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2023-10-19", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "His Apple years gave him a front-row seat to the world's most advanced AR/VR and AI/ML systems, and much of that work won't surface for years", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S21.035", "cluster": "S21", "_hub": "SR:S21:tweet:x-com", "hub": "SR:S21:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "any sufficiently advanced technology is indistinguishable from magic. It would be an honor and a privilege to work at Apple and be an apprentice amongst the wizards.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2023-10-19", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The best engineering culture treats technology as magic and builders as apprentice wizards", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S21.036", "cluster": "S21", "_hub": "SR:S21:tweet:x-com", "hub": "SR:S21:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Massive props to Claude Code for being an incredible pair-programming partner on this 🤓", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-02-27", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Claude Code is a great pair-programming partner; builder identity includes leveraging the best AI tools available", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S21.037", "cluster": "S21", "_hub": "SR:S21:tweet:x-com", "hub": "SR:S21:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "First time around these were interesting ideas. This time I turned them on myself. Very different experience 😅", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-04-14", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Re-reading Zero to One while actually building reveals what the frameworks really cost; the Thiel 7 questions hit differently when you turn them on your own company", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S21.038", "cluster": "S21", "_hub": "SR:S21:tweet:x-com", "hub": "SR:S21:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Grand visions all skip the hard work of shrinking the problem space … The trap was too much freedom, too much money, too many directions, and too little pressure to choose the first constraint.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-13", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Grand visions are dangerous if they skip the hard work of shrinking the problem space; General Magic's trap was too much freedom, money, and direction with too little pressure to choose the first constraint", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S21.039", "cluster": "S21", "_hub": "SR:S21:tweet:x-com", "hub": "SR:S21:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The vision is the easy part. The real work is finding the smallest box where the big idea can prove itself.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-13", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The real work is finding the smallest box where a big idea can prove itself; the vision is easy, earning the first wedge is hard", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S21.001", "cluster": "S21", "_hub": "SR:S21:podcast:talk-venture-with-grace", "hub": "SR:S21:podcast:talk-venture-with-grace", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-venture-with-grace", "url": "", "text": "My quick background is I've always been a software nerd. I made my parents buy me a book on C++ and taught myself how to code back when I was 12 and got really into building iOS apps cuz the iPhone had just come out back then.", "paraphrase": "", "source_id": "talk-venture-with-grace", "date": "2025-12-05", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-venture-with-grace", "private": false}, {"id": "S21.032", "cluster": "S21", "_hub": "SR:S21:podcast:talk-venture-with-grace", "hub": "SR:S21:podcast:talk-venture-with-grace", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-venture-with-grace", "url": "", "text": "I was on the vision pro team and on the Apple intelligence team and um through that again to kind of deepen my fascination with AI", "paraphrase": "", "source_id": "talk-venture-with-grace", "date": "2025-12-05", "register": "B", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Apple Vision Pro + Apple Intelligence work shaped his AI-era perspective", "highlight": false, "also_supports": [], "corpus_ref": "talk-venture-with-grace", "private": false}, {"id": "S21.028", "cluster": "S21", "_hub": "SR:S21:podcast:talk-roam-remote-work", "hub": "SR:S21:podcast:talk-roam-remote-work", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roam-remote-work", "url": "", "text": "I have always been a builder. That's the number one thing I'll say about myself", "paraphrase": "", "source_id": "talk-roam-remote-work", "date": "2026-02-02", "register": "B", "prompted": "P", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Being a builder is the core of his identity", "highlight": false, "also_supports": [], "corpus_ref": "talk-roam-remote-work", "private": false}, {"id": "S21.029", "cluster": "S21", "_hub": "SR:S21:podcast:talk-roam-remote-work", "hub": "SR:S21:podcast:talk-roam-remote-work", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roam-remote-work", "url": "", "text": "back when I was 12 made my parents buy me a book on plus and taught myself how to code and ended up building iOS apps", "paraphrase": "", "source_id": "talk-roam-remote-work", "date": "2026-02-02", "register": "B", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Self-teaching and hands-on building from childhood is formative", "highlight": false, "also_supports": [], "corpus_ref": "talk-roam-remote-work", "private": false}, {"id": "S21.030", "cluster": "S21", "_hub": "SR:S21:podcast:talk-roan-weigert", "hub": "SR:S21:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "I got to see how the biggest company in the world tackles the biggest new technological opportunity in the world. And that was just absolutely fascinating.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Apple gave him a direct view of how the world's biggest company attacks the world's biggest technological opportunity", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S21.031", "cluster": "S21", "_hub": "SR:S21:podcast:talk-roan-weigert", "hub": "SR:S21:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "I found that things were moving faster outside and I decided then that I wanted to go be a part of where I thought the technology, the innovation was moving fastest, which is in the earliest stages.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "He left Apple because innovation was moving faster outside — toward the earliest stages", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S21.027", "cluster": "S21", "_hub": "SR:S21:podcast:talk-aic-why-video", "hub": "SR:S21:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "We even built a custom script to assign groups for every single person that was at the event to make sure they were meeting as many new people as possible. And that's something we carry forward that that sort of attention to detail, something we carry forward with us to today.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Founding the Geni Collective was shaped by a persistent attention to community craft detail — building a custom group-assignment script for a single event is the kind of care they carry forward", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S3.000", "cluster": "S3", "_hub": "SR:S3:blog:essay-nerd-to-bodybuilder", "hub": "SR:S3:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "Rather than striving to be the best at one specific thing, it is both more effective and efficient to become very good (say, top quartile) at a composite set of skills.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S3.003", "cluster": "S3", "_hub": "SR:S3:blog:essay-nerd-to-bodybuilder", "hub": "SR:S3:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "Big innovation most often happens when an outsider who may be far away from the surface of the problem reframes the problem in a way that unlocks the solution.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S3.009", "cluster": "S3", "_hub": "SR:S3:blog:essay-nerd-to-bodybuilder", "hub": "SR:S3:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "Embracing paradoxical passions leads to the formation of the most profoundly unique identities.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Embracing paradoxical passions leads to the formation of the most profoundly unique identities — the edge comes from non-obvious combinations", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S3.010", "cluster": "S3", "_hub": "SR:S3:blog:essay-nerd-to-bodybuilder", "hub": "SR:S3:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "I will likely never become the most prolific programmer or most successful bodybuilder but combining the two may lead to a more distinctive outcome.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He will never be the most prolific programmer or most successful bodybuilder — but combining the two may lead to a more distinctive outcome than optimizing one singular skill", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S3.001", "cluster": "S3", "_hub": "SR:S3:blog:booknotes-community", "hub": "SR:S3:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Membership identity: Values: who am I / Rituals: how should I act / Core beliefs: what do I believe", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S3.006", "cluster": "S3", "_hub": "SR:S3:blog:booknotes-community", "hub": "SR:S3:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "More to make insiders feel safe (shared values) / Must have 1+ values, be exclusionary in some way", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Boundaries make insiders feel safe more than they keep outsiders out — every community must have at least one value and be exclusionary in some way", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S3.007", "cluster": "S3", "_hub": "SR:S3:blog:booknotes-community", "hub": "SR:S3:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Democratization of media and communication eliminates mass culture / More social enclaves, 'age category ghettos,' and lifestyle specialization", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Mass culture fractures into subcults and over-choice — democratization of media eliminates mass culture, forcing community design to be niche and values-based", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S3.002", "cluster": "S3", "_hub": "SR:S3:blog:essay-top-10-reads-2024", "hub": "SR:S3:blog:essay-top-10-reads-2024", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-top-10-reads-2024", "url": "", "text": "platforms' ad-driven motives clash with users' best interests, since maximizing ad engagement doesn't always align with meaningful or healthy online experiences. This structural misalignment makes the entire system feel even more vulnerable.", "paraphrase": "", "source_id": "essay-top-10-reads-2024", "date": "2024-12-30", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-top-10-reads-2024", "private": false}, {"id": "S3.008", "cluster": "S3", "_hub": "SR:S3:blog:essay-gai-collective-curiosity", "hub": "SR:S3:blog:essay-gai-collective-curiosity", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-gai-collective-curiosity", "url": "", "text": "Learning is most effective through thoughtful and welcoming discussion in an environment full of diverse perspectives. Seek think tanks, not echo chambers.' (notion-rec-essay-gai-collective-curiosity)", "paraphrase": "", "source_id": "essay-gai-collective-curiosity", "date": "2023-04-12", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Learning is most effective in environments with diverse perspectives — seek think tanks, not echo chambers", "highlight": false, "also_supports": [], "corpus_ref": "essay-gai-collective-curiosity", "private": false}, {"id": "S3.004", "cluster": "S3", "_hub": "SR:S3:tweet:x-com", "hub": "SR:S3:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "LLMs are incredible average-generating machines. That's part of what makes them useful. They compress the internet, surface the consensus, and give everyone a baseline level of intelligence on demand. As more people outsource more of their thinking to the same systems, the advantage shifts.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-15", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S3.005", "cluster": "S3", "_hub": "SR:S3:tweet:x-com", "hub": "SR:S3:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The edge moves toward people who spend time in rooms with original thinkers, weird builders, deep operators, and non-consensus perspectives … The scarce thing becomes better questions, better taste, and better rooms.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-15", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S3.011", "cluster": "S3", "_hub": "SR:S3:podcast:talk-tjstar-keynote", "hub": "SR:S3:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "I lean into my obsessions. I'm obsessed with AI, with community, with weightlifting. I lean into those things. And I am a very spiky person.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Being spiky — leaning hard into specific obsessions — is the edge over algorithmic homogenization", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S22.002", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "exercise is ~still~ criminally underrated as the ultimate productivity multiplier. Especially in the heart of SF's early stage ecosystem where founders routinely put in 80-hour weeks, there's always room for a healthier balance!", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2024-10-14", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S22.005", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Share more of what you're working on. Building in public – whether it's code, fitness, writing, whatever – is one of the best accountability mechanisms out there. And you never know who it resonates with!", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-02-27", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S22.006", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I put 8.5 years of training data into one chart. Every workout. Every set. 45,000+ data points – all from an app I originally built in high school.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-02-27", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S22.007", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "20 weeks and ~20 lbs out from my next targeted bodybuilding show in July! 💪😤 … Progress is going well though five weeks in – from 214+ to under 206 during this morning's weigh-in.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-02-23", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S22.023", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "High-level competitive sports such as bodybuilding involves A TON of sacrifice – much more than I had originally appreciated.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2024-01-02", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Competitive bodybuilding is a serious discipline that demands sacrifice and teaches embodied self-knowledge", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S22.024", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Between tendon pain that I'd ignored for years and an intensity-first mindset, my approach had become unsustainable.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-01-02", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Overtraining accumulates invisibly until it breaks you; sustainable balance beats intensity-first", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S22.025", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "One habit that truly brought me joy in 2024 was training with friends. This year, I lifted in 20+ gyms with 20+ friends across the US – both massive PRs! Sharing this passion with others has made lifting more rewarding than ever!", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-01-02", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Training with friends is a multiplier on lifting joy and accountability", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S22.026", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I lean 996 (and tbh, closer to 7/7/7 😅)", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-11-11", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Work intensity at near-996 / 7-7-7 is his natural default alongside competitive bodybuilding — both coexist in his identity", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S22.027", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I started cutting for a natural bodybuilding competition, my hormones shifted, and I started waking up at 4am, 3am, sometimes 2am – completely wired. Instead of fighting it, I built a system around it!", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-03-12", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "His extreme early-rising habit originated from bodybuilding prep shifting his hormones; he chose to build a system around the disruption rather than fight it", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S22.028", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "In an attempt to fix my quad / hamstring muscle imbalance I've been getting back into deadlifts. Just hit 505+ lbs for the first time in 3+ years yesterday! 🏋️‍♂️", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-02-23", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "After a multi-year injury stretch he is back lifting heavy — 505+ lb deadlift for the first time in 3+ years, fixing a quad/hamstring imbalance", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S22.029", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Looking at my aggregate PRs, this was my best season since '21–'22, finishing 60+ lbs above my trendline target. Basically, two years of progress in one. I'm now within 300 lbs (4.1%) of my estimated lifetime peak!", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2025-04-06", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He peaked at 223.4 lbs in the 2025 bulk — his best season since 2021-22, finishing 60+ lbs above trendline with 22 PRs", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S22.030", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I'd only need to add ~4.5 lbs to my bench @ 225 lbs to justify a further bulk. For example, a 492 lb 1RM @ 223.4 has the same Wilks score as 511 lbs @ 250. So… maybe I should bulk to 250 next year? 😝🤔", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2025-04-06", "register": "D", "prompted": "U", "signal_strength": 0.42, "strength01": 0.42, "influence_1to10": 4, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He competes as a natural bodybuilder and tracks Wilks-normalized strength — considers bulking to 250 lbs for a higher score", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S22.031", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Most importantly, I'm just really happy to feel healthy, strong, and truly back after a challenging 2.5 years post-competition. Odds of competing again this year are still under 10%, but I'm not closing the door!", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2025-04-06", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Post-competition recovery across 2.5 challenging years — odds of competing again this year under 10% but the door isn't closed", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S22.032", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I definitely prefer lifting with people around me. What I give up in shirtless posing, I get back and more in the form of mogging and massive adrenaline rushes!", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2025-08-24", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Lifting with people around dramatically increases workout intensity — community applies to the gym too", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S22.033", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Since all stress is a tradeoff, tbh I'm not super optimistic I'll make it all the way down without having to cut myself off like last time. Currently, I'm giving myself a 10-20% chance.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-02-23", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Competing as a natural bodybuilder while running a high-growth org means all stress is a tradeoff — the chance of success is explicitly managed", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S22.034", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "life is only going to get more intense from here so I'm mentally preparing for this to be my last realistic chance to compete before switching to powerlifting.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-02-23", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Competitive bodybuilding window is closing as professional intensity grows; mentally preparing to pivot to powerlifting", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S22.035", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I have more discipline and willpower than ever before", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-02-23", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Discipline and willpower have compounded over 8+ years of bodybuilding; data-driven tracking (40,000+ sets) is core to the approach", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S22.036", "cluster": "S22", "_hub": "SR:S22:tweet:x-com", "hub": "SR:S22:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Make exercise your first major activity of the morning! This has worked wonders for my consistency – even during weeks of peak work intensity.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2024-10-14", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Making exercise the first major activity of the morning is the key to consistency even during peak work intensity", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S22.000", "cluster": "S22", "_hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "This synergistic relationship between weightlifting and app development remains the key driver of my passion and perseverance.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S22.001", "cluster": "S22", "_hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "I weighed in every morning, meticulously logged every single meal, and worked out for 45 days straight.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S22.008", "cluster": "S22", "_hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "Performing at a bodybuilding competition almost naked in front of a mass of ogling strangers was the culmination of a five-year journey. Once terrified at the mere thought of presenting a powerpoint in front of a small class, it hit me: how did I get here?", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Performing at a bodybuilding competition was the culmination of a five-year journey of identity expansion that started from a shy, comfort-zone-fearing nerd", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S22.009", "cluster": "S22", "_hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "I set out on a path which I hoped would lead me to break out of my comfort zone, explore my physical and mental limits, and finally develop a more well-rounded identity.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "His original motivation for weightlifting was to break out of a comfort zone and develop a more well-rounded identity beyond programming", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S22.010", "cluster": "S22", "_hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "Inspired by the novel synergy I discovered between weightlifting and app development, my disposition for technology took over as I programmed a spreadsheet to log and analyze short- and long-term weight trends.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He applied his technical disposition to weight cycling — programming spreadsheets to log and analyze weight trends — turning discipline into a system", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S22.011", "cluster": "S22", "_hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "For four years now I have strategically seesawed an average of over twenty pounds per cycle.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He has strategically bulk/cut cycled an average of over twenty pounds per cycle for four years — discipline applied at scale", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S22.012", "cluster": "S22", "_hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "Only in retrospect did I realize the tiered nature of my commitment to weightlifting.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Commitment to bodybuilding is tiered and progressive — each layer of commitment opens the next; he deliberately chose the hardest echelon", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S22.013", "cluster": "S22", "_hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "Rather than entering with the objective of winning, my intention was to test the waters and determine whether bodybuilding was a passion I wanted to commit to even further.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He entered competition not to win but to test the waters and put years of growth against an objective measuring stick", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S22.014", "cluster": "S22", "_hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "To my immense surprise and joy, I placed second in the Men's Novice Bodybuilding category.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He placed second in Men's Novice Bodybuilding at INBF Battle of the Bay and received feedback he could compete for a pro card", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S22.015", "cluster": "S22", "_hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "Walking triumphantly off stage, I finally had the confidence to grant myself ownership over a new facet of my identity. I am a bodybuilder.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Walking off stage he claimed ownership over a new facet of his identity — \"I am a bodybuilder\" is a self-declaration", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S22.016", "cluster": "S22", "_hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "Building and flexing not only physical muscles but also the hypothetical willpower muscle.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Weightlifting builds a \"hypothetical willpower muscle\" — the physical discipline directly trains mental discipline", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S22.017", "cluster": "S22", "_hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "Weightlifting has a way of indirectly teaching a variety of profoundly important life lessons: Building and flexing not only physical muscles but also the hypothetical willpower muscle.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Weightlifting teaches grit, essentialism, and intense focus — lessons with broad applicability beyond the gym", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S22.018", "cluster": "S22", "_hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "Fostering willpower, practicing the art of essentialism, daring greatly, and embracing my paradoxical passions form a unique foundation for growth as I venture onwards and upwards with insatiable ambition.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Fostering willpower, practicing essentialism, daring greatly, and embracing paradoxical passions form a unique foundation for growth", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S22.019", "cluster": "S22", "_hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "hub": "SR:S22:blog:essay-nerd-to-bodybuilder", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-nerd-to-bodybuilder", "url": "", "text": "While I certainly have my work cut out for me, my motivational flame burns more intensely than ever.", "paraphrase": "", "source_id": "essay-nerd-to-bodybuilder", "date": "2022-12-11", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "His motivational flame burns more intensely after placing — not diminished by partial success; he plans to pursue a pro card", "highlight": false, "also_supports": [], "corpus_ref": "essay-nerd-to-bodybuilder", "private": false}, {"id": "S22.003", "cluster": "S22", "_hub": "SR:S22:blog:essay-personal-site", "hub": "SR:S22:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "I'm a competitive natural bodybuilder (INBF/WNBF) — the discipline keeps me grounded and it's become a whole second identity at this point", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S22.004", "cluster": "S22", "_hub": "SR:S22:blog:essay-personal-site", "hub": "SR:S22:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "I track every set, iterate my programming, and measure what matters – I even built my own app to systematize progress! One reason I love lifting is the objective daily affirmation: I walk in, hit a PR, and know definitely that I'm the best I've ever been!", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S22.020", "cluster": "S22", "_hub": "SR:S22:podcast:talk-tjstar-keynote", "hub": "SR:S22:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "Humans are fundamentally anti-fragile. uh that means that we get better with the right amount of stress with the sweet spot of stress that actually makes us better people.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Humans are fundamentally anti-fragile — they get stronger from the right amount of adversity and failure", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S22.021", "cluster": "S22", "_hub": "SR:S22:podcast:talk-tjstar-keynote", "hub": "SR:S22:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "I am a huge data nerd. I track all my workouts all the way back going back like 10 plus years. I literally went ahead and graphed it and you can see it follows a very nice, very tight logarithmic curve.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "He tracked 10+ years of bodybuilding data and graphed it — his bench max follows a tight logarithmic curve, illustrating logistic growth", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S22.022", "cluster": "S22", "_hub": "SR:S22:podcast:talk-venture-with-grace", "hub": "SR:S22:podcast:talk-venture-with-grace", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-venture-with-grace", "url": "", "text": "Find me in the gym. Find me with my wife.", "paraphrase": "", "source_id": "talk-venture-with-grace", "date": "2025-12-05", "register": "B", "prompted": "P", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Bodybuilding / gym remains his off-work identity alongside family", "highlight": false, "also_supports": [], "corpus_ref": "talk-venture-with-grace", "private": false}, {"id": "S6.000", "cluster": "S6", "_hub": "SR:S6:tweet:x-com", "hub": "SR:S6:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "the gap between what's being built and who gets to see it is one of the most dangerous dynamics in AI right now. When the people shaping policy have never watched a founder demo their product — when the builders have never heard the concerns of the people their tools will affect — everyone loses.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-02-20", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S6.002", "cluster": "S6", "_hub": "SR:S6:tweet:x-com", "hub": "SR:S6:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "some of the most valuable infrastructure in this era won't be code – it'll be people and society!!", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-07-09", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S6.003", "cluster": "S6", "_hub": "SR:S6:tweet:x-com", "hub": "SR:S6:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Data – not compute – is the true bottleneck to U.S. AI leadership. If we don't act fast, we risk losing ground in the global race.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2025-03-26", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S6.004", "cluster": "S6", "_hub": "SR:S6:tweet:x-com", "hub": "SR:S6:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Our recommendations focus on: 1️⃣ Building a federated National Data Store to unlock innovation 2️⃣ Modernizing info architecture with AI-native standards like MCP 3️⃣Creating an AI-ready economy by attracting top talent", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2025-03-26", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S6.005", "cluster": "S6", "_hub": "SR:S6:tweet:x-com", "hub": "SR:S6:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "BIG NEWS: the @GenAICollective is expanding to NYC!! 🗽🤩 Step two of many towards this community's mission to become the worldwide community for AI and technological progress", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2024-03-21", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S6.016", "cluster": "S6", "_hub": "SR:S6:tweet:x-com", "hub": "SR:S6:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I'm BLOWN AWAY by the entrepreneurial energy exuding from everyone I met last night – there's something really special developing here!", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-03-20", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "India — especially Bengaluru — is primed for explosive global AI scene emergence", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S6.017", "cluster": "S6", "_hub": "SR:S6:tweet:x-com", "hub": "SR:S6:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Feels like Hyderabad is primed to explode onto the global AI scene in the next few years", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-03-21", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Hyderabad is primed to explode onto the global AI scene in the next few years", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S6.018", "cluster": "S6", "_hub": "SR:S6:tweet:x-com", "hub": "SR:S6:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Nine AI startups demoed their work to a room full of policymakers, builders, and community members — in a space where conversations about AI usually happen behind closed doors.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-02-20", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI policy conversations happen behind closed doors; the gap must be bridged by putting builders and community members in the same room as policymakers", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S6.019", "cluster": "S6", "_hub": "SR:S6:tweet:x-com", "hub": "SR:S6:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "access vs adoption", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-18", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Access vs adoption is a live tension; making AI accessible, social, and local — everywhere — is mission-critical", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S6.020", "cluster": "S6", "_hub": "SR:S6:tweet:x-com", "hub": "SR:S6:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "AI is moving too quickly for any of us to metabolize alone … Being in a room with other thoughtful people actually helps you process what is happening, build language for it, and decide where you have agency.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-28", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI is moving too quickly for any of us to metabolize alone; distributed, in-person, global sense-making is the answer", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S6.021", "cluster": "S6", "_hub": "SR:S6:tweet:x-com", "hub": "SR:S6:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "India isn't just ready for the AI revolution—it's going to lead it!", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2025-03-25", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "India is not just ready for the AI revolution — it will lead it, specifically at the application layer", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S6.022", "cluster": "S6", "_hub": "SR:S6:tweet:x-com", "hub": "SR:S6:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "My thesis going in was that India would become the global powerhouse for application-level AI. After hundreds of conversations? I'm more than convinced!", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2025-03-25", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "His thesis that India would be the global powerhouse for application-level AI was confirmed after hundreds of in-person conversations", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S6.023", "cluster": "S6", "_hub": "SR:S6:tweet:x-com", "hub": "SR:S6:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "More than policy – it's our belief that the U.S. can and must lead with openness, trust, and prosperity.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2025-03-26", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The U.S. can and must lead AI with openness, trust, and prosperity — this is a values-level belief, not just a policy position", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S6.024", "cluster": "S6", "_hub": "SR:S6:tweet:x-com", "hub": "SR:S6:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Small business and craftspeople are being left behind as startups instead choose to focus on building tech on top of tech. How can we close the adoption gap of sales and marketing best practices?", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2023-08-16", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Non-tech workers and small businesses are being left behind as startups focus on \"tech on top of tech\" — the adoption gap must be closed", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S6.025", "cluster": "S6", "_hub": "SR:S6:tweet:x-com", "hub": "SR:S6:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "A future where work is democratized by agents, empowering a new wave of smaller, more agile companies.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2025-07-19", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI work is being democratized by agents — smaller, more agile companies will be empowered by this", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S6.001", "cluster": "S6", "_hub": "SR:S6:blog:essay-human-side-of-ai", "hub": "SR:S6:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "In diversity lies the true power of collective innovation.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S6.011", "cluster": "S6", "_hub": "SR:S6:blog:essay-human-side-of-ai", "hub": "SR:S6:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "Across the United States, cities are stitching together a patchwork of AI innovation. Los Angeles channels creativity into consumer applications, Boston pushes the frontiers of biotech, Miami thrives on the pulse of crypto, and Chicago anchors itself in finance and legal tech.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "American AI innovation is geographically distributed — each city has a distinct specialization and identity that colors its approach to AI", "highlight": false, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S6.012", "cluster": "S6", "_hub": "SR:S6:blog:essay-human-side-of-ai", "hub": "SR:S6:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "Cities outside San Francisco often admire its fearless innovation and rapid pace but worry about its insularity. They see a bubble that drives progress but risks neglecting the broader tech ecosystem. Understanding these differences is critical – not just to celebrate local strengths but to foster collaboration that transcends boundaries.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Cities outside San Francisco worry about its insularity; they see a bubble that drives progress but risks neglecting the broader tech ecosystem — collaboration across that boundary is critical", "highlight": false, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S6.006", "cluster": "S6", "_hub": "SR:S6:blog:notion-manifesto-whitepapers", "hub": "SR:S6:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Open democracy is the method. Inclusive institutions is the goal.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S6.007", "cluster": "S6", "_hub": "SR:S6:blog:notion-manifesto-whitepapers", "hub": "SR:S6:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "upgrading our institutions requires in-person, real-world convenings – deliberation you can't just 'leave' with an end-call button.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S6.008", "cluster": "S6", "_hub": "SR:S6:blog:essay-americas-ai-ultimatum", "hub": "SR:S6:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "there is no single data protection legislation in the United States. Rather, a jumble of hundreds of laws at both the federal and state levels serve to protect the personal data of U.S. residents.", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "The U.S. needs a coherent federal data privacy framework — the current patchwork of hundreds of state and federal laws is inadequate", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S6.009", "cluster": "S6", "_hub": "SR:S6:blog:essay-americas-ai-ultimatum", "hub": "SR:S6:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "The U.S. should regulate data as a utility' (essay-americas-ai-ultimatum); 'The energy and telecom industries are precedents for data as a utility.", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "Data should be regulated as a utility — energy and telecom precedents provide a workable model", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S6.013", "cluster": "S6", "_hub": "SR:S6:blog:essay-trust-manifesto", "hub": "SR:S6:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "those conditions shouldn't be exclusive. We believe every city, every pioneer, every problem-solver deserves access to that same spark. And we're making it happen.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The conditions for closeness and innovation shouldn't be exclusive to the Bay Area — every city, every pioneer, every problem-solver deserves access to that same spark", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S6.014", "cluster": "S6", "_hub": "SR:S6:blog:essay-trust-manifesto", "hub": "SR:S6:blog:essay-trust-manifesto", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-trust-manifesto", "url": "", "text": "AI wasn't going to be shaped from the top down – it was going to emerge from the people pushing its limits in real time.", "paraphrase": "", "source_id": "essay-trust-manifesto", "date": "2025-04-03", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI is not being shaped from the top down — it is emerging from the people pushing its limits in real time, at the edges", "highlight": false, "also_supports": [], "corpus_ref": "essay-trust-manifesto", "private": false}, {"id": "S6.010", "cluster": "S6", "_hub": "SR:S6:blog:essay-gai-collective-curiosity", "hub": "SR:S6:blog:essay-gai-collective-curiosity", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-gai-collective-curiosity", "url": "", "text": "The GenAI Collective began to grow organically into a community of founders, funders, and thought leaders built around a shared curiosity for generative AI.' (notion-rec-essay-gai-collective-curiosity)", "paraphrase": "", "source_id": "essay-gai-collective-curiosity", "date": "2023-04-12", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The community grew organically into founders, funders, and thought leaders — reflecting a broad coalition, not a narrow in-crowd", "highlight": false, "also_supports": [], "corpus_ref": "essay-gai-collective-curiosity", "private": false}, {"id": "S6.015", "cluster": "S6", "_hub": "SR:S6:podcast:talk-tjstar-keynote", "hub": "SR:S6:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "I firmly believe that the future's already here. It's just unevenly distributed and nowhere is it faster than in San Francisco.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The future is already here but unevenly distributed — San Francisco is the fastest node", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S13.000", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "These five layers are a single read/write cycle", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.001", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "Systems that close this loop compound with every cycle' and 'Everything compounds", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.006", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "I've spent the past month obsessed with one question: how do you build an AI system that gets smarter every time it runs? So I built one.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The self-improving AI stack is the defining infrastructure challenge of the moment — he spent a month obsessively researching how to build an AI that gets smarter every run", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.007", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "I curated 121 sources (63 repos, 13 papers, 24 tweets, 21 articles), deep-researched 51 of them by reading source code and documentation.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He built a self-compiling wiki from 121 sources — a knowledge base about self-improving knowledge bases — as proof of the architecture", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.008", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "The five-layer stack (knowledge, memory, context, skills, self-improvement) is the minimum viable architecture for agents that compound.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The five-layer stack — knowledge, memory, context, skills, self-improvement — is the minimum viable architecture for agents that compound; anything less is already outdated", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.009", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "outputs get evaluated, evaluations rewrite the knowledge base", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "A self-improving system emerges when outputs are evaluated and evaluations rewrite the knowledge base — a recursive loop", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.010", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "Shared context graphs let multiple agents (and humans) read and write to the same evolving knowledge structure. Organizational memory at the scale of entire companies.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Shared context graphs represent organizational memory at the scale of entire companies — agents and humans reading/writing the same evolving knowledge structure", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.011", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "every organization generates...who decided what, when, with what information, and what happened next.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Context graphs capture decision traces — who decided what, when, with what information, and what happened next — as organizational memory", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.012", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "agents stop being stateless tools and become participants in organizational knowledge.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Agents stop being stateless tools and become participants in organizational knowledge once context graphs arrive", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.013", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "In the agent-native ecosystem (coding tools, personal knowledge bases, developer workflows), markdown won.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "In the agent-native ecosystem, markdown won as the dominant storage format — simplicity and inspectability beat complex infrastructure", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.014", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "The bottleneck turned out to be how you organize the knowledge, not which search engine you use", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The bottleneck in knowledge bases is how you organize knowledge, not which retrieval engine you use — organization beats infrastructure", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.015", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "One 313-star repo scores 91% on a standard long-memory benchmark using plain keyword search' and 'small structures beat big infrastructure", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Small structures beat big infrastructure — a 313-star repo using plain keyword search scores 91% on long-memory benchmarks; JSON graph overhead loses inspectability", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.016", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "A 3,000-token compressed topic index...transforms recall", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Agent memory fails on implicit context without a compressed topic index; a 3,000-token topic index loaded into every conversation transforms recall", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.017", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "If a hallucinated 'fact' gets stored as a user preference, every downstream session builds on it.' and 'One bad extraction propagates because the agent doesn't know the memory is wrong, and the user doesn't know the memory exists.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Silent memory poisoning is the critical vulnerability: one hallucinated fact stored as a user preference propagates through every downstream session because neither agent nor user knows the memory is wrong", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.018", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "Structured forgetting matters as much as structured memory.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Structured forgetting matters as much as structured memory — long-running agent systems require validation gates that review memories without knowledge of their origin", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.019", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "Git is infrastructure.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Git is infrastructure for agents — version control enables auditable, inspectable memory that can be traced and rolled back", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.020", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "The same AI model shows up to 6x performance differences based purely on how you organize its input' and '83% fewer input tokens AND better task completion", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Context engineering yields up to 6x performance differences from the same model purely based on how input is organized — fewer tokens, better results", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.021", "cluster": "S13", "_hub": "SR:S13:blog:essay-self-improving-ai-stack", "hub": "SR:S13:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "If you're spending more tokens, you're probably loading the wrong things.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "If you are spending more tokens you are probably loading the wrong things — the correct instinct is ruthless curation, not maximizing context", "highlight": false, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S13.002", "cluster": "S13", "_hub": "SR:S13:blog:essay-personal-site", "hub": "SR:S13:blog:essay-personal-site", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-personal-site", "url": "", "text": "I'm now building collective intelligence infrastructure for AI agents – the technical counterpart to what AIC does for people", "paraphrase": "", "source_id": "essay-personal-site", "date": "2026", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-personal-site", "private": false}, {"id": "S13.003", "cluster": "S13", "_hub": "SR:S13:tweet:x-com", "hub": "SR:S13:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I think this is the right frame. Systems of record tell you what happened. Systems of intelligence tell you what matters now, what changed, who/what is relevant, and what action is worth taking. Been thinking about this a lot recently.", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2026-05-14", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S13.004", "cluster": "S13", "_hub": "SR:S13:tweet:x-com", "hub": "SR:S13:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Agree on 'agent proficiency' as a frame, but it's a literacy. You're managing what an AI knows about you. Few people will maintain a wiki. Agents that build this context layer on autopilot are the thing that scales.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-04-05", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S13.005", "cluster": "S13", "_hub": "SR:S13:tweet:x-com", "hub": "SR:S13:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I wanted to recreate that feeling digitally: a virtual bookshelf I could visit when I'm wrestling with a big decision … Every single note is handwritten … when I'm stuck on a problem, I open the bookshelf, scan my collection, and almost always get reminded of a framework or anecdote that reframes my thinking. It's like having a conversation with every author I've ever read at once!", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-02-23", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S13.023", "cluster": "S13", "_hub": "SR:S13:tweet:x-com", "hub": "SR:S13:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "How timely… 🥷", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2026-04-03", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Using LLMs to build personal knowledge bases is a timely and important direction — directly relevant to his stealth collective-intelligence infrastructure work", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S13.024", "cluster": "S13", "_hub": "SR:S13:tweet:x-com", "hub": "SR:S13:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "All the repos in one place: @mem0ai ~ https://t.co/N2suPH4VcU (51K ⭐) @Claude_Memory ~ https://t.co/EzMwU2Q4Z8 (46K ⭐) Graphiti ~ https://t.co/lhQfSxSc4P (24K ⭐) @Letta_AI ~ https://t.co/gyU7q1N8kd (22K ⭐) @supermemoryai ~ https://t.co/gbpT9yOBAE (21K ⭐)", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-04-07", "register": "D", "prompted": "U", "signal_strength": 0.42, "strength01": 0.42, "influence_1to10": 4, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He actively curates the AI memory infrastructure landscape — tracking the top repos by star count as a signal of where the space is converging", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S13.025", "cluster": "S13", "_hub": "SR:S13:tweet:x-com", "hub": "SR:S13:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "It's like hiring a genius consultant then making them re-read every doc from scratch at every meeting", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-04-06", "register": "D", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Re-loading context at every AI session is inefficient — like making a genius consultant re-read every doc from scratch", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S13.022", "cluster": "S13", "_hub": "SR:S13:podcast:talk-roan-weigert", "hub": "SR:S13:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "I basically have a ChatGPT or Gemini window open at all times and just asking it questions, right? Learning from it. It is so much better at exploring than even I am. So there's compound returns to using these tools, becoming more familiar with these tools and then using that to leverage yourself up even more.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "AI tools (ChatGPT, Gemini) are better at exploring than he is — keeping one open at all times for questions creates compounding returns", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S16.000", "cluster": "S16", "_hub": "SR:S16:tweet:x-com", "hub": "SR:S16:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Love the sentiment but this graphic is really misleading tbh. Only ~50% of the world's 8.3B people are a reasonable age (15-65, with a discount for <15 and 65+) and have online access. For many more people outside our bubble, there's simply little/no need for AI in their daily lives.", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2026-05-13", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S16.001", "cluster": "S16", "_hub": "SR:S16:tweet:x-com", "hub": "SR:S16:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Only ~50% of the world's 8.3B people are a reasonable age (15-65, with a discount for <15 and 65+) and have online access. For many more people outside our bubble, there's simply little/no need for AI in their daily lives.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-05-13", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S16.002", "cluster": "S16", "_hub": "SR:S16:tweet:x-com", "hub": "SR:S16:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Zero' is doing a lot of work here — there are plenty of humans who outsource most of the thinking to AI and just sign off on it.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-04-05", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S16.005", "cluster": "S16", "_hub": "SR:S16:tweet:x-com", "hub": "SR:S16:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "As generative AI crosses the chasm from visionary early adopters to the pragmatist early majority, a primary focus becomes providing clear and compelling end user value in increasingly low-friction ways.", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2023-08-19", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S16.006", "cluster": "S16", "_hub": "SR:S16:tweet:x-com", "hub": "SR:S16:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "While AI poses many near-term risks, we should all carry a sense of pragmatic optimism towards the future of AI!", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2023-08-14", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S16.015", "cluster": "S16", "_hub": "SR:S16:tweet:x-com", "hub": "SR:S16:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Vibe coding feels like 3D printing in 2012. The demos made everyone think we'd all manufacture at home. Turns out people mostly want finished products cheaper, faster, and at scale. 80% magic is amazing. Taste, distribution, and network effects are different.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-12", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Vibe coding is like 3D printing in 2012 — demos made everyone think manufacturing would move home; 80% magic is real but taste, distribution, and network effects are different", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S16.016", "cluster": "S16", "_hub": "SR:S16:tweet:x-com", "hub": "SR:S16:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "What's the ultimate method for reducing friction? Incorporating directly into existing products! Thus, big companies / platform owners like @Google, @Microsoft, @Apple, etc. seem poised to dominate B2C GenAI use cases.", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2023-08-19", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The ultimate friction-reduction method is incorporating AI directly into existing products — which means big platform owners like Google, Microsoft, and Apple are poised to dominate B2C GenAI", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S16.003", "cluster": "S16", "_hub": "SR:S16:blog:essay-chatgpt-ios-app", "hub": "SR:S16:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "As powerful as ChatGPT's generality is, this comes at the cost of precision and performance in narrow, precise use cases such as app development.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S16.004", "cluster": "S16", "_hub": "SR:S16:blog:essay-chatgpt-ios-app", "hub": "SR:S16:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "Despite ChatGPT's glaring shortcomings, the rate of progress in LLM capability and scale over the past couple of years is staggering.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S16.008", "cluster": "S16", "_hub": "SR:S16:blog:essay-chatgpt-ios-app", "hub": "SR:S16:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "We already know that ChatGPT has the coding interview skills to land itself a job at a top tech firm. However, job interviews are a notoriously poor predictor of on-the-job performance.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "ChatGPT has coding interview skills that could land it a job at a top firm, but job interviews are a notoriously poor predictor of on-the-job performance", "highlight": false, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S16.009", "cluster": "S16", "_hub": "SR:S16:blog:essay-human-side-of-ai", "hub": "SR:S16:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "Pundits proclaimed 2024 as the year of agents. But did reality match the hype? The enthusiasm was palpable, and builders rallied. Yet, the year revealed itself as one of infrastructure, not breakthrough applications.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Pundits proclaimed 2024 as the year of agents but reality revealed it as a year of infrastructure, not breakthrough applications — substantive adoption is still on the horizon", "highlight": false, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S16.010", "cluster": "S16", "_hub": "SR:S16:blog:essay-human-side-of-ai", "hub": "SR:S16:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "The city operates in a bubble where audacity and optimism are the norm.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "San Francisco operates in a bubble where audacity and optimism are the norm — but that bubble is not necessarily better than others elsewhere", "highlight": false, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S16.011", "cluster": "S16", "_hub": "SR:S16:podcast:talk-aic-why-video", "hub": "SR:S16:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "That uncertainty is certainly higher than it's ever been before.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Young people graduating today face more career uncertainty than any prior generation, and even Chappy — who is on the frontier — finds it genuinely hard to advise them", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S16.012", "cluster": "S16", "_hub": "SR:S16:podcast:talk-aic-why-video", "hub": "SR:S16:podcast:talk-aic-why-video", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-aic-why-video", "url": "", "text": "hiring for new grads is already down 50% from pre- pandemic. And and I can tell you, speaking for my friends who are just graduating now, it's a really tough environment. And that's happening now, right? We really are in that elbow of the curve.", "paraphrase": "", "source_id": "talk-aic-why-video", "date": "2025", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Big tech is already experiencing a 50% drop in new-grad hiring from pre-pandemic levels — the impact is happening now, not in some future scenario", "highlight": false, "also_supports": [], "corpus_ref": "talk-aic-why-video", "private": false}, {"id": "S16.013", "cluster": "S16", "_hub": "SR:S16:podcast:talk-tjstar-keynote", "hub": "SR:S16:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "90% of all content online, generated online, is going to be AI generated by going into next year. That's going to increase very quickly to 99%.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "90% of all online content will be AI-generated soon — attention economy is increasingly AI-driven", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S16.014", "cluster": "S16", "_hub": "SR:S16:podcast:talk-tjstar-keynote", "hub": "SR:S16:podcast:talk-tjstar-keynote", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-tjstar-keynote", "url": "", "text": "I believe that AI is going to bring us into an incredible age of abundance… it will be almost utopian.", "paraphrase": "", "source_id": "talk-tjstar-keynote", "date": "2025-05-29", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "AI will bring an almost utopian age of abundance — he is explicitly not doom-oriented", "highlight": false, "also_supports": [], "corpus_ref": "talk-tjstar-keynote", "private": false}, {"id": "S16.007", "cluster": "S16", "_hub": "SR:S16:podcast:talk-consensus-miami", "hub": "SR:S16:podcast:talk-consensus-miami", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-consensus-miami", "url": "", "text": "A lot of people will tell you, oh, it's the models aren't good enough. It's none of that. It's literally compute, data centers, energy that is driving pretty much all decision-making in AI right now.' (coindesk.com/markets/2026/05/08 [transcript - audio-verify])", "paraphrase": "", "source_id": "talk-consensus-miami", "date": "2026-05-08", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-consensus-miami", "private": false}, {"id": "S15.001", "cluster": "S15", "_hub": "SR:S15:blog:essay-americas-ai-ultimatum", "hub": "SR:S15:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "First, the letter is a call for inaction without a prescription for action.' (essay-americas-ai-ultimatum); 'a moratorium keeps faulty versions in the wild", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S15.002", "cluster": "S15", "_hub": "SR:S15:blog:essay-americas-ai-ultimatum", "hub": "SR:S15:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "Second, cease fires are rarely uniformly observed. There are too many open-source generative AI models available to effectively monitor a moratorium.", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S15.008", "cluster": "S15", "_hub": "SR:S15:blog:essay-americas-ai-ultimatum", "hub": "SR:S15:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "Tesla Autopilot precipitated 273 reported accidents in 2021' (essay-americas-ai-ultimatum); 'Musk's call for a moratorium on the development of AI seems disingenuous", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "Musk's call for an AI moratorium is disingenuous given his track record with autonomous systems", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S15.011", "cluster": "S15", "_hub": "SR:S15:blog:notion-manifesto-whitepapers", "hub": "SR:S15:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Seems to be focused primarily on how capitalism + globalism leads to unbounded competition + need for growth / progress → runaway negative externalities → global ecosystem collapse. Slow? Pause?", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Capitalism + globalism leads to unbounded competition and need for growth → runaway negative externalities → global ecosystem collapse; \"slow, pause?\"", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S15.012", "cluster": "S15", "_hub": "SR:S15:blog:notion-manifesto-whitepapers", "hub": "SR:S15:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "only crisis makes real change possible… role: develop/seed 'ideas lying around' so they're available when crisis hits", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "Crisis + intentional elite-seeding is highly effective for change — \"ideas lying around\" must be developed/seeded so they're available when a crisis hits", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S15.000", "cluster": "S15", "_hub": "SR:S15:blog:booknotes-ai-futures", "hub": "SR:S15:blog:booknotes-ai-futures", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-ai-futures", "url": "", "text": "When AI accomplishes a task, do we think more of AI, less of humans, or less of task itself? Often last option", "paraphrase": "", "source_id": "booknotes-ai-futures", "date": "2021", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "booknotes-ai-futures", "private": false}, {"id": "S15.003", "cluster": "S15", "_hub": "SR:S15:blog:essay-self-improving-ai-stack", "hub": "SR:S15:blog:essay-self-improving-ai-stack", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-self-improving-ai-stack", "url": "", "text": "The models are good enough. The infrastructure around them is what's lagging.", "paraphrase": "", "source_id": "essay-self-improving-ai-stack", "date": "2026-04-06", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-self-improving-ai-stack", "private": false}, {"id": "S15.009", "cluster": "S15", "_hub": "SR:S15:blog:essay-chatgpt-ios-app", "hub": "SR:S15:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "will ChatGPT replace software engineers outright within the next handful of years? Almost certainly not.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "ChatGPT will not replace software engineers outright within a few years", "highlight": false, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S15.010", "cluster": "S15", "_hub": "SR:S15:blog:essay-end-of-venture", "hub": "SR:S15:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "While generative music may take a share of the pie, I'm confident that it will never swallow the whole pie", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Generative AI will not kill the music industry or human creative industries — AI takes a share but never the whole pie", "highlight": false, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S15.004", "cluster": "S15", "_hub": "SR:S15:tweet:x-com", "hub": "SR:S15:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "But the economy is not a fixed pie of tasks. It's a register of human desire. If intelligence gets cheaper, Jevons paradox may kick in. We may use dramatically more of it, then build new systems and services around it.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-05-15", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S15.005", "cluster": "S15", "_hub": "SR:S15:tweet:x-com", "hub": "SR:S15:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Saying LLMs can't adapt because their weights are frozen is like saying humans can't learn because our DNA is fixed … The frozen-weights critique … treats the model as the whole organism rather than the inherited machinery every agent builds on top of.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-14", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S15.006", "cluster": "S15", "_hub": "SR:S15:tweet:x-com", "hub": "SR:S15:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Economists rediscover tragedy of the commons, assign it a robot theme 😅", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-04-12", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S15.007", "cluster": "S15", "_hub": "SR:S15:tweet:x-com", "hub": "SR:S15:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "congrats on the cost savings, your customers have left the chat", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-04-13", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S15.013", "cluster": "S15", "_hub": "SR:S15:tweet:x-com", "hub": "SR:S15:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "congrats on finding the use case, here's your bill", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-04-13", "register": "D", "prompted": "P", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Labs capturing API arbitrage value from power users is an expected market dynamic, not a crisis", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S15.014", "cluster": "S15", "_hub": "SR:S15:tweet:x-com", "hub": "SR:S15:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The AI jobs apocalypse view often sounds like lump-of-labor thinking: AI does more tasks, so humans must do less work.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-05-15", "register": "D", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The AI jobs apocalypse relies on lump-of-labor thinking — a fixed-pie fallacy", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S15.015", "cluster": "S15", "_hub": "SR:S15:tweet:x-com", "hub": "SR:S15:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "the DSM is going to need a whole frontier models appendix 😂", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-04-22", "register": "D", "prompted": "P", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI doomerism is a psychosis, not a rational position", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S12.000", "cluster": "S12", "_hub": "SR:S12:blog:essay-end-of-venture", "hub": "SR:S12:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "As the economics for software change and the long tail opens up, Silicon Valley is experiencing a micro-SaaS revolution.", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S12.001", "cluster": "S12", "_hub": "SR:S12:blog:essay-end-of-venture", "hub": "SR:S12:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "The venture capital 1.0 model that has been in operation since the 1980s will fail in this new paradigm where software development is commoditized.", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S12.014", "cluster": "S12", "_hub": "SR:S12:blog:essay-end-of-venture", "hub": "SR:S12:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "In 2024, this standard venture economic model no longer applies.", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The standard venture economic model no longer applies in 2024 because the cost to build software has dropped precipitously", "highlight": false, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S12.015", "cluster": "S12", "_hub": "SR:S12:blog:essay-end-of-venture", "hub": "SR:S12:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "Underlying every capital allocation is a cost-benefit analysis — and while investors are chasing the same _benefit_ as they were in the 80s, the _cost_ to build software has been dropping precipitously.", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The cost drop is structural: while investors chase the same benefit as the 1980s, the cost side of the equation has collapsed", "highlight": false, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S12.016", "cluster": "S12", "_hub": "SR:S12:blog:essay-end-of-venture", "hub": "SR:S12:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "In mere days and for under $100, founders can now stand up a fully-featured full stack web app on their own domain using a cloud computing service like Vercel and get that app in front of thousands of eyeballs using Google AdWords.", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Founders can now build and distribute a full-stack web app in days for under $100 — the barrier to entry is essentially gone", "highlight": false, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S12.017", "cluster": "S12", "_hub": "SR:S12:blog:essay-end-of-venture", "hub": "SR:S12:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "it's not an _if_ anymore, but _when_ software development becomes fully commoditized. According to my most trusted sources, this happens in the next 2–5 years, if not sooner.", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Software development becoming fully commoditized is not an if but a when — timeline is 2–5 years or sooner", "highlight": false, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S12.018", "cluster": "S12", "_hub": "SR:S12:blog:essay-end-of-venture", "hub": "SR:S12:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "Sam Altman is 'openly predicting the world's first single-person unicorn' ($1B+ valuation).", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Sam Altman openly predicts the world's first single-person unicorn — a signal that micro-SaaS and solo founders are the new paradigm", "highlight": false, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S12.019", "cluster": "S12", "_hub": "SR:S12:blog:essay-end-of-venture", "hub": "SR:S12:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "Generative AI is the final piece to this new reality.", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Generative AI is the final piece unlocking the new software economics — it completes the commoditization of development", "highlight": false, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S12.002", "cluster": "S12", "_hub": "SR:S12:blog:essay-chatgpt-ios-app", "hub": "SR:S12:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "The barriers to entry for the creator economy are crumbling as previously passive content consumers will become active contributors.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S12.005", "cluster": "S12", "_hub": "SR:S12:blog:essay-chatgpt-ios-app", "hub": "SR:S12:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "These new tools will have a profound impact on the economy akin to the proliferation of personal computers.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S12.012", "cluster": "S12", "_hub": "SR:S12:blog:essay-chatgpt-ios-app", "hub": "SR:S12:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "Can ChatGPT democratize app development — placing this valuable skill in the hands of the average layperson with an original idea?", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "ChatGPT could democratize app development by placing the skill in the hands of the average layperson", "highlight": false, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S12.013", "cluster": "S12", "_hub": "SR:S12:blog:essay-chatgpt-ios-app", "hub": "SR:S12:blog:essay-chatgpt-ios-app", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-chatgpt-ios-app", "url": "", "text": "The experiment above offers a tantalizing glimpse into a future where complete creative power is made accessible to everyone.", "paraphrase": "", "source_id": "essay-chatgpt-ios-app", "date": "2023-02-20", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The experiment offers a glimpse into a future where complete creative power is made accessible to everyone", "highlight": false, "also_supports": [], "corpus_ref": "essay-chatgpt-ios-app", "private": false}, {"id": "S12.009", "cluster": "S12", "_hub": "SR:S12:blog:essay-americas-ai-ultimatum", "hub": "SR:S12:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "Data is the new infrastructure' (essay-americas-ai-ultimatum); 'Data should be a central part of any infrastructure plan.", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "Data is the new infrastructure — it should be treated as national infrastructure the way roads and broadband are", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S12.010", "cluster": "S12", "_hub": "SR:S12:blog:essay-americas-ai-ultimatum", "hub": "SR:S12:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "The U.S. [Infrastructure Investment and Jobs Act] contemplates investment in roads, airports, railways, broadband, clean energy, and clean water, yet it overlooks the most critical and strategic asset in the race to AGI.", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "The U.S. Infrastructure Act invests in roads, broadband, and clean energy but overlooks data — the most critical asset in the AGI race", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S12.011", "cluster": "S12", "_hub": "SR:S12:blog:essay-americas-ai-ultimatum", "hub": "SR:S12:blog:essay-americas-ai-ultimatum", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-americas-ai-ultimatum", "url": "", "text": "The White House focused on clean energy and clean water' (essay-americas-ai-ultimatum); 'it should prioritize 'clean data'", "paraphrase": "", "source_id": "essay-americas-ai-ultimatum", "date": "2023-04-02", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": true, "reinforces": "The White House prioritized clean energy and clean water — it should add clean data to that agenda", "highlight": false, "also_supports": [], "corpus_ref": "essay-americas-ai-ultimatum", "private": false}, {"id": "S12.008", "cluster": "S12", "_hub": "SR:S12:blog:booknotes-community", "hub": "SR:S12:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Death of bureaucracy / Loyalty to profession, not organization / Agency / Resurgence in entrepreneurship / Company man → associate man", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Organizational loyalty is dying — loyalty shifts to profession and agency; bureaucracy is dead and entrepreneurship is surging in its place", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S12.003", "cluster": "S12", "_hub": "SR:S12:podcast:talk-venture-with-grace", "hub": "SR:S12:podcast:talk-venture-with-grace", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-venture-with-grace", "url": "", "text": "also just small teams continuing to leverage themselves up. I think it's going to be a really interesting new world again of like subventure opportunities with people being able to build, prototype, and then build more quickly than ever before. And then also building through things like lovable and uh cursor and windsurerve being democratized in a way that we've never seen before. Anybody can go build software.", "paraphrase": "", "source_id": "talk-venture-with-grace", "date": "2025-12-05", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-venture-with-grace", "private": false}, {"id": "S12.022", "cluster": "S12", "_hub": "SR:S12:podcast:talk-venture-with-grace", "hub": "SR:S12:podcast:talk-venture-with-grace", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-venture-with-grace", "url": "", "text": "go look at the market for for media a few decades ago and now you look at the market for media now and you have what millions of influencers who are all making a living off of the content they produce including us here right now… that's really like the democratization of creativity. The same thing is happening in software", "paraphrase": "", "source_id": "talk-venture-with-grace", "date": "2025-12-05", "register": "B", "prompted": "P", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The democratization of software mirrors what happened to media — millions of new creators at sub-venture scale", "highlight": false, "also_supports": [], "corpus_ref": "talk-venture-with-grace", "private": false}, {"id": "S12.020", "cluster": "S12", "_hub": "SR:S12:podcast:talk-roan-weigert", "hub": "SR:S12:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "My optimistic vision of the future is that AI is the most incredible tool force for the democratization of creativity and intelligence that we've ever seen. Right? Now you can pull out your phone now if you have access to the internet. You can go have a chat with a super intelligent agent. You can go generate images, incredible images. You can go generate music. You can go generate entire vibe-coded apps and that's all possible on your phone with access to the internet.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "P", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "AI is the most incredible democratizing force for creativity and intelligence ever seen — anyone with internet access can now chat with a super-intelligent agent, generate images, music, and vibe-coded apps on their phone", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S12.021", "cluster": "S12", "_hub": "SR:S12:podcast:talk-roan-weigert", "hub": "SR:S12:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "What you have is what the very best human is capable of producing in terms of whether it's visual, audio, whatever it may be, and the ability for the average person, for any person to go create that is getting closer and closer to the cutting edge, right? Where I'd say like the music that I can create as somebody using a generative music platform is about 90% as good as an actual artist. So that is compressing the delta between what the average person can make and what the world's best can make.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "P", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "The delta between what the average person can produce and what the world's best can produce is rapidly compressing — he estimates generative music he creates is ~90% as good as an actual artist", "highlight": false, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S12.004", "cluster": "S12", "_hub": "SR:S12:tweet:x-com", "hub": "SR:S12:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "HOT TAKE: Early stage venture is doomed. 📉 GenAI is commoditizing software. Venture is facing a generational reckoning & must adapt in order to survive or risk radical disruption.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2024-04-15", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S12.006", "cluster": "S12", "_hub": "SR:S12:tweet:x-com", "hub": "SR:S12:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "AI agents will allow us to abstract away complexities in the rest of life!", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2023-08-11", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S12.007", "cluster": "S12", "_hub": "SR:S12:tweet:x-com", "hub": "SR:S12:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Cofactory is the portmanteau of 'company factory.' That's what we're building. We have a head start and – as such – are staying in stealth mode for now but stay tuned!", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2023-11-18", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S7.000", "cluster": "S7", "_hub": "SR:S7:tweet:x-com", "hub": "SR:S7:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "To every chapter lead who raised their hand and said 'I'll build this in my city' – you're the reason this works. You're creating homes for people who care about where AI is going.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2026-01-29", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S7.001", "cluster": "S7", "_hub": "SR:S7:tweet:x-com", "hub": "SR:S7:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The AI Collective passport became real – where you can show up to any chapter in the world and instantly have a community.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2026-01-29", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S7.002", "cluster": "S7", "_hub": "SR:S7:tweet:x-com", "hub": "SR:S7:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Our model scales. The same conversations happening in living rooms and coworking spaces around the world are now happening in the halls of power.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-02-20", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S7.007", "cluster": "S7", "_hub": "SR:S7:tweet:x-com", "hub": "SR:S7:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Instead of chasing Silicon Valley consensus, Manus has a global-first strategy, building for idiosyncratic use cases in markets like Brazil and Japan.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2025-07-19", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S7.011", "cluster": "S7", "_hub": "SR:S7:tweet:x-com", "hub": "SR:S7:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Huge props to our Chicago chapter lead @JohnsonSwagel for getting this incredible community rolling!", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2024-11-05", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Chapter leads are founders in their own right — credit and props flow to them for building community", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S7.004", "cluster": "S7", "_hub": "SR:S7:podcast:talk-venture-with-grace", "hub": "SR:S7:podcast:talk-venture-with-grace", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-venture-with-grace", "url": "", "text": "if you are a chapter lead, you are the CEO of your chapter… I like to think of it as we're we're making a bet on somebody on a founder of their local ecosystem who becomes the center of gravity for that ecosystem. And uh I find that the best things happen when you give really great founders a ton of uh control and a ton of you know possibility for lateral movement.", "paraphrase": "", "source_id": "talk-venture-with-grace", "date": "2025-12-05", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-venture-with-grace", "private": false}, {"id": "S7.005", "cluster": "S7", "_hub": "SR:S7:podcast:talk-venture-with-grace", "hub": "SR:S7:podcast:talk-venture-with-grace", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-venture-with-grace", "url": "", "text": "we're we're ultimately here to support… we're responsible for making sure that every chapter meets th that high bar and those standards, but beyond that, it's really under the control of the chapter. And we like to give as much autonomy as we possibly can while keeping things within bounds.", "paraphrase": "", "source_id": "talk-venture-with-grace", "date": "2025-12-05", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-venture-with-grace", "private": false}, {"id": "S7.003", "cluster": "S7", "_hub": "SR:S7:podcast:talk-roam-remote-work", "hub": "SR:S7:podcast:talk-roam-remote-work", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roam-remote-work", "url": "", "text": "we have at least one chapter lead in every single one of those cities stewarding the community that they are part of and that they're they're helping to energize", "paraphrase": "", "source_id": "talk-roam-remote-work", "date": "2026-02-02", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-roam-remote-work", "private": false}, {"id": "S7.006", "cluster": "S7", "_hub": "SR:S7:podcast:talk-roan-weigert", "hub": "SR:S7:podcast:talk-roan-weigert", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-roan-weigert", "url": "", "text": "We have over 100 volunteer organizers, visionaries, local visionaries taking time out of their day to put together these incredible community experiences, bring people together in all these cities around the world.", "paraphrase": "", "source_id": "talk-roan-weigert", "date": "2025-07-01", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-roan-weigert", "private": false}, {"id": "S7.008", "cluster": "S7", "_hub": "SR:S7:blog:booknotes-community", "hub": "SR:S7:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Journey into maturation / Create opportunities to mentor, be a mentor / Strict egalitarianism becomes a problem", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The inner-ring principle — aspirational layers of belonging — creates a growth path inside community and prevents the failure mode of strict egalitarianism", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S7.009", "cluster": "S7", "_hub": "SR:S7:blog:booknotes-community", "hub": "SR:S7:blog:booknotes-community", "category": "blog", "catColor": "#ff6f9c", "source_key": "booknotes-community", "url": "", "text": "Accountability grows from co-creation / assets + gifts, not needs + deficiencies / only associational life can deliver care", "paraphrase": "", "source_id": "booknotes-community", "date": "2024", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Accountability grows from co-creation — assets and gifts, not needs and deficiencies; only associational life can deliver true care", "highlight": false, "also_supports": [], "corpus_ref": "booknotes-community", "private": false}, {"id": "S7.010", "cluster": "S7", "_hub": "SR:S7:blog:notion-manifesto-whitepapers", "hub": "SR:S7:blog:notion-manifesto-whitepapers", "category": "blog", "catColor": "#ff6f9c", "source_key": "notion-manifesto-whitepapers", "url": "", "text": "Proximity before policy: start with local, embodied trust. Transparency by default: document and publish deliberation artifacts. Iteration over ideology: continuous experimentation beats static doctrine.", "paraphrase": "", "source_id": "notion-manifesto-whitepapers", "date": "2023", "register": "C", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Open democracy requires proximity before policy — start with local, embodied trust; transparency by default; iteration over ideology", "highlight": false, "also_supports": [], "corpus_ref": "notion-manifesto-whitepapers", "private": false}, {"id": "S11.000", "cluster": "S11", "_hub": "SR:S11:tweet:x-com", "hub": "SR:S11:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "While the last generation of software competed for human attention, the agent-native generation will compete for machine usability … If agents become real economic actors inside companies, every core software assumption gets reopened.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-04-28", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S11.001", "cluster": "S11", "_hub": "SR:S11:tweet:x-com", "hub": "SR:S11:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "We'll need software that treats agents as first-class users: able to understand context, take action, ask for help, and leave behind a legible trail … Make Something Agents Want!!", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-04-28", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S11.004", "cluster": "S11", "_hub": "SR:S11:tweet:x-com", "hub": "SR:S11:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Excited to share that I'll be speaking on the mainstage at @consensus2026 this Thursday! We'll be talking AI x decentralization: open-source vs centralized AI, where AI + blockchain are converging, and what we're seeing on the ground across @AICollectiveCo's 200,000+ members", "paraphrase": "", "source_id": "tweets-rescues-2026-06-11", "date": "2026-05-05", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-rescues-2026-06-11", "private": false}, {"id": "S11.005", "cluster": "S11", "_hub": "SR:S11:tweet:x-com", "hub": "SR:S11:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "agent wallets with approvals feels like v0.1 of a very long chapter", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-04-30", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S11.009", "cluster": "S11", "_hub": "SR:S11:tweet:x-com", "hub": "SR:S11:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The next trillion internet users won't be human … Agents are already using it, but they're awkwardly operating through a layer designed for humans.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-04-28", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The next trillion internet users won't be human; agents are already using the web but awkwardly, through a layer designed for humans", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S11.010", "cluster": "S11", "_hub": "SR:S11:tweet:x-com", "hub": "SR:S11:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The agent economy is begging for new primitives. 1️⃣ Interfaces: APIs, CLIs, MCP servers, and machine-readable surfaces … 5️⃣ Memory: Persistent context about what happened … 6️⃣ Identity: A way to know which agent did what … 7️⃣ Observability: Logs, audit trails, rollback, and human review when the stakes are high.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-04-28", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The agent economy requires new primitives: machine-readable interfaces, agent-discoverable docs, scoped permissions, retry-aware workflows, persistent memory, verifiable identity, and audit-trail observability", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S11.011", "cluster": "S11", "_hub": "SR:S11:tweet:x-com", "hub": "SR:S11:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Agents will be crypto's best user … The obvious version is chatbots with wallets. The useful version is autonomous agents making economic decisions at machine speed.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-11", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Agents will be crypto's best user; the useful version is autonomous agents making economic decisions at machine speed, not chatbots with wallets", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S11.012", "cluster": "S11", "_hub": "SR:S11:tweet:x-com", "hub": "SR:S11:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Stablecoins are", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-11", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Stablecoins are the right payment primitive for agentic/machine-speed economic decisions", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S11.013", "cluster": "S11", "_hub": "SR:S11:tweet:x-com", "hub": "SR:S11:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "An LLM is not the whole brain. It's more like a cortical column: a core predictive module inside a larger adaptive system. The base model provides the predictive architecture. The surrounding agentic system learns through context, memory, tools, feedback loops, fine-tuning, and multi-agent coordination.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-14", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "An LLM is not the whole brain — it is more like a cortical column: a core predictive module inside a larger adaptive system that learns through context, memory, tools, feedback loops, fine-tuning, and multi-agent coordination", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S11.014", "cluster": "S11", "_hub": "SR:S11:tweet:x-com", "hub": "SR:S11:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "My favorite idea from last night: personal AI agents as automated decision-makers, allowing us to move higher up the executive value chain!", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2023-08-11", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Personal AI agents as automated decision-makers move humans higher up the executive value chain — freeing people from task-execution toward judgment-level work", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S11.015", "cluster": "S11", "_hub": "SR:S11:tweet:x-com", "hub": "SR:S11:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "By remaining LLM-agnostic and focusing on the application layer, they can move faster and integrate the best tech for the job.", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2025-07-19", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "LLM-agnostic application-layer companies that focus on the best tool for the job move fastest", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S11.002", "cluster": "S11", "_hub": "SR:S11:podcast:talk-consensus-miami", "hub": "SR:S11:podcast:talk-consensus-miami", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-consensus-miami", "url": "", "text": "The number one thing that I've heard kind of throughout this conference... even my friends who only know about AI, they know nothing about blockchain, is they've heard about agentic payments.' (coindesk.com/markets/2026/05/08 [transcript - audio-verify])", "paraphrase": "", "source_id": "talk-consensus-miami", "date": "2026-05-08", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-consensus-miami", "private": false}, {"id": "S11.003", "cluster": "S11", "_hub": "SR:S11:podcast:talk-consensus-miami", "hub": "SR:S11:podcast:talk-consensus-miami", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-consensus-miami", "url": "", "text": "When agents make the majority of financial decisions, economic decisions, how do they transact with each other?' (coindesk.com/markets/2026/05/08 [transcript - audio-verify])", "paraphrase": "", "source_id": "talk-consensus-miami", "date": "2026-05-08", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-consensus-miami", "private": false}, {"id": "S11.008", "cluster": "S11", "_hub": "SR:S11:podcast:talk-consensus-miami", "hub": "SR:S11:podcast:talk-consensus-miami", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-consensus-miami", "url": "", "text": "You want them to be highly systematic, mechanistic. You want very small, micro transactions. You want very low latency.' (coindesk.com/markets/2026/05/08 [transcript - audio-verify])", "paraphrase": "", "source_id": "talk-consensus-miami", "date": "2026-05-08", "register": "B", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "Agent payment rails must be systematic, mechanistic, micro, and ultra-low-latency — not human-scale", "highlight": false, "also_supports": [], "corpus_ref": "talk-consensus-miami", "private": false}, {"id": "S11.007", "cluster": "S11", "_hub": "SR:S11:podcast:talk-venture-with-grace", "hub": "SR:S11:podcast:talk-venture-with-grace", "category": "podcast", "catColor": "#b98bff", "source_key": "talk-venture-with-grace", "url": "", "text": "the the copout answer would be agents, and it's been agents for a little while, right? I think the more moving to the application layer is something I'm interested in like very vertical specific, maybe even things that might traditionally be subventure scale.", "paraphrase": "", "source_id": "talk-venture-with-grace", "date": "2025-12-05", "register": "B", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": true, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "talk-venture-with-grace", "private": false}, {"id": "S11.006", "cluster": "S11", "_hub": "SR:S11:blog:essay-human-side-of-ai", "hub": "SR:S11:blog:essay-human-side-of-ai", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-human-side-of-ai", "url": "", "text": "2024 built the scaffolding. 2025 will be the year of AI agents applied, where we'll move from theory to practice as agents begin reshaping our workflows – and our workplaces.", "paraphrase": "", "source_id": "essay-human-side-of-ai", "date": "2025-01-02", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-human-side-of-ai", "private": false}, {"id": "S20.000", "cluster": "S20", "_hub": "SR:S20:tweet:x-com", "hub": "SR:S20:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Within one conversation, I knew he was right. Ben had this vision for Cofactory... I was so bought in that I left Apple to join as CEO.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2026-02-04", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S20.001", "cluster": "S20", "_hub": "SR:S20:tweet:x-com", "hub": "SR:S20:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Creative strategic thinking... Ambition without ego. He wants to do big things, but not for the glory... Conviction. Ben doesn't hedge. He sees something clearly and moves toward it with total commitment.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2026-02-04", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S20.002", "cluster": "S20", "_hub": "SR:S20:tweet:x-com", "hub": "SR:S20:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "$2.5M raised by last SF Pitch Night's winning startup, $5.6M the event before that. Who's next??", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-03-09", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S20.003", "cluster": "S20", "_hub": "SR:S20:tweet:x-com", "hub": "SR:S20:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Excited to join @SusaVentures! @denwezoh and I first met a couple of years ago at one of our events, and what started as a chance conversation turned into a close friendship that I deeply value.", "paraphrase": "", "source_id": "tweets-quote-00", "date": "2025-12-19", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-quote-00", "private": false}, {"id": "S20.006", "cluster": "S20", "_hub": "SR:S20:tweet:x-com", "hub": "SR:S20:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "when I asked @manusai's co-founder and CPO, Tao Zhang, this question on stage last night, his response set the tone for the entire evening: 'We were happy. It's validation.'", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-07-19", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "When a giant like OpenAI enters your domain, the right founder response is \"We were happy. It's validation.\"", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S20.007", "cluster": "S20", "_hub": "SR:S20:tweet:x-com", "hub": "SR:S20:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I've seen firsthand how deeply they support founders – not just with capital, but with conviction, care, and long-term partnership.", "paraphrase": "", "source_id": "tweets-orig-00", "date": "2025-04-01", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Great venture is support with conviction, care, and long-term partnership — not just capital", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-00", "private": false}, {"id": "S20.004", "cluster": "S20", "_hub": "SR:S20:blog:essay-end-of-venture", "hub": "SR:S20:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "Venture needs to shift to helping the tastemakers of the future solve PMF and GTM at scale — a problem set AI may be farther away from addressing effectively.", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S20.005", "cluster": "S20", "_hub": "SR:S20:blog:essay-end-of-venture", "hub": "SR:S20:blog:essay-end-of-venture", "category": "blog", "catColor": "#ff6f9c", "source_key": "essay-end-of-venture", "url": "", "text": "Anecdotally, I've talked with a higher concentration of bootstrapped founders and indie entrepreneurs over the past half year than ever before.", "paraphrase": "", "source_id": "essay-end-of-venture", "date": "2024-04-15", "register": "C", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "essay-end-of-venture", "private": false}, {"id": "S25.000", "cluster": "S25", "_hub": "SR:S25:tweet:x-com", "hub": "SR:S25:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The Demo Night App is open source and intended to be entirely community-driven so expect an even more awesome experience with every event! Interested in helping us take this to the next level? Check out the repo & DM me if you want to hop on a call! 😄", "paraphrase": "", "source_id": "tweets-build-in-public", "date": "2024-05-23", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-build-in-public", "private": false}, {"id": "S25.001", "cluster": "S25", "_hub": "SR:S25:tweet:x-com", "hub": "SR:S25:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Share more of what you're working on. Building in public – whether it's code, fitness, writing, whatever – is one of the best accountability mechanisms out there. And you never know who it resonates with!", "paraphrase": "", "source_id": "tweets-build-in-public", "date": "2026-02-27", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-build-in-public", "private": false}, {"id": "S25.002", "cluster": "S25", "_hub": "SR:S25:tweet:x-com", "hub": "SR:S25:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "👷 Demo Night App GitHub repo: https://t.co/HGbX0do6EQ", "paraphrase": "", "source_id": "tweets-build-in-public", "date": "2024-06-19", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Publishing the repo link is a default reflex on every project announcement — the build is narrated with its source attached", "highlight": false, "also_supports": [], "corpus_ref": "tweets-build-in-public", "private": false}, {"id": "S25.003", "cluster": "S25", "_hub": "SR:S25:tweet:x-com", "hub": "SR:S25:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "👷 Join the team and build cool software like this with me! 👇", "paraphrase": "", "source_id": "tweets-build-in-public", "date": "2025-10-30", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Open-sourcing is an invitation to co-build, not just to inspect — join the team and build with me", "highlight": false, "also_supports": [], "corpus_ref": "tweets-build-in-public", "private": false}, {"id": "S25.004", "cluster": "S25", "_hub": "SR:S25:tweet:x-com", "hub": "SR:S25:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "And for fellow nerds who are inspired – the whole site is open source!", "paraphrase": "", "source_id": "tweets-build-in-public", "date": "2026-02-23", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "His personal book-notes site ships open source for fellow nerds to reuse", "highlight": false, "also_supports": [], "corpus_ref": "tweets-build-in-public", "private": false}, {"id": "S25.005", "cluster": "S25", "_hub": "SR:S25:tweet:x-com", "hub": "SR:S25:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Full wiki (183 articles, 139 entities, open source): https://t.co/wOOGZfwJV9", "paraphrase": "", "source_id": "tweets-build-in-public", "date": "2026-04-07", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "His AI wiki (183 articles, 139 entities) is published fully open source", "highlight": false, "also_supports": [], "corpus_ref": "tweets-build-in-public", "private": false}, {"id": "S25.006", "cluster": "S25", "_hub": "SR:S25:tweet:x-com", "hub": "SR:S25:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Want to do your own analysis? Here's the code! 👨‍💻", "paraphrase": "", "source_id": "tweets-build-in-public", "date": "2025-01-21", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He releases the analysis code behind his own data deep-dives so anyone can replicate it", "highlight": false, "also_supports": [], "corpus_ref": "tweets-build-in-public", "private": false}, {"id": "S25.007", "cluster": "S25", "_hub": "SR:S25:tweet:x-com", "hub": "SR:S25:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Here's the code! Also, I included my own WLD data as an example for you to mess around with!", "paraphrase": "", "source_id": "tweets-build-in-public", "date": "2024-12-26", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He shares not just the code but his own raw training data as the example dataset", "highlight": false, "also_supports": [], "corpus_ref": "tweets-build-in-public", "private": false}, {"id": "S25.008", "cluster": "S25", "_hub": "SR:S25:tweet:x-com", "hub": "SR:S25:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The whole thing is open source if you want to do the same with your Weightlifting App data!", "paraphrase": "", "source_id": "tweets-build-in-public", "date": "2026-02-27", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The full lifting-visualization pipeline is open source so other Weightlifting App users can do the same", "highlight": false, "also_supports": [], "corpus_ref": "tweets-build-in-public", "private": false}, {"id": "S24.000", "cluster": "S24", "_hub": "SR:S24:tweet:x-com", "hub": "SR:S24:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I track PRs across 13 featured lifts spanning every muscle group, plot them over time, and fit an asymptotic curve to see where I'm converging. Right now I'm at ~94% of my estimated ceiling, gaining roughly 70 lbs/year across those lifts. The diminishing returns are real, but they're also what makes it fun!", "paraphrase": "", "source_id": "tweets-quant-self", "date": "2026-02-27", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-quant-self", "private": false}, {"id": "S24.001", "cluster": "S24", "_hub": "SR:S24:tweet:x-com", "hub": "SR:S24:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "💪 2025 Bodybuilding Year in Review! 📊 I've tracked 40,000+ sets across my ~8-year lifting career – every PR and every step on the scale 🤓 Nerding out over the data is half the fun… and 2025 was stacked!", "paraphrase": "", "source_id": "tweets-quant-self", "date": "2026-01-31", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-quant-self", "private": false}, {"id": "S24.002", "cluster": "S24", "_hub": "SR:S24:tweet:x-com", "hub": "SR:S24:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I put 8.5 years of training data into one chart. Every workout. Every set. 45,000+ data points – all from an app I originally built in high school.", "paraphrase": "", "source_id": "tweets-quant-self", "date": "2026-02-27", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The body is a measurement-and-modeling system: every set logged for 8 years, every PR plotted, an asymptotic curve fit to find where he is converging", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quant-self", "private": false}, {"id": "S24.003", "cluster": "S24", "_hub": "SR:S24:tweet:x-com", "hub": "SR:S24:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "How much strength should I gain this year? Plotting my progress since 2018 and applying an asymptotic trendline, looks like 4,218 lbs → 4,321 lbs!", "paraphrase": "", "source_id": "tweets-quant-self", "date": "2025-01-21", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He treats strength goals as a forecasting problem: plot progress since 2018, apply an asymptotic trendline, and derive the exact target for the year", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quant-self", "private": false}, {"id": "S24.004", "cluster": "S24", "_hub": "SR:S24:tweet:x-com", "hub": "SR:S24:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Was surprised to see the new PRs actually decreased my total 1RM projections. Time for a quick code fix!", "paraphrase": "", "source_id": "tweets-quant-self", "date": "2025-02-02", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "When the model disagrees with intuition (new PRs lowering total 1RM projection), the fix is a code change, not a fudge — the model is the source of truth", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quant-self", "private": false}, {"id": "S24.005", "cluster": "S24", "_hub": "SR:S24:tweet:x-com", "hub": "SR:S24:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Using each year's July 1st total is not only more stable, it all seems much more accurate all-around! ~50 pounds more to add this season, though I suspect I'll fly right past that.", "paraphrase": "", "source_id": "tweets-quant-self", "date": "2025-02-02", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Choosing a stable, principled metric (each year's July-1 total) makes the whole projection more accurate — measurement methodology matters", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quant-self", "private": false}, {"id": "S24.006", "cluster": "S24", "_hub": "SR:S24:tweet:x-com", "hub": "SR:S24:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Let's scale up this analysis to include all my favorite exercises! Full list 👇 Counts of favorite exercises (representing 2,188 exercises, 24.8% of total): 1. Flat Bench: 369 times 2. One-arm Overhead Extensions: 296 times 3. Close-grip Bench: 268 times 4. OHP: 259", "paraphrase": "", "source_id": "tweets-quant-self", "date": "2025-01-21", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He scales the analysis exhaustively, counting and ranking every exercise across 8,800+ logged exercises to mine the data for patterns", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quant-self", "private": false}, {"id": "S24.007", "cluster": "S24", "_hub": "SR:S24:tweet:x-com", "hub": "SR:S24:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Lastly, I looked at training intensity vs bodyweight. Somewhat counterintuitively, volume and sets per hour go down as I gain weight—heavier sets just take longer to recover from! 👍", "paraphrase": "", "source_id": "tweets-quant-self", "date": "2025-04-06", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The data reveals counterintuitive truths about his own body — volume and sets-per-hour drop as he gains weight because heavy sets take longer to recover from", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quant-self", "private": false}, {"id": "S24.008", "cluster": "S24", "_hub": "SR:S24:tweet:x-com", "hub": "SR:S24:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "According to my DEXA scan during peak week, I was at 16.7% body fat—exactly where I expected. No visceral fat either! Super happy with the 25.3 FFMI as well", "paraphrase": "", "source_id": "tweets-quant-self", "date": "2025-04-06", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He runs his physique through objective external instruments (DEXA scans, FFMI) and predicts the results in advance, treating his body as a calibrated experiment", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quant-self", "private": false}, {"id": "S24.009", "cluster": "S24", "_hub": "SR:S24:tweet:x-com", "hub": "SR:S24:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I'm lucky to store most of my fat in my legs, which keeps my arms looking lean year-round—14% vs 18% BF in arms and legs respectively", "paraphrase": "", "source_id": "tweets-quant-self", "date": "2025-04-06", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Even fat distribution is data he models — he knows his arm-vs-leg body-fat split to the point and accounts for it", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quant-self", "private": false}, {"id": "S24.010", "cluster": "S24", "_hub": "SR:S24:tweet:x-com", "hub": "SR:S24:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I did a DEXA scan after about a week of cutting and slightly beat expectations with a 13.8% @211 lbs BW result! Graphing out my past scans, this puts me slightly above the linreg trend line.", "paraphrase": "", "source_id": "tweets-quant-self", "date": "2026-02-23", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Successive DEXA scans get plotted against a linear-regression trend so each new datapoint is read against the model, not in isolation", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quant-self", "private": false}, {"id": "S24.011", "cluster": "S24", "_hub": "SR:S24:tweet:x-com", "hub": "SR:S24:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I'm following a relatively linear cut schedule (tapering from 1.5 → 1 lbs) and giving myself plenty of buffer this year – including a two-week diet break for my birthday in April", "paraphrase": "", "source_id": "tweets-quant-self", "date": "2026-02-23", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "A cut is a scheduled, linear, buffered protocol (tapering 1.5 → 1 lbs/week, planned diet breaks) — discipline executed as a plan, not willpower", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quant-self", "private": false}, {"id": "S24.012", "cluster": "S24", "_hub": "SR:S24:tweet:x-com", "hub": "SR:S24:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Curious if I'd improve my Wilks score by gaining even more weight, I ran some numbers: I'd only need to add ~4.5 lbs to my bench @ 225 lbs to justify a further bulk.", "paraphrase": "", "source_id": "tweets-quant-self", "date": "2025-04-06", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "He optimizes against composite physique metrics directly: he ran the Wilks numbers to decide whether bulking further is justified", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quant-self", "private": false}, {"id": "S24.013", "cluster": "S24", "_hub": "SR:S24:tweet:x-com", "hub": "SR:S24:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "This is my favorite graph of the set: PR SZN! 😤 My yearly peak PR month is almost always January since that's when I'm at the top of my bulk.", "paraphrase": "", "source_id": "tweets-quant-self", "date": "2025-01-21", "register": "D", "prompted": "U", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "His PR data carries a real seasonal signal he has identified from years of records — peak-PR month is January, the top of his bulk", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quant-self", "private": false}, {"id": "S24.014", "cluster": "S24", "_hub": "SR:S24:tweet:x-com", "hub": "SR:S24:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "I've tracked nearly 40,000 sets across my ~8 year lifting career, including every single PR 🤓 Here's the first big one of the 2025 season: 10x210 on overhead press! After the workout, I did a deep dive into the numbers...", "paraphrase": "", "source_id": "tweets-quant-self", "date": "2025-01-21", "register": "D", "prompted": "U", "signal_strength": 0.9, "strength01": 0.9, "influence_1to10": 9, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "The lifting tracker he built in high school is the substrate for ~40,000 logged sets and every season's analysis — self-built measurement infrastructure", "highlight": false, "also_supports": [], "corpus_ref": "tweets-quant-self", "private": false}, {"id": "S17.000", "cluster": "S17", "_hub": "SR:S17:tweet:x-com", "hub": "SR:S17:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The question is no longer only 'how much code can we produce?' – it's 'how much of what we produce can we still understand?", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-22", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S17.001", "cluster": "S17", "_hub": "SR:S17:tweet:x-com", "hub": "SR:S17:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "1️⃣ Determine the longevity of the project and how grokable it needs to be 2️⃣ Determine your quality bar for the product 3️⃣ Assess the current quality of coding agents 4️⃣ Align with your team on how fast the product of ↑ allows you to move 5️⃣ Continuously update ↑", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-22", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S17.002", "cluster": "S17", "_hub": "SR:S17:tweet:x-com", "hub": "SR:S17:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Flat rate just delayed the model routing lesson. Now everyone has to learn it.", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-04-06", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S17.003", "cluster": "S17", "_hub": "SR:S17:tweet:x-com", "hub": "SR:S17:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "The real limit was always you", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-04-06", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S17.004", "cluster": "S17", "_hub": "SR:S17:tweet:x-com", "hub": "SR:S17:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "prompt engineering is basically therapy now", "paraphrase": "", "source_id": "tweets-reply-01", "date": "2026-04-06", "register": "D", "prompted": "", "signal_strength": 0.85, "strength01": 0.85, "influence_1to10": 8, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "", "highlight": true, "also_supports": [], "corpus_ref": "tweets-reply-01", "private": false}, {"id": "S17.005", "cluster": "S17", "_hub": "SR:S17:tweet:x-com", "hub": "SR:S17:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "Cognitive debt is the scarier version because it lives in your own head. It's the gap between what your system does and what you can actually explain, debug, and safely change.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-22", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Cognitive debt — the gap between what your system does and what you can actually explain, debug, and safely change — is the scarier version of technical debt and it lives in your own head", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S17.006", "cluster": "S17", "_hub": "SR:S17:tweet:x-com", "hub": "SR:S17:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "It really does feel like having a team of tireless, slightly overconfident junior engineers next to you who will happily crank forever if you point them in a direction. And that is exactly why the phrase landed so hard. The code can start moving faster than your understanding.", "paraphrase": "", "source_id": "tweets-orig-01", "date": "2026-05-22", "register": "D", "prompted": "U", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "AI coding tools are incredible — like tireless, slightly overconfident junior engineers — but the code can move faster than your understanding, and that is exactly the risk", "highlight": false, "also_supports": [], "corpus_ref": "tweets-orig-01", "private": false}, {"id": "S17.007", "cluster": "S17", "_hub": "SR:S17:tweet:x-com", "hub": "SR:S17:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "When your second brain retains more than you do, are you still the expert?", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-04-06", "register": "D", "prompted": "P", "signal_strength": 1.0, "strength01": 1.0, "influence_1to10": 10, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "When your second brain retains more than you do, the question of who is still the expert becomes real", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}, {"id": "S17.008", "cluster": "S17", "_hub": "SR:S17:tweet:x-com", "hub": "SR:S17:tweet:x-com", "category": "tweet", "catColor": "#4eb3ff", "source_key": "x-com", "url": "", "text": "we trained genius-level reasoning and are now teaching it to talk less. fine 😂", "paraphrase": "", "source_id": "tweets-reply-00", "date": "2026-04-06", "register": "D", "prompted": "P", "signal_strength": 0.62, "strength01": 0.62, "influence_1to10": 6, "emphasis_markers": [], "sentiment": "", "audio_verify": false, "compliance_sensitive": false, "reinforces": "Teaching genius-level reasoning to talk less (token-compression tricks) is a telling irony of AI development", "highlight": false, "also_supports": [], "corpus_ref": "tweets-reply-00", "private": false}];
